insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-10-14','+++Hablo con Elena: la situación sigue evolucionando bien, con buen comportamiento y trabajando el tema de los "caprichos" frescuentes que se le ocurren a la vez que el manejo adecuado del dinero. +++Conversación con Margarita: ya echjaba de menos la llamada de esta semana a pesar de que le advertí que no todas las semanas podría ser el mismo día. Retoma el tema del tatuaje, sigue haciendo el puzzle y enviará foto (le está costando). IMPORTANTE: NO entrar en sus peticiones constantes y remitirla a lo que los compañeros del Las Cumbres hayan hablñado con ella al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-10-13','Visita de Consuelo. Demanda única: quiere cambiar de Centro, a CRR de Badajoz o Cáceres. SE descarta su pretensión de volver con su familia y entiende los motivos para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-10-14','Conversación con Gisela. Se le plantea la conveniencia o no de solicitar el traslado de Consuelo a otro CRR. Lo valorarán y nos llamarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2016-10-14','Visita de Pipi. Con absoluta mala educación se dirige a mí sin mediar saludo alguno, índicándole que aquí nunca se le ha tratado así y ante la negativa a darle más dinero del que le han dado en el CRR dice que va a pedir el alta voluntaria. Le abro la puerta y le invito a hacerlo...Se marcha tirando la silla al suelo al levantarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2016-10-14','Llamada de Jairo. Insiste en que quiere 1700€ para comprarse ropa, un reloj, un móvil, un ordenador y pagar la matrícula de la UNED. Insiste una y otra vez en que necesita "...todos esos elementos materiales para poder asegurar que va a aprobar el examen de acceso, que sin ello no tendrá los alicientes necesarios para asegurarse un futuro mejor. Insiste también en la familia de Salamanca y en que se quiere ir con ella porque se encuentra muy mal en el CSS...argumento que solamente utiliza cuando ve que no va a conseguir lo quiere, al decirle yo que para aprobar el acceso lo que necesita es estudiar y no tener todos esos "lementos materiales" como el los llama.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2016-10-14','Conversación con Choni, T. Soc. del SSB de Miajadas. Enviará el DNI por correo-e. Comenta que D. Felipe estuvo tutelado por su hermano, hasta que cayó enfermo (actualmente se encuentra ingresado en un centro de salud mental).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-10-17','Hablamos con Maria José(la hermana) y con el taxista, los recogeran el día 22 de octubre a las 6.30 de la mañana en la puerta del Marcelo Nessi. Tienen la convivencia el día 22 a las 9 de la mañana. El taxista después nos enviara la factura y que el centro nos confirme que ha ido la hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2016-10-17','Nos envia el centro la declaración individual de PNC fuera de plazo. No obstante la enviamos a DG de Politicas sociales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-10-18','Citan a Francisco el día 19/10/2016, a las 10:30 horas, en la sede del Juzgado de 1ª. Instancia e Instrucción nº 2, de Plasencia, en relación con la Liquidación de la Sociedad de Ganananciales nº 326/2016. Tiene abogado, Antonio Javier Fernández Sánchez, 927404120-679291280. Tenemos que acudir (coche pedido a las 8:30 horas). El juicio versa sobre la liquidación de la sociedad de gananciales y posterior división judicial de la herencia de sus padres, D. Juan Gonzalo Ayala Rodríguez y Dª. Nieves Núñez Albarrán. En su día ya se hizo una primera liquidación y división de herencia de sus padres, pero tasaron el valor del inmueble en 48.080,96 euros, en lugar de los 135.000 euros según informe policial o, en su caso, el 3,09% (coeficiente multiplicador) de su valor catastral, que ascendería a 112.000 euros, siendo su hermana, María Rosa Ayala Núñez la principal beneficiada, al adjudicársele dicho inmueble y el local comercial, con un valor de 24.040,48 euros, pagando en compensación a sus dos hermanos, 24.040,48 euros a cada uno. Por este motivo declararon nula esa liquidación y herencia.','2');
