insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2016-10-18','Nos llama un abogado que conoce a Agustín desde hace tiempo porque dice que Agustin está sin dinero porque es una tutela nueva y le han bloqueado la cuenta. Cobra 636 € de pensión y tiene deuda de 60€ /mes de una prótesis dental. Solicita un extra y hay que hablar con la TS Maribel para que nos haga una previsión de gastos. Tlf. de Agustín 663630277. Tlf José Manuel (abogado)699997501','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-10-18','Hablamos con Fatima TS de ESM comenta que el jueves 13 de octubre fue Cristopher al psiquiatra. Que tanto el psiquiatra como ella lo ven bien y que si queremos un informe médico habría que solicitarlo por escrito. Ellos no ven que se vaya a un centro, además Cristopher les ha dicho a ellos que como se vaya a un centro se va a escapar.','2');
