insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-10-21','Llamada a Margarita. Ha estado en ESM y le mantienen el tratamiento. Sigue con buen comportamiento. Ya no quiere hacerse el tatuaje para ahorrar para cosas básicas. EL DÍA 3 DE DICIEMBRE ES SU CUMPLEAÑOS. LLAMARLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-10-21','Conversación con Juana, T. Soc. (SSB).D. Juan sigue insistiendo en quese quiere marchar a Montijo.Según comenta Juana, el médico no ha derivado todavía a D. Juan a Neurología porque considera que no lo necesita. Le pido que vuelva a hablar con el médico y que si no cosidera justificada dicha derivación hable nuevamente con nuestro curatelado porque, dada las caraterísticas de la curatela, el tiene capacidad para decidir en ese sentido: que le haga ver que acepte la propuesta el PIA para Badajoz o Mérida, más próximas a Montijo de lo que está ahora y al que pued eacercarse en autobús cuando lo desee.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-10-24','Llama Dª Teresa (927-470279), hermana de D. José Mª. Comenta que le ha llegado la notificación de la contratación de un seguro de deceso a nombre de su hermano. Comenta que ya tiene uno junto a sus padres y a otro de sus hermanos, con la COMPAÑÍA "ATOCHA" y Nºde POLIZA PNCC003384. Como referencia me da el nombre del padre y su DNI: Félix Valle Barbero, DNI nº 07418665-S.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-10-24','Llamada de Javier. Quiere 60€ para regalar a sus hermanas algo para los cuempleaños que ya han pasado; 60€ para su cumpleaños que está por llegar; y dinero para comprarse ropa y un perfume. SE LE INFORMA de los gastos que está teniendo, por encima de sus ingresos y reconoce que una media de 200€ al mes en teléfono es una barbaridad (más de 2000€ al año). Promete que no voleverá a llamar tanto, pero es una promesa que ya ha hecho en otras ocasiones. CUANDO LO VISITE FUTUEX nos enviará presupuesto de ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2016-10-21','Conversación con Ana, de Aprosuba de Zafra (924-563092). Comenta que la familia quiere que sea ingresada en una plaza residencial porque está convencida de que con la familia que está terminará mal. +++IMPORTANTE: es curatela económica. +++SITUACIÓN ACTUAL: Buen comportamineto en Centro Ocupacional y aparentemente sin problemas con la familia con la que convive. Aprosuba considera que podría incluso vivir en su casa de Feria con una adecuada supervisión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Dª Natividad (607-724850), hermana de Dª Antonia +++La familia con la que convive es la de una prima hermana de su padre, Dª Manuela (88 años)y la hija de esta. Está convencida de que cuando Dª Manuela fallezca sus hijos van a echar de casa a Dª Antonia, porque ya la hija se lo ha dicho. +++Dª Natividad dice que su hermana siempre se ha mostrado muy agresiva con ellos y que cuando se marchó a casa de Dª manuela se le llevó todo el ajuar de la cvasa (cubertería, electrodomésticos, etc.) y quiere que se lo devuelva, porque no tiene que adquierir todo nuevamente cuando la casa estaba completamente equipada. +++Solicita que hablemos con Aprosuba de todo ello para tratar de que se le busque una palza a su hermana para que no se quede en la calle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-10-20','VISITA DOMICILIARIA a Dª Antonia. +++Montserrat, T. Soc. SSB: considera que debe estar ingresada en un centro de mayores, aunque cometnta que en los pisos supervisados de la localidad no la van a aceptar, como ya se intentó y ella se negó, porque la conocen y saben los problemas que puede plantear. Cree que lña mejor opción para ella es la Residencia privada de Torres de San Miguel (mientras tenga dinero para costeársela). +++VISITA. Acompañado por Montserrat. Dª Antonia nos abre la puerta descalza y con aspecto de haberse levantado para ello. Su higiene y aspecto son muy deficientes (suciedad, uñas sin cortar..., con el pantalón ligeramente caído lo que permite ver que va con el pañal. También el aspecto de la casa es muy deficiente, con una clara falta de higiene y orden, especialmente en la planta baja donde vive ella, donde se acumula la ropa encima de un sofá y una cama que ocupa prácticamente todo el espacio disponible del salón, donde ella duerme, y al que se accede directamente desde la entrada (su hijo vive arriba). Nos enseña la casa, con ciertas reticencias al principio porque "...es que está muy desordenada y no he podido limpiar...". Niega que su hijo la haya dejado nunca sola, ni un solo día, aunque reconoce que ambos tienen un genio fuerte cuando se enfadan. NO QUIERE NI OIR HABLAR DE UNA RESIDENCIA. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Acudimos Montserrat y yo al gimnasio que D. Juan Carlos (su hijo: 651-664601) tiene en la localidad y que a esa hora, medio día, está vacío (al parecer han abierto otro en la localidad y sus clientes se han ido al otro). TAMPOCO QUIERE OIR HABLAR DE INGRESAR A SU MADRE EN UNA RESIDENCIA, al menos en este momento que todavía ella se vale por sí misma y para él no supone ninguna carga. NIEGA que discuatan con frecuencia (es cierto que la T. Soc. confirma que desde el último "ingreso" la situación está más tranquila)y menos aún que su madre haya estado sola varios días: "Yo le doy su medicación a sus horas, el desayuno, comida y cena y la baño (una vez a la semana). Además, yo también la necesito a ella, porque todas las personas necesitamos del afecto de quien nos quiere y ella solo me tiene a mí, porque el resto de la familia se ha desentendido completamente de nosotros...". Insiste en que la cuenta en la que está con su madre en Caja Extremadura es solamente suya, aunque su madre figure como cotitular y que ahora no puede sacar dinero de ella (solamente el 50%). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Visita al Consultorio local de Cilleros. Contactos: Dr. José Manuel y la Enferemera (Pilar). El médico, como ya me comentó en la conversación telefónica que mantuvimos, cree no solamente que la mejor alternativa para Dª Antonia es un residencia, sino que cree además que se adaptará rapidamente a ella. Ambos mencionan que la relación entre ella y su hijo es "rara", y pone los siguiente ejemplos: Antonia acude a consulta y refiere que su hijo no puede estar con otras mujeres porque padece de eyaculación p., algo que es muy raro que una madre sepa, como también son excesivos los arrumacos y cariños que se hacen cuando acuden a consulta... +++SOLICITAREMOS DEPENDENCIA Y AUTORIZACIÓN JUDICIAL DE INTERNAMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2016-10-24','Llama Gysela. Comenta que se fue a comprar dos cartones de tabaco (160€) y volvió sin el tabaco y sin el dinero, que se había gastado en las máquinas. La han sancionado recortando el dinero diario. SE están planteando llevarla a la Asociación antitabaco de Almendralejo.Nos lo dirán para subirle la asignación para los traslados. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='MARTIN'and apellido2='ASENSIO'),'2016-10-24','Nos llama Ladislao Martín, abogado de Coria (927503898), en relación con una herencia de Domingo Asensio Jorna, tío de nuestro tutelado, fallecido el 12/5/2004. Hay una vivienda en C/. Colón, 25, de Villamiel, que está en muy malas condiciones. Ninguno de los herederos quiere quedársela. La vivienda tiene un valor catastral de 6.000 euros, con una superficie construida de 105 metros cuadrados. Van a hacer las escrituras de la herencia en la notaría de Hoyos, Coria o Moraleja. Una vez las tengan nos envían borrador para su posterior ratificación aquí en una notaría de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-10-24','Se envía al Juzgado de 1ª Instancia nº 2 de Castuera fax con los informes de la UDAC y del CAMP con la evolución de D. Hermenegildo en ambos servicios. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Dª Marta, sobrina de D. Hermenegildo. "¿Qué se puede hacer para que no se esté repitiendo esta situación permanentemente? Se le explican todos los intentos infructuosos que se han realizado con su tío. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada a Cristina, T. Social del CAMP (924-021574). Se le informa de la última gestión con el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2016-10-24','Llama Dª María (¿664-819589?), madre de D. Juan Manuel. "Él quiere que le quiten la tutela y que la coja yo, pero yo no quiero". Se le indica que él puede solicitar al juzgado aquello que estime oportuno, al igual que su madre. Al parecer no hay ningún conflicto entre ellos que Dª María considere relevante, más allá de el de aguantar los caprichos día a día que plantea su hijo. +++Se le aconseja que en caso de ser necesario, no tenga inconveniente en llamar al 112 por el bien de él y de ella misma. +++Se le plantea también la posibilidad de ingresar en un centro, pero la madre dice que él no quiere. +++Le pido que se ponga su hijo, pero él se niega a hacerlo. +++También se le plantea que ante cualquier situación que se le plantee, puede llamrnos o acudir a los SSB de la localidad y ellos se pondrán en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2016-10-24','Llamada a Maribel, T.Soc. del SSB de Llerena. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamo a Dra. Constanza (924-877157): Agustín está en UHB de Llerena porque se ha tomado un bote de pintura roja. El intento de autolesión se debe al temor que él tiene de que le quiten la paga. +++PROPUESTA que le planteo: ME LLAMARÁ CUANDO SE ENCUENTRTE MEJOR PARA IR A HABLAR CON ÉL ANTES DE TRASLADARLO A LA URH de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2016-10-24','COMPLETAR: NO INDICACIÓN QUIRÚRGICA DE LA RODILLA. eL DR. RAÚL ENVIARÁ INFORME EN DICHO SENTIDO. ¿cONSULTAR A LA FAMILIA? hABLAR CON css PLASENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-10-24','25 de octubre. Eulalia Rangel Porro participa en una excursión de un día organizada por ADENEX, en colaboración con nuestro centro.La salida será a las 9 de la mañana y la llegada en torno a las 19:00 horas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-10-25','Llamada de Puri Molina, de la Residencia de Fuente Atenor (AZuaga): D. Isidoro está en "huelga de hambre". Pido que nos envíe informe al respecto para comunicar al Juzgado y seguir sus instrucciones. IMPORTANTE: SE TRATA DE UNA CURATELA A NIVEL PATRIMONIAL y EN LA ESFERA DE LA SALUD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-10-25','Conversación con Beatriz y Maribel, Psicóloga y Psiquiatra de la Subdirección General de Salud Mental sobre la búsqueda de recurso asistencial para Jesús una vez que cumpla condena el próximo 20 de enero. Hay pendiente una reunión con la Subdirectora de Salud Mental a la que convocarán también a la Comisión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Patricia, T. Soc. del C. Psiquíátrico Penitenciario de Sevilla. +++MOTIVO DEL TRASLADO:La incompatibilidad de Jesús con otro de los internos con el que ha mantenido peleas habituales durante su estancia en el Centro, favorecidas también por el carácter rencoroso de Jesús. Además de los problemas debidos a la propia infraestructura del centro que dificulta el aislamiento en estos casos, además de la temporalidad de los mismos.No era posible mantener por más tiempo a Jesús en el centro en estas condiciones. +++PROPUESTA DE RECURSO: Centro para personas con discapacidad dotado de medidas de CON CONTENCIÓN. Se envía a la Subdirección Médica del centro solicitud de informe psiquiátrico y psicológico de D. Jesús, para valorar el recurso más idóneo (FAX:955-614300).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-10-25','Se le cita para que asista el día 15/11/2016 al Juzgado de Primera Instancia e Instrucción nº 3 de Mérida, para ser reconocido por el médico forense para emtitir informe sobre imputabilidad del mismo (auxilio judicial nacional 107/2016) Caso de no asistir sin causa justificada, la citación podrá convertirse en Orden de Detención. Esta citación va relacionada con el Procedimiento Abreviado nº 432/2016, seguido en el Juzgado de Primera Instancia nº 3, de Don Benito, por delitos de amenazas graves con arma blanca contra Petra Naranjo Olivares. No tenemos que estar presente, tan solo que lo acompañe alguien del centro Sociosanitario de Mérida. No necesita abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-10-25','Me comenta María Barrasa que acompañarán a Francisco el día de la citación judicial para el reconocimiento médico forense y que la próxima semana van a derivarlo a la URH.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-10-24','COMUNICACIÓN Ctro. Penitenciario de Badajoz. El 20/10/2016 ha ingresado en este Centro procedente del hospital Psiquiátrico Penitenciario de Sevilla JESÚS VÁZQUEZ DÍAZ que se encuentra tutelado por esa Comisión.**************************************************Así mismo le informo que el mismo tien prevista la //EXCARCELACION\ el //20/01/2017\.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-10-24','COMUNICACIÓN Que D. Hermenegildo Ruíz Romero con DNI 53269058-T, tutelado por la Comisión Tutelar de Adultos de Extremadura, tras su última escapada el día 20/10/2016, se ha vuelto a escapar, siendo esta la sexta vez que se fuga desde su regreso el día 20/09/2016 al Centro Residencial "Nuestra Sra. de las Cruces", sito en la Avda. Alonso Martín, 16, después de haber pemanecido en la UDAC desde el 26/06/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-10-24','FUGA Se fuga, Hermenegildo, alrededor de las 12:55 horas. Se sigue protocolo de actuación, denuncia a la policía nacional, etc. Se localiza, tras llamada de la sobrina, a las 3:00 horas de la mañana, en Cabeza del Buey. Regresa el domingo 23 a las 10:50 horas en taxi. ***********************************************************Ahora, siendo las 11:40 de la tarde del 24/10/2016, se encuentra en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-10-25','Conversación con Pilar, T. Soc. del CSS de Plasencia. +++Acaba de volver de vacaciones y desconoce la situación de D. Juan en estos momentos. +++Le comprarán ropa y calzado porque lo necesita (saldo a fecha de hoy: 1411.64€). +++Hablará con el Psiquitra para ver qué planes hay previstos para él. Nos llamará . +++','2');
