insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2016-10-25','Visita de D. Gregorio (dirección, calle Vespasiano nº8, 2ºA y telf.680-978433), hermano de Dª Segunda, acompañado de su pareja. +++Según refiere, siempre ha sido él el que se ha ocupado de su hermana: gestiones de la casa, compra del panteón (propiedad de Dª Segunda, con la finalidad de ser ocupado por su marido -fallecido- y ella en su momento), etc. +++NO tiene seguro de deceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-10-25','Se recibe nota interior comunicando el alta de D. Agustín de la UDAC con fecha de 24 de octubre de 2016','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2016-10-25','-aplazo el contrato con la empresa de dependencia , le dan 300€ que iba a ir dirigido a habilitación psicologica. Se aplaza tras su recaida en UHB a la espera de su evolución por si hubiera que cambiar PIA.','2');
