insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-10-26','Mª DOLORES PLANTEA QUE QUIERE HACER UN NUEVO TESTAMENTO PORQUE NO QUIERE QUE SUS SOBRINAS, HIJAS DE SU HERMANO PEDRO, HEREDEN NADA DE ELLA. Mª DOLORES HIZO TESTAMENTO EN 2009, UNA VEZ ESTABA INCAPACITADA, POR LO QUE EL TESTAMENTO PODRÍA ANULARSE SI ALGUIEN LO PIDE. LAS CONDICIONES DE ESTE TESTAMENTO SON QUE NOMBRA HEREDERO UNIVERSAL A SU HERMANO PEDRO, Y EN EL CASO DE FALLECIMIENTO DE ESTE ANTES QUE Mª DOLORES NOMBRA HEREDEROS A SUS OTROS TRES HERMANOS, POR TANTO CON ESTE TESTAMENTO SUS SOBRINAS NO HEREDARÍAN NADA. VISTO EL TESTAMENTO QUE TIENE HECHO ES RECOMENDABLE NO ANULAR ESTE Y SOLICITAR AL JUZGADO QUE Mª DOLORES PUEDA HACER OTRO TESTAMENTO YA QUE CORREMOS EL RIESGO DE QUE NOS LO DENIEGUEN Y EL TESTAMENTO QUE TIENE HECHO SE ANULE, CON LO CUAL SE HARIA UNA SUSTITUCIÓN LEGAL Y SUS SOBRINAS SÍ TENDRÍAN DERECHOS HEREDITARIOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='PILAR'and apellido2='ROJO'),'2016-10-26','Llamada a Purificación, Animadora Sociocultural de la Residencia "Fuente Atenor". +++En relación a la conversación del día anterior, remite informe sobre la mencionada incidencia. La situación está estabilizada, por lo que no se considera necesario solicitar al Juzgado instrucción alguna en ese sentido. +++SE envía la sentencia de incapacitación, dado que en el punto tercero del fallo se establece que el Centro debe informar al Juzgado cada seis meses de la situación de D. Isidoro. +++LOs compañeros de la sección económica están al tanto del presupuesto de gastos enviado desde la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-10-26','Nos envía el hermano de Ceferino un correo electrónico en el que nos dice que su abogado va a iniciar el proceso de desahucio de los inquilinos, por impago de mensualidad y recibos de luz y agua. Van a presentarlo ante el Juzgado el próximo día 6 de noviembre. El proceso suele tardar unos 3 meses.','2');
