insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2016-10-27','Conversación con Maribel (Apba.9). Plantea la posibilidad de que Roberto se beneficie de la Vivienda Tutelada, dado que se prevé la posibilidad de que queden plazas libres. Mantendrían la plaza residencial mientras estuviera en la Vivienda (solicitarían el doble perfil).No va a ser algo inmediato pero nos lo comenta a la Comisión para que tengamos constancia de ello.En estos momento, no es necesario que desde la CTAEx se haga ninguna gestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-10-27','Conversación con Elena, T. Soc. +++Cree que con las llamadas se está creyendo que puede estar constantemente pidiendo dinero para comprar cualquier cosa que se le ocurra. +++Hablo con Margarita sobre el tema, haciéndole ver que sus ingresos son muy pequeños y que no puede estar pidiendo constantemente. Ahora quería comprarse una revista de tatuajes. Parece ser que ha entendido lo que le digo y ha renunciado a la revista. +++Propone Elena no cerrar las llamadas todas las semanas para hacerlo cuando lo consideremos nosotros.Le explico a Margarita que seguiré llamádola, pero que no sé qué días serán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-10-27','En relación con la asunción por parte de la Institución Malagueña de tutelas, nos indica Verónica (952607702) que el lunes nos llama para informarnos en qué estado se encuentra el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-10-31','Llamada a Soledad, T. Soc. del H. Virgen de la Montaña (927-256800).SEgún el fax remitido el pasado viernes 28, no es posible la derivación a UME de Mérida porque no hay camas en este momento y, según el informe remitido desde esta Unidad, NO HAY PREVISIÓN DE PLAZAS LIBRES PARA HOMBRES A CORTO PLAZO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con la Dra. María García Navarro, Psiquiatra encargada de Saturnino, pero la enfermera me informa que haoy no ha ido y que no sabe si acudirá. Le informará de mi llamada en caso de que vaya a trabajar hoy. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++IMPORTANTE: según Francisco, su hermano, ya ha alquilado el piso donde vivía Saturnino y este es consciente de ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2016-10-31','Contestación a la llamada realizadala desde "La Providencia" en relación a Isabel. María no está en este momento y luego saldrá de viaje. Le avisarán de mi llamada si es posible antes de salir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-11-02','Nos comunican desde el Juzgado de Primera Instancia nº 2 de Trujillo, competente para conocer la solicitud de autorización judicial de gastos extraordinarios para que Mª. Isabel pueda darle a su hermana 1.000 euros, (927321014, Loli, procedimiento 370/16), que van a visitar a Mª. Isabel a la Residencia de Jaraicejo, el día 9/11, a las 10 horas, para hablar personalmente con ella en relación con este tema. Posteriormente a esa visita, el Juzgado dictará la Resolución que corresponda y la enviará a la Abogacía General de la Junta de Extremadura. Una vez nos remitan el Auto, tenemos 10 días para contestar al Juzgado, ratificándonos en la solicitud hecha y en las actuaciones practicadas, sin oponernos a ella. He llamado a Marcos, director de la Residencia (659950675), para comunicárselo.','2');
