insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-11-02','FUGA El 31/10/2016. Se fuga alrededor de las 15:05 Hs. Se sigue protocolo de actuación. Se localiza tras llamada dela Guardia Civil en la Coronada donde ha sido encontrado en el suelo, es atendido por el 112 y llevado al Centro de Salud de Villanueva de la Serena donde es recogido por un auxiliar en taxi y regresa al centro a las 2:30 Hs. de la mañana.****************************************************Ahora, siendo las 12:18 Hs. de la mañana del 02/11/2016, se encuentra en el centro.','1');
