insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2016-11-03','-LLama la TS de Orellana para comentar que Fco no puede sacar dinero pq se le ha bloqueado la cuenta. Aunque está pendiente el inventario se realizan las ss acciones : -Se deriva el caso a Futuex ( visita , pto. economico , deudas pendientes , valoración para ingreso ...) -Se comenta con la parte economica ( desbloqueo de cuentas , pte. limitación de la pension hasta que lleguen informes de Futuex) -Se le pide a Clara ( Dependencia ) den prioridad de valoración . -Se solicita de la parte juridica expte. de internamiento involuntario en centro ( a valorar pte. informes de la visita ) -Se solicita a la TS del SSB que lo den de alta en la comida a domicilio . ( TS Amalia )','2');
