insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-11-07','FUGA Tras su última escapada del día 03/11/2016, y desconocer durante todo el día su paradero, finalmente fue localizado por la noche, tras recibir la Dirección del Centro una llamada de Manuel, sobrino de Hermengildo, quien informaba que su tío se encontraba en Cabeza del Buey, en estado de embriaguez y muy agresivo, que no atendía a razones. El sobrino nos exigía que fuéramos a recogerle. Finalmente, quien acudió fue la policía local del pueblo que avisó a la Cruz Roja que se encargó de llevar a Hermenegildo hasta el Hospital de Mérida, donde ha estado ingresado hasta el dia de hoy en Salud Mental.****************************************************Siendo ahora las 11:30 Hs, Hermenegildo ha regresado al Centro en ambulancia desde el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-11-07','En relación con el juicio sobre delitos leves nº 166/2016, seguido en el Juzgado de Instrucción nº 4, de Badajoz, nos citan, como responsables civiles subsidiarios, el día 30/11/2016, a las 11:00 horas. Hemos enviado la citación a Gabinete Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-11-08','.Alta en la UDAC , lo llevan desde el CSS al centro Aprosuba 10','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2016-11-08','-se modifica la cuantia de la PNC al fallecer la madre , pasara a percibir 551€ desde 1/4/2016 mas atrasos de 386€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2016-11-08','-NO TIENE PENSIÓN ACTUALMENTE , LA PLAZA RESIDENCIAL SE PAGA DE LA CUENTA EN COMUN QUE TENIA CON SU HNA PAULA . VOY A ESPERAR UNOS MESES PARA SEGUIR PAGANDO POR ESA CUENTA Y LUEGO TRAMITARÉ PNC .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-11-08','FUGA El día 07/11/2016, regresa al Centro a las 11:30 de la mañana, después de haber permanecido 4 días en el Hospital de Mérida en Salud Mental. A las 15:30 vuelve a salir sin permiso. Se activa protocolo de actuación con denuncia presentada en la Comisaría. Siendo, ahora, las 13:10 Hs. del día 08/11/2016, se desconoce su paradero y no se ha recibido noticias por parte de ninguna institución ni familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2016-11-08','-Su madre ha fallecido recientemente . Envia copia del cdo defuncion para solicitar pension de orfandad. Se le deriva a CAISS a traves de FUTUEX , tiene capacidad para ello y tendrán que ver la vida laboral de su madre para saber si generó derecho a pension','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-11-09','FUGA Tras su última exapada el día 07/11/2016, ha sido localizado por la policía local de Campanario a las 21:30 Hs. a donde se han desplazado dos educadores del Centro para recogerle en taxi, regresando a las 22:50 Hs.********************************************************Siendo ahora las 10:50 Hs. del 09/11/2016, se encuentra en el Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-11-09','Acudo hoy a la citación judicial en el Juzgado de Primera Instancia e Instrucción nº 1, de Mérida, en relación con el Auxilio Judicial 90/2016, a las 11:00 horas. Me dice el oficial, que José María ha acudido acompañado de un tal Antonio, de Cáritas, pero que se ha ido porque necesita hablar con su abogado de la Comisión Tutelar. No he coincidido con él. Nos vuelven a citar para el día 22/11, a las 11:40 horas. Si hubiera que designarle abogado de oficio, para este proceso, se le asigna en el propio Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-11-09','Acudo hoy a la citación judicial en el Juzgado de Primera Instancia e Instrucción nº 1, de Mérida, en relación con el Auxilio Judicial 90/2016, a las 11:00 horas. Me dice el oficial, que José María ha acudido acompañado de un tal Antonio, de Cáritas, pero que se ha ido porque necesita hablar con su abogado de la Comisión Tutelar. Nos vuelven a citar para el día 22/11, a las 11:40 horas. Si hubiera que designarle abogado de oficio, para este proceso, se le asigna en el propio Juzgado.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2016-11-09','Recibimos Diligencia de Ordenaciòn del Juzgado de Primera Instancia e Instrucción nº 1, de Valencia de Alcántara, declarando la firmeza del Auto dictado el 30/9/16, en el que se fija la Mancomunidad de Valencia de Alcántara, como lugar neutral para que el resto de nietos puedan ver a Dª Manuela, los miércoles, de 10 á 12 horas. Se lo hacemos saber a las partes implicadas y a la Mancomunidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-11-09','Citan a Luis Miguel el 30/11/16, a las 9:30 horas, en la Audiciencia Provincial Sección nº 2 de Cáceres, en relación con el Procedimiento Ordinario 10/2015, como acusado. También citan a María Luisa Rodríguez Pérez, excompañera de la Comisión Tutelar. Pongo en conocimiento de la Audiencia Provincial que ya no trabaja con nosotros y que se encuentra en Centro Residencial Cervantes, de Cáceres (927005070).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-11-10','Comunicamos por fax al Juzgado de lo Penal 2, de Mérida, que el lugar designado para que Jonathan cumpla la medida de internamiento impuesta de 5 meses (Ejecutoria 295/2016, Procedimento origen 68/2016), sea el Centro Penitenciario, de Badajoz. Estamos a la espera que nos llamen para indicarles el día que va a comenzar a cumplirla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-11-10','Recibimos liquidación del Impuesto de Plusvalías, por la vivienda sita en Avda. Hernández Serrano, 17, de Logrosán (Cáceres), que forma parte de la herencia de sus padres. Esta liquidación se gira antes de realizar las escrituras de la herencia y, en nuestro caso, aceptarla, así como pedir autorización judicial, porque su hermana Isabel ha comunicado al Ayuntamiento el testamento de los padres. Hasta entonces no podemos pagar. Van a enviarnos escrito, en el que se indica lo anterior, suspendiendo la liquidación, hasta entonces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-11-14','-NUEVO TF DE SU HNA M. JOSE 627386178','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-11-14','Conversación con Rosa (administarción): +++Avisar de la visita de Dª Clemencia Sopo Horrillo (690-014203), prima hermana de José Luis: están dispuestos a llevar a Dª Inés a Plasencia y querrían saber si podría ser un fin de semana. Una vez allí le indico la posibilidad de quedarse en el hotel de enfrente al CSS y luego ir nuevamente a recogerla. +++José Luis TINE UN ORDENADOR PORTATIL EN LA CAJA FUERTE DEL CSS. +++Llamo a Dª Clemencia: pueden ir en fin de semana, pero el CSS pide que sean avisados antes para facilitar todo lo posible el encuentro, incluso si son varios días. +++Hablo con Mª José, T. Soc. de Valle, para informarle de estas gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2016-10-11','La fecha es aproximada. Rosa Mª Rubio Glez, hermana de D. Javier (952-238383).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-11-15','Acudo a la citación ayer, en el Juzgado de 1ª. Instancia e Instrucción nº 2, de Mérida, procedimiento 599/2016. Cristofer acude también. Le asiste el abogado de oficio César González, 687936455. Le toman declaración y le reconce el forense. Cristofer renuncia a ejercer cualquier acción, civil o penal que le corresponda. Está tranquilo, dice que no quiere volver al comedor social, que vive solo, come lo que le dan los vecinos y lo que se hace él (purés, arroz...) Pregunta, varias veces, como va su pensión, está convencido que no se la van a dar. Cambia de móvil 667022144.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-11-15','Envío, vía correo electrónico, a Belén (Trabajadora Social del Centro Penitenciario de Badajoz) y a Valentín Mendo, liquidación de condena de Jesús, con fecha de cumplimiento el 9/10/2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-11-11','FUGA El 10/11/2016. Hermenegildo sale sin permiso del Centro a las 13:30 Hs., se activa protocolo y se presenta denuncia. Es localizado a las 22 hs. por la olicía local de Villanueva de la Serena, manifiestan que se ha presentando Hermenegildo por voluntad propia porque tiene frío. Acude un educador a recogerle en taxi, regresando a las 23 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-11-11','FUGA El 11/11/2016. Hermenegildo vuelve a saltar la valla a las 10:15 Hs. de la mañana, se activa protocolo. Es preciso destacar, que actualmente se encuentra en paradero desconocido en chanclas, ya que los educadores le habían retirado el calzado para evitar su fuga, pero aún así, a pesar de ir en chanclas y estar a baja temperatura, ha salido sin permiso.***************************************************Siendo ahora las 14:13 Hs. del día 11/11/2016, se desconoce su paradero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-11-15','FACTURAS FARMACIA: SE QUEDA CON LA FARMACIA EN EL PAGO TRIMESTRAL DE LAS FACTURAS. COMIENZA EN OCTUBRE DE 2016','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-11-15','Subcomisión de casos mantenida enla UHB del H.Infanta Cristina. CONCLUSIÓN: +++Actualmente con tratamineto trimestral que tiene que repetir en enero. Fabiola Psiquiatra del ESM, si se dan las circunstancias, promoverá ingreso en UHB con la previsión de, posteriormente, derivarlo a UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-11-15','Subcomsión de casos en la UHB del H. Infanta Cristina. CONCLUSIONES: +++Diagnóstico: Discapacidad intelectual leve/moderada. +++Se pedirá a CADEX valoración de perfil de D. Ramón por si un C. Ocupacional pudiera ser una alternativa como recurso para él en su localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-10-31','FUGA El día 29/10/2016. Se fuga Hermenegildo alrededor de las 19:05 Hs. Se sigue protocolo de actuación. Se ocaliza tras llamada del Hospital de Mérida, el domingo 30, a las 9:20 Hs. dela mañana, donde nos informan que ha pasado allí la noche en observación tras haber ingresado por intoxicación etílica. Acuden dos educadores del Centro a recogerle en taxi.******************************************************Ahora, siendo las 8:50 Hs. de la mañana del 31/10/2016, se encuentra en el centro.','2');
