insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2016-11-16','En relación con la herencia de su madre Sabina Ramos Rodríguez, las escrituras de aceptación y adjudicación de herencia se están haciendo en la notaría de Barcarrota (Marina 924736869 notariabarcrrota@hotmail.com). El abogado que está gestionando la herencia es Emilio Martínez (924180066-610728454 emartinez@martinezasensioabogados.es)Nos envían borrador antes de la firma. Para ello, o bien ponemos a un mandatario verbal y luego nos ratificamos o bien vamos a firmar a Barcarrota).','2');
