insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-11-16','llamo a Gisela para ver el estado en que se encuentra Mariloli, después del incidente sufrido por el autobús urbano en el que viajaba el pasado 11 de noviembre:está bien, tuvo algunas molestias en las cervicales que no han requerido de collarín. A raíz de la exploración, le detectaron cierto grado de osteoporosis, para lo cual la natación podría ser una medida adecuada, especialmente si hay una prescripción médica para ello, más allá de la puramente lúdica. Gisela nos informará al respecto de esta posibilidad.','2');
