insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-11-29','Con motivo de la Ejecutoria nº 459/2016, en la que se le impone la medida de 30 días de trabajo en beneficio de la comunidad, ponemos en conocimiento del Juzgado de lo Penal nº 2 de Badajoz, que el mismo se encuentra ingresado desde el 10 de octubre de 2016, en el centro Mensajeros de la Paz de Extremadura, en Nuñomoral (Cáceres), sita en C/. Casares de las Hurdes, s/n, 10626, a los efectos de ponerlo en conocimiento del Servicio de Gestión de Penas de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-11-29','Llama Cristina, T. Soc. de Mensajeros de la Paz: Florencio se quiere marchar el día 5 a su pueblo. Están tratando de convencerlo para que no lo haga, porque tampoco tiene dinero para ello, pero él dice que se va porque nadie se lo puede impedir según su sentencia (curatela económica). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++hablo con José Florencio: está decidido a irse del 5 al 12 de diciembre con su amigo Vicente Manga Vélez, al que conoció en Aprosuba 14, y se quedarían en casa de los padres de Vicente en Almendral. Cristina habló con teresa, hermana de Vicente, y le dijo que su hermano nunca se había quedado en casa de sus padres y que ahora ya no estaba en Aprosuba 14 sino en otra residencia (sin concretar) en la que acababa de entrar hace 10 días, por lo que no se iba a marchar a casa de sus padres tan pronto. A pesar de ello José Florencio sigue empeñado en irse con los padres de su amigo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Cristina nos mantendrá informados durante esta semana sobre cómo evoluciona la situación. Tanto para ella como para esta Comisión no es tanto el problema de que se vaya esos días como el riesgo que pueda existir de que no vuelva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-11-29','Ayer se envió correo electrónico a D.Miguel Ángel y Dª Granada informando de la plaza dada a su tío y exponiendo la posibilidad de que fueran ellos los que realizaran el traslado. En contestación a nuestro correo, la negativa a realizar ellos el traslado fue la respuesta. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Por ello, hoy se ha procedido a solicitar dicho traslado a Servicio 112 para que el mismo se efectúe en el día de mañana. SE ha avisado a la Médico y T. Social de la localidad de que es posible que el 112 se ponga en contacto con ellas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-11-29','Acude a la sede de la CTAEx. Se informa de los siguientes aspectos: +++pensión: la cobrará a finales de diciembre con los atrasos. +++planificación: se abonarán los gastos del piso y resto para alimentación. Respecto al teléfono, que tiene rota la pantalla, la propuesta es contratar con un gasto fijo de 20€/mes que no se pueda ampliar. +++PIA: plantea las alternativas de piso supervisado, CRR o SAD (300€ por 20 h/mes). Él no quiere centro, por lo que se puede intentar el SAD y, caso de que no responda, promover ingreso en centro. Cristopher nos dice que ahora le está ayudando un Pastor evangelista, que le compra la comida y él la prepara en casa (no quiere volver al Comedor Social, a pesar de nuestra recomendación para que siga en él) y que también le ha comprado la ropa que lleva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-11-29','Llamada de Emi (665-397226) a la CTAEx. Quiere ir a ver a sus hijos y quiere extra de 50€/hijo para Reyes y Papá Nöel.','2');
