insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2016-11-30','SALIDA Entre el 08/12/2016 y "después de reyes". Viaje a ver a su hermana. Sonia Bernabé, dixit: "Parece mucho tiempo, pero la verdad es que no tienen contacto frecuente, por lo que aprovechan las fiestas o periodos de vacaciones. A Juan se le nota ilusionado y la familia tiene ganas de compartir estos días con él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2016-11-30','SALIDA Entre el 23/12/2016 y el 03/01/2017. Visita a la familia en domicilio familiar. Traslado Cruz Roja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2016-11-30','SALIDA Entre el 23/12/2016 y el 03/01/2017. Visita a la familia en domicilio familiar. Traslado Cruz Roja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2016-12-01','Pedro. Acompaño a Dª Victoria a la cita del juzgado donde ha prestado declaración y ha sido reconocida por la Médico-Forense (ver declaración en expediente). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Respecto a su insistencia para ser trasaladada de Centro: +++Insiste en que "...en ese Centro hay mucha agrsividad...", pero cuando lo hace solo se refiere al comportamineto de su agresor, Ángel Delgado. +++Habla muy bien de algunos profesionales, especialmente de Andrea: "...Si me fuera la echaría mucho de menos..." +++Habla muy bien de su compañera de habitación, Rosa: "...compartimos habitación y me llevo muy bien con ella..." +++REspecto al coordinador de ASINDI, dice que "...él apoya a Ángel porque este tiene padres y yo no...", a lo que le indico que ella tiene a la Comisión para ayudarla. "Un día, (despues de la agresión que ha provocado la denuncia), estando con el coordinador, fumando, Ángel me pidió que le perdonara. Estaba muy nervioso y yo, para que se calmara, le dije que le perdonaba, pero no porque yo lo quisiera hacer..." Los comentarios que hace sobre su situación en ASINDI me llevan a pensar que NO ES TANTO QUE ELLA NO ESTÉ AGUSTO EN EL CENTRO SINO QUE LO QUE LE MOLESTA Y LE DA MIEDO ES QUE ÁNGEL ESTÉ EN ÉL. Por ello, a mi pregunta "Entonces...¿te quieres ir del Centro porque no estás bien en él o querrías quedarte en el caso de que Ángel se marchara de allí..." Su respuesta es una mirada fija en mí, en silencio, como pensando una respuesta ante una alternativa que parece ser nunca se había planteado. La tranquilizo y le pido que lo piense, porque en unos días se lo volveré a preguntar porque su respuesta es muy importante para mí. +++Pido a Katu, su acompañante, que en la medida de lo posible traten de mantener separados a ambos, a lo que constesta que ya ellos lo estan haciendo muy bien de manera voluntaria...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-12-02','Conversación con Isabel, hermana de Manuel. El piso no cuenta con las condicones necesarias de habitabilidad: carente de mobiliario, no tiene camas, faltan puertas y la cocina carece de suelo. Tras la limpieza simplemente se le dieron varias capas de pintura. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a María Barrasa para informarle del tema, pero tiene permiso hasta el día 12 de diciembre. Hablo con Maribel, quien trasladará la información al Psiquiatra que lleva a D. Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-12-02','Nos comunican desde el Juzgado de Primera Instancia e Instrucción nº 2 de Plasencia, en relación con la Liquidación de Gananciales 326/2016, División Herencia, Auto 224-2016, el Acuerdo transaccional por el que sus hermanos acuerdan pagar a Francisco 20.000 euros, quedando terminado el procedimiento. A día de hoy, aún no han pagado. Me he puesto en contacto con el abogado de Francisco para ponerlo en su conocimiento y la otra parte, le ha comentado que estaban esperando al Auto y que la próxima semana (5-11 de diciembre) harán el pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2016-12-02','Conversación con Ana, T.Soc. del centro. Se está tramintando el prtesupuesto para el arreglo de la dentadura de Antonia. Pido a Ana que solicite a la clínica informe sobre la indicación clínica de este tratamiento de implantología dental completa (Antonia no quiere otro, a pesar de las explicaciones que le han ofrecido en la propia clínica), así como otras alternativas existentes de menor coste para Antonia. Dada la cuantía del tratamineto, debemos pedir autorización judicial justificando el mismo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Quedamos en fijar una fecha de reunión para después de Reyes (si fuera posible antes de Navidad hablaríamos con antonia sobre la conveninecia o no del tratamiento o de seguir otras alternativas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2016-12-02','Viene Dª Petra, madre de Alfonso, porque no le han ingresado la pensión de noviembre: se le explica que por error se ha ingresado en la cuenta de la vicpresidenta de la Comisión y que en unos días la tendrá en su cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2016-12-02','Llamo a Bibi, T. Soc. de Aprosuba 7. Plantea la siguiente situación:todos los resiedentes se marchan con sus familias los días 24 y 25 de diciembre. Solo queda en residencia Manuel Jesús, acompañado de dos Cuidadoras. Para evitarle la sensación de desarraigo y soledad que esta situación podría provocar en él proponen el llevar a Manuel a Aprosuba de Zafra para que pase esos días en compañía de profesionales y residentes, propuesta que considero acertada contando con la acxeptación de todos los implicados en ella. Desde Aprosuba 7 SOLICITARÁN a CTAEx autorización para ello, inidcando en la misma las fechas objeto de la misma, acomapñamineto en desplazamientos (ida y vuelta), etc. La enviarán por corre-e y se le renviará convenuentemente firmada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-12-02','FUGA El 30/11/2016. A las 17:00 Hs. volvió a marcharse sin permiso, se activó protocolo. Fue localizado en Cabeza del Buey por su sobrina Marta, quien informó a la Dirección del Centro que pasaría la noche allí y regresaría al Centro a la mañana siguiente. Regresó a las 14:30 Hs. en taxi desde su pueblo natal.*****************************************************Siendo ahora las 13:30 Hs. del día 02/12/2016, se encuentra en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-12-05','Llamada de Maria Dolores. +++Ha ido a verla un "médico de los autobuses" y le ha pedido una indemnización, pero le ha dicho que eso ya se verá, que depende de lo que diga la cínica Diana. +++Protesta porque su hermano se ha vuelto muy mandón en su casa y eso no puede ser así. +++"La Psiquiatra dice -comenta María Dolores- que estoy muy bien: yo me quiero ir a un piso de alquiler con una compañera o dos de los pisos tutelados a los que le van a dar el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-12-05','Visita a D. Arturo en la Residencia "El Péndere".Me reciben Gemma (Administrativa)y Begoña (Directora). Comentan que D. Arturo ha estado muy tranquilo desde su ingreso en la residencia el pasado día 30 de noviembre. Nada más entrar, vió los andadores que usaban alunos residentes y pidió uno para él, que desde entonces está utilizando (y con el que nos ha recibido hoy durante la visita). Desde el primer momento también ha pensado que ese mismo día se iba a volver a casa y no entiende el por qué de estar allí. +++HAY QUE FIRMAR LOS TRES CONTRATOS Y ENVIARLOS POR CORRE-E Y ORDINARIO. TAMBIÉN ENVIAR COPIA DEL SEGURO DE DECESO. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON D.ARTURO: "Allí se presentó un montón de gente, me ataron los pies y las manos -que yo les dije "pero por qué me atan, ¿se creen que les voy a pegar o qué?- y me pusieron una inyección que me dolió mucho, pero mucho...Que yo pensé: bueno, pues ahora me volverán a llevar a mi casa porque yo estoy bien, no sé por qué me han traido aquí...". NADIE LE HABÍA EXPLICADO LA SITUACIÓN, NI LO QUE IBA A SUCEDER NI CUÁNDO. Este era uno de los objetivos de mi visita, explicarle su situación, la tutela y el por qué se encontarba en la residencia. Él no recordaba haber estado ante un juez, ni nadie le había explicado nada (DURANTE EL TRASLADO REFIERE QUE SOLAMENTE ESTABA EN CASA CON ÉL SU SOBRINO IGNACIO). No entiende que su sobrina ya no le podía atender, ni que un juez ha ordenado su ingreso ni que se tieene que quedar en la residencia: "Yo aquí que hago...si donde me necesitan es en mi casa..." +++Preguntado por ello, llego a la conclusión que en su casa la limpieza la hacía su sobrina Granada y su sobrino Ignacio lo aseaba. Su sobrina le llevaba la comida una vez al día, pero al parecer o bien no desayunaba y cenaba o bien comía lo que había en cada momento: "Desayunar...si total, yo como muy poco (lo corrobora la Directora) y espero a comer más tarde...". SE muestra muy educado, agradeciendo en cada momento cualquier pequeña muestra de interés que se le ofrece (ayudarle a sentar y levantar, etc.). Su pierna izquierda es la que peor movilidad tiene: "Cuando me levanto por la mañana no la puedo mover, peor después de un rato ya puedo caminar...". Con el andador se defiende basatante bien. Según la Directora, la Fiosterapeuta le ha diagnosticado artrosis bilateral. D. Arturo insiste en que él donde debe estar es en su casa, pero lo hace sin ningún atisbo de agresividad, ni mal humor. Símplemente no comprende por qué se tiene que quedar allí "...si yo me encuentro bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-07','Se envía fax al Juzgado de 1ª Instancia nº 1 de Cáceres, al no haber regresado Álvaro al centro el pasado día 4 de diciembre como se le indicó a su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2016-12-07','Carmen Ayuso (65458). Comunica que su padre ha recibido notificación de un incremento de IBI referido a los tres últimos años, ocasionado al parecer por la existencia de un doblado en la vivienda de refernecia. ENVIARÁ DICHA NOTIFICACIÓN POR CORREO-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-09','Llamada a María Gil, Gerente Novaforma: siguen sin tener noticias de Álvaro y lo que les preocupa es que solamente se llevó la medicación para el fin de semana. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al Juzgado nº 1 de Cáceres: pasaron el fax al nº 7 por estar de guardia en la fecha de los hechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-12-09','Se envía al Juzgado de 1ª Instancia nº 1 de Cáceres respuesta a la comparecencia realizada por D. Ventura ante ese Juzgado. Se envía trambién por correo ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2016-12-09','En relación con la Ejecutoria 371/2014-4 del Juzgado de lo Penal nº 1, de Plasencia (procedimiento abreviado 145/2013), en el que se le impone la medida de internamiento en centro, hasta julio de 2017, en principio iba a cumplirla en el Sociosanitario de Plasencia, pero no era centro adecuado. Se propuso el Sociosanitario de Mérida, pero tampoco lo es. Van a requerirnos para que seamos nosotros quiénes indiquemos centro adecuado para cumplirla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-12-09','Conversación con Margarita: comenta que está haciendo de "guía" de una nueva residente y que ha terminado dos puzzles Elena comenta que está teniendo muy buen comportamiento y para ella esa "guía" le está sirviendo para sentirse útil y con cierta responsabilidad y "autoridad".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-12-09','Nos comunica Cristina, T. Soc. del CRF Mensajeros de la Paz (927-433003), que José F. se ha marchado del centro el pasado día 5 de diciembre de madrugada, como ya el 29 de noviembre nos había comunicado sus intenciones de marcharse a pasar esta semana con un amigo (ver incidencia de la fecha). Llamaremos al Centro pasada esta semana. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ LIQUIDACIÓN DE CONDENA: ALEJAMIENTO DE LA MADRE desde el 14-julio de 2016 al 13-julio-2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-12-09','El Equipo Técnico del Programa Ambulatorio y Vivienda del Área de Inclusión perteneciente a Cáritas Diocesana de Mérida-Badajoz, INFORMA: Que D. JOSE MARÍA VALLE SIMÓN, con DNI 11774103-N, que reside en el piso semiautónomo de Cáritas Diocesana Mérida-Badajoz sito en C/ Juan Canet (Mérida), Va a viajar a su pueblo (Jerte) a pasar las Navidades con su familia, de modo que estará ausente del piso desde el día 22 de Diciembre de 2016 hasta el 2 de Enero de 2017. Les ruego por favor, comuniquen la recepción de esta información. Gracias Un saludo Cristina Lara Durán Área Social Programa de Vivienda Cáritas Diocesana Mérida-Badajoz Paseo de la Radio s/n 06010 Badajoz Tel: 924 260175 clara.cdmeba@caritas.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-12-09','El 5 de diciembre, Francisco ha recibido los 20.000 euros en su cuenta bancaria, correspondientes a la liquidación de la sociedad de gananciales 326/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2016-12-09','Gisela acude a la CTAEx para que la ayudemos en el traslado e ingreso si procedse de Dª Luisa en el Hospital de Mérida, donde ya fue trasladada en el día de ayer por el 112, a raiz de mostrar un importante estado de somñolencia del que no eran capaces de sacarla y de las alteraciones de comportamiento y agresividad que se produjeron con la llegada de la ambulancia. Hoy, acompañando a Gisela, hemos recogido a Dª Luisa en un bar próximo al CRR, acompañándonos al Hospital sin poner objección alguna. Allí, atendida por la Dra. Agustina, ha quedado ingresada en la UHB, no sin mostrar resistencia al ingreso, siendo necesaria la intervención de la seguridad del Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-12-12','Recibido correo de Nace. Tomás acudirá a cirugía general y digestiva el 30 de diciembre, porque sigue sin cicatrizar el desgarro sufrido tras sufrir los abusos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-12','Llamada de María (Novaforma:927-223745). La madre de Álvaro, Dª Mª José, llamó este fin de semana al Centro para informar de que había vuelto a llevvar a Álvaro al médico porque todavía no se le había curado el dedo y que se lo iba a quedar una semana más en casa (con la proximidad de las vacaciones es posible que lo que pretenda sea quedárselo durante todas ellas). La principal PREOCUPACIÓN es que Álvaro no sabemos si está tomando su medicación, porque solo se lleva la precisa para el fin de semana. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Comunico con el Juzgado de 1ª Instancia nº 7 de Cáceres (927-620263, 927-620163 y fax:927-620168): no ha tenido entrada todavía en el Juzgado el fax que la Comisión remitió el pasado día 7 de diciembre al Juzgado nº 1 y que este envió a aquel según me informaron el pasado día 9. SE explica la situación al funcionario del Juzgado y la única solución parece ser ponernos en contacto con la madre, lo cual no es posible ya que tdos los intentos de hablar con ella se han topado con el teléfono desconectado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se comunica a Carmen Barquilla (Fiscalía de Cáceres: 927-620279, fax:927-620274) la situación de Álvaro y se le remite el fax enviado a los Juzgados 1 y 7 de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-12-02','FUGA El día 02/12/2016. Volvió a marcharse sin permiso por la tarde. Se activó protocolo, fue localizado en Castuera a las 12 de la noche por la Policía Local, quien lo retuvo hasta que llegó un educador a las 12:30 Hs. y regresó al Centro a las 2 Hs. de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-12-05','FUGA El día 05/12/2016. De madrugada volvió a marcharse sin permiso, se activó protocolo. Fue localizado en la estación de trenes a las 6:35 Hs. por la Policía. Un cuidador fue a recogerle.*************************************************Siendo ahora las 15:00 Hs. del 05/12/2016, se encuentra en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-12-12','Conversación con D. Juan Ignacio Díaz (659-372675, dejar mensaje si salta el contestador). Propone mantener una reunión entre Amalia y su hija, en la que se decida si conviene o no mantener un encuentro entre ella y Ceferino. Por su abogado está enterado de lo ocurrido en el juicio y agradecido por la buena disposición que demostró la T. Social en el mismo, motivo por el cual plantean inicialmente una reunión con Amalia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2016-12-12','SALIDA Entre el 24/12/2016 (19 Hs.) y el 25/12/2016 (Hs). Tras reunión del Equipo Técnico de la entidad, se nos plantea el recurso de trasladarlo al Servicio Residencial de Plena Inclusión Zafra, donde permanecerá con sus iguales pudiendo acceder a actividades lúdicas y controlado en todo momento por personal cualificado. El tutelado lo trasladará personal de Aprosuba-7 asumiendo la responsabilidad de regresarlo a su domicilio en la fecha acordada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='DAVILA'and apellido2='TAMAYO'),'2016-12-02','Conversación con María Cadenas (La Providencia: 924-536278). Operaron a Dª Paula el pasado día 1 de diciembre para eliminar un tumor del hígado (extirparon una parte del mismo). Comenta que los cuatro primeros días tras la operación son críticos. En 15 días tendrán el resulatdo de la biopsia, pero al parecer el diagnóstico no es favorable. Volveré a llamar en unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-12-13','José Florencio volvió ayer al centro sobre las 16:30 de la tarde. Volvía en buenas condiciones, pero con unos rasguño en la cara sobre los que dió versiones diferentes: la gata de su abuela y que se cayo por un barranco. Tampoco volvió con su ordenador, que dijo se lo había dejado asu hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-12-13','Llama Susana (660-283719), concejal del Ayto. de Valdecaballeros e hija de los vecinos interesados en comprar la casa de la calle Fragua 16 de la localidad. Comenta que han enviado hace bastante tiempo dos correos-e en realción a ello, que no constan en el correo actual (quizá se enviaron al de "gobex". también otro por correo ordinario. Enviarán oferta de compra de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2016-12-13','Conversación con PIlar (coordinadora de Piso Supervisado de Zafra: 924-554651). Está prevista el alta de Beatriz en el piso para después de Reyes, pero no en el CRPS. +++Está buscando piso de alquiler. +++Enviará informe sobre la evolución de Beatriz durante su estancia en el piso, así como el estudio económico consensuado con ella para su seguimiento una vez que tenga el alta. +++Se mantendrá el seguimiento desde el CRPS. +++Propuesta (que enviarán junto al informe): todos los gastos fijos y básicos que tenga se domiciliarán, disponiendo solamente del dinero de bolsillo para ocio que se establezca en el mencionado estudio económico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-13','Conversación con Carmen Barquilla: lo ha comunicado a la Jueza y va a proceder a dar orden a la Policía para que acudan a recoger a Álvaro. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con María (Novaforma): la Policía ya la ha llamado para conocer el teléfono de Dª MªJosé (DIRECCIÓN: C/. Trajano nº 7, Cáceres) y avisarla de que irán a recoger a Álvaro. +++María enviará inoforme sobre lo ocurrido, así como descripción del estado en que ha regresado Álvaro al centro. +++De momento, SE SUSPENDEN LAS SALIDAS DE FIN DE SEMANA, en base al incumplimineto de las condiciones señaladas inicialmente y aceptadas por ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2016-12-14','Acude Ángel, marido de Castillo: nos dice que ingresó voluntaruiamente en la UHB de Mérida el pasado día 8 de diciembre y que se está planteando que, a lo mejor, cuando le den el alta, su mujer necesita una ayuda de alguna otra persona y que eso les va a suponer algún gasto más de lo habitual. Comenta que ha estado ingresada en dos ocasiines más duranbte este año. NO tienen limitación alguna en la cuenta y la curatela se refiere solamente al art. 271 del CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2016-12-14','Hablo con Clara sobre la revsión de PIA solicitada a Juan Francisco para ver posible pasdo a Grado II y proponer como PIA plaza residencial. Mañana está prevista la visita de los compañeros de valoración. NÚMERO EXPEDIENTE DEPENDENCIA: EXP DEP: BCA-10328-09','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2016-12-14','SE pasa a la firma la solicitud de elección de centro de Juan José para mantenimiento del servicio en Nuestra Señora de La Luz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-12-14','Conversación con María Barrasa. También ella había hablado con la hermana de D. Manuel en los mismos términos que lo hizo con la Comisión. +++EVOLUCIÓN: la evolcuión de don manuel está siendo muy buena, adquiriendo conciencia de su situación actual, manifestando deseos de no volver a Badajoz donde considera que le da cierto pudor la imagen que los vecinos pudieran tener de él en base a las circunstancias vividas y haciendo planes de futuro en cuanto a poder llegar el momento en que se pueda quedar en Mérida dre alquiler y retomar los estudios de idiomas en la EOI. +++DE momento no se le va a dar el alta en la vivienda del CSS, porque se considera que sería contraproducente para su evolcuión el volver allí, al margen de la inhabitabilidad del piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2016-12-14','Hemos recibido del Juzgado de 1ª. Instancia e Instrucción nº 3 de Cáceres, autorización judicial para su ingreso involuntario en centro adecuado. Comprobar situación del expediente de revisión de PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-12-14','Recibimos Sentencia nº 221/16, del Juzgado de Primera Instancia e Instrucción nº 4, de Badajoz, absolviendo a Cefereino en relación al Juicio por delito leve nº 166/16.','2');
