insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-12-15','Llama Dª isabel, madre de Jesús: quiere hacer testamento y dejar a su hijo el piso, para que después pase a sus nietos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-12-15','Conversación con Clemen. Hermenegildo, tras la última fuga, ha tenido problemas en las piernas, con temblores que le obligan a permanecer en silla de ruedas. Le están haciendo pruebas (se le indica a Clemen que si no lo han derivado a neurología). La sobrina se lo quiere llevar a casa los fines de semana de Navidad y Año nuevo, pero Clemen no considera que, en su estado actual, sea buena idea , ni que sea algo que se merezca por su comportamiento. De acuerdo con Clemen, hablaré con la sobrina y le diré que de momento no se puede autorizar esa salida en estos momentos dada la situación de salud de Hermenegildo, pero que quizá, si mejora en lo que queda hasta Navidad, se pueda autorizar dado que la alternativa, si él insisite en ir, y su problema de mobilidad ha pasado, es que se fugue del centro, por lo que se considera más apropiado autorizar el desplazamiento para que este sea controlado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con Marta, la sobrina (678-284973), pero cuelgan la llamada ( o esa sensación me ha dado).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2016-12-16','Llamada de Isabel Corchero, T. Social Coria (927-508000). Comunica que lleva tiempo intentando localizar a Dª Carmen para realizar el Informe Social que se le ha pedido desde CTAEx para realizar el inventario. Ha solcitado apoyo a la Policía Local para que lla localicen. Si en unos días no es así, nos enviará Informe en dicho sentido para comunicarlo al Juzgado. Comenta que sabe que está en la localidad, pero no responde a llamadas ni abre la puerta de casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-15','Llamo a Novaforma pero no puedo comunicar con ellos. La llamada termina por "colgarse".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-16','Álvaro HA REGRESADO HACE UNOS MINUTOS AL CENTRO (13:00) CON LA POLICÍA. +++Se evitará el contacto con la madre en estos momentos. +++Enviarán informe de situación. +++Revisar autorización de salidas y, de momento, evitar las mismas (enviar al centro dicha no autorización por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2016-12-15','Visita a Castillo en la UHB de Mérida, donde está ingresada desde el pasado día 8 de diciembre. NO le constaba a la Unidad su situación de curatela porque ella no se lo había comentado. +++Castillo se molestó con mi visita porque pensaba que queríamos, desde la Comisión, controlarla de alguna manera. Se le explicó que su marido había estado aquí el día anterior, lo cual tampoco le gustó. +++Al parecer el motivo del ingreso fue porque decía oir en su interior la voz de su marido que le decía lo que tenía que hacer y ell','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2016-12-16','Llama la hermana de Mª Antonia insistiendo en los temas de la incidencia anterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2016-12-16','Conversación con Eva, T. Soc. SSB: considera que no es preciso mantener próximo a la localidad a Dª Mª Eugenia y que la solicitud de plaza se puede, y debe , realizarse por emergencia social. +++Se plantea la necesidad de si sería preciso valoración psiquiátrica antes de determinar el Centro adecuado. +++Llamo al C.Salud para solcitar Infrome médico para revisión de grado: la médico se ha jubilado y la suplente , Dra Puerto Pérez Pérez, está saliente de guardia (927-271378). Llamar el lunes. +++Valorar ingreso por E. Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2016-12-19','-Se acepta por PIA( GRADO 1 ) VIVIENDA TUTELADA DE DISCAPACIAD .Una vez que nos asignen el recurso de discapacidad , hay que solicitar que se le incluya en el Equipo de Salud Mental que le corresponda , asi se establece en su PIA.','2');
