insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='OSCAR'and edp.apellido1='BLAZQUEZ'and apellido2='PEREZ'),'2016-12-19','-Se recibe escrito del CSS de un abogado de CC que tiene la madre de Oscar , que pide unas exigencias como madre sin tener en cuenta que el chico está tutelado . La madre sabe de sobra que es así , lo visita semanalmente en el Centro y desde el dpto de TS así se lo han comunicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2016-12-19','Llama Esmeralda, de Ático Soluciones Inmobiliarias (924-487264), interesándose por el piso de D. Ricardo, a raiz de que él se ha presentado allí para venderlo, le ha dado el nombre de su madre y esta ha comentado a la inmobiliaria que está tutelado por nosotros. Cuando estemos en disposición de vender, Esmeralda muestra interés en la compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-12-19','Conversación con Daniel Pizarro, Psiquiatra CSS Plasencia (927-428800). Sobre situación previa a alta: +++Ya han solicitado plaza en Pisos Supervisados. Ha tenido entrada en la Unidad el 14 de diciembre y tienen prevista Subcomisión para enero (se informa de ello a Daniel). +++Familia en Logrosán: NO EXISTE familia alguna en Logrosán como Juan le ha dado a entender a Daniel, diciéndole además que querrían ocuyparse de él. Tanto desde el SSB como Mari Carmen, su hermana, confirman que NO EXISTE FAMILIA ALGUNA EN LOGROSÁN (informo también de ello a Daniel).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2016-12-19','Correo-e remitido por Blanca, T. Soc. del CSS de Mérida:TRAS CONVERSACION TELEFONICA CON LA DRA VALVERDE, SE INFORMA QUE LA PACIENTE VERA-LUCIA DA CONCEICAO BEZERRA PASARA LOS DIAS DE NAVIDAD 23,24,25 Y 26 DE DICIEMBRE DE 2016 CON SU AMIGA MARNI EN SU DOMICILIO. UN SALUDO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-12-19','COnsulta a Carmen Ferrer: La solicitud presentada para pisos supervisados es de abril de este año.Se ha aceptado su perfil y se está pendiente de resolución de grado de discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-20','Conversación con María (Novaforma). La madre de Álvaro no ha vuelto a ir por el centro, pero llama constantemnete reclamando que su hijo vuelva con ella y profiriendo insultos cada vez que llama. Álvaro se encuentra bien. Reclama volver con su madre de vez en cuando, pero su actitud sigue siendo la habitual. El dedo lo lleva perfectamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-12-20','Conversación con Clemen (924-021562).Hermenegildo sigue en la misma situación: continúa en la silla de ruedas porque persisten los temblores de la piernas. El médico dice que hace intención de caminar, pero no quiere abandonar la silla (se Clemen, podría ser algo también psicológico en el sentido de justificar el que no intente escaparse por encontrarse malo). +++Ha llamado una hermana de Hermenegildo, Dª Manuela (674-404981), que vive en Almodóvar del Campo (Ciudad Real), que ha pedido al CAMP llevarse a su hermano una semana para Navidad. La CTAEx nunca ha hablado con esta señora, pero de acuerdo con Clemen, no se considera que sea el momento adecuado para autorizar dicha salida, dad la situación en la que Hermenegildo se encuentra. +++Al igual que el viernes pasado, intento hablar con la sobrina, Marta (678-284973), pero cortan la llamada sin descolgar. Lo mismo pasa ahora cuando he llamado a Dª Manuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='ARNOSI'and apellido2='PEREZ'),'2016-12-20','PENSION El 20/12/2016. Remitida solicitud rectificada junto con documentacion necesaria para Prestación por Hijo a Cargo. El 20/12/2016. Fecha registro del oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2016-12-20','Llamada de Mª Jesús (52076), de Infancia y Familia. Enviará la documentación requerida por fax y correo ordinario. Informa de que la Prestación por Hijo a Cargo hay que solicitarla antes del 31 de diciembre para que no se le de baja a partir del 1 de enero.','2');
