insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-12-20','Sale el 20/12/16 del centro penitenciario de Badajoz y lo trasladan directamente ese día al Sociosanitario de Mérida, para cumplir la medida pendiente hasta el 9 de octubre de 2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2016-12-20','Conversación con José Tello. Enviará plano de las fincas por corre-e. Preguntar en catastro precio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-12-21','Conversación con Mª Carmen (605-413652), hermana de Juan. En Zorita hay familiares en 2º y 3º grado. Solamente hay una prima que padece fibromialgia. En cualquier caso, considera que nadie está en condiciones de hacerse cargo de su hermano. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Daniel, Psiquiatra (924-428800 y móvil 650-155243 solo en caso necesario). No tiene motivos para mantener el ingreso durante mucho más tiempo. Consultaremos al juzgado en qué situación se encuentra el procedimiento de ampliación de la capacidad solicitada en julio. EN CASO DE ALTA, COMUNICAR AL JUZGADO LA NO EXISTENCIA ALTERNATIVA AL INTERNAMIENTO. +++Daniel plantea una hospitalización intermedia: mantener el contacto con el CSS mientras él reside en una pensión. El problema de ello es el nivel de ingreos de Juan (PNC) y su adicción a las máquinas tragaperras). A fecha de hoy, su saldo es de 1526.04€ +++VALORAR en base al procedimiento abierto en el juzgado. +++Daniel vuelve a llamar para comunicar que al menos durante las Navidades se mqntendrá el ingreso de D. Juan en el CSS, intentando que acepte la posibilidad de los pisos supervisados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-12-21','Llama Dª Manuela, hermana de Hermenegildo. Quiere llevarse a su hermano a Ciudad Real desde hoy hata el lunes. Se le explica que en las actuales circunstancias quizá no sea un buen momento para viajar, pero insiste en que va a ir a verlo y solicita autorización para llevárselo. +++Se le indica que si el médico y la dirección del Centro están de acuerdo en que pueda y sea conveniente irse la Comisión no se opondría. +++Dª Manuela refiere que es Ax de Clínica en una residencia y que puede atender adecuadamente a su hermano. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Clemen envía informe del estado de Hermenegildo, considerando esta Comisión que no está en condiciones de marcharse del centro salvo criterio facultativo contrario a esta decisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-12-21','En relación con la modificación de la capacidad de Juan, para pasar de curatela a tutela, el Juzgado de Logrosán se inhibe a favor de los de Plasencia. Este aún no se ha puesto en contacto con nosotros. Hasta este momento, seguimos ejerciendo la CURATELA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2016-12-21','Conversación con la cuñada de D. José A. +++Pide 1700€ para los gastos de su tío. Se le informa que lo que se le va a dar es lo siguiente: +++++1000€, por el mes de diciembre, en los que se incluye el alquiler (350€) para los gastos. +++++Reparación del calentador:deberá presentar factura o hacerlo el técnico que lo arregle para poder cobrar dicha reparación. +++++Todo lo que salga de los gastos corrientes (ropa, reparaciones, etc.) se solicitará previamente para su autorización o no. +++++Se realizará visita por FUTUEx para elaborar un PRESUPUESTO MENSUAL que se abonará a D. Indalecio Quirós Sauceda (DNI:09156398-Y). Según su cuñada, VAN A SOLICITAR LA REMOCIÓN DE LA TUTELA con la finalidad de que sea su hermano el que se haga cargo de ella.Se le explica el procediemiento para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-12-21','En esta fecha se comunica a Jonathan la orden para cumplir la pena de internamiento por 5 meses interpuesta por el Juzgado de lo Penal nº 2 de Mérida y que deberá cumplirse en el C. Penitenciario de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2016-12-22','Conversación con José Mª de la Concepción, de Aprosuba 3 (639-672766): +++Enviarán factura de hotel con número de cuenta para estancia de 3 noches del 24 al 26 de diciembre. 180€. Se pagará por transferencia. +++SE autoriza reintegro de 70€ para gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2016-12-21','SALIDA El 20/12/2016~~. Ha salido del Sociosanitario de Mérida de permiso para pasar la navidad con su familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2016-12-22','Conversación con José Mª de la Concepción, de Aprosuba 3 (639-672766). +++Diego se ha marchado con la familia el pasado día 20. +++Están interesados en hablar con la Comisión, al parecer del tema de la herencia. Según comenta José Mª, preguntaron qué pasaría con la herencia de Diego en caso de que falleciera.LLAMARÉ UNA VEZ QUE DIEGO ESTÉ DE REGRESO EN APROSUBA 3 (a partir del 6 de enero).Teléfono de Dª Socorro, hermana de Diego, 637-374390.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2016-12-22','- Alejandro reside en PROA y periodos vacacionales el CAM Isabel de Moctezuma en Caceres . - Se le ha tramitado PHHC para + 18 años . - No Se le va a tramitra P. Orfandad Absoluta ya la cobran los tres hermanos. - Hay que solicitar plaza de discapacidad por dependencia. ( grado 3)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='GARCIA'and apellido2='DE PRUNEDA TREVIJANO'),'2016-12-22','-se le visita en la residencia de mayores para aclarar su limitacion economica , ya se ha resuelto 75€/ semanal .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-12-22','Hablo con Noelia, Residencia Novaforma (927-629107)La propuesta del Equipo Interprofesional de Novaforma es la de visitas supervisadas fuera del domicilio familiar hasta que la conducta de Dª Mª José cambie en el sentido de aceptar las condiciones propuestas para volver a las salidas de fin de semana. Sin embargo, consideran que la Residencia no es el lugar adecuado por los antecedentes previos de conductas disruptivas de la convivencia cuando se han producido, por lo que plantean PUNTO DE ENCUENTRO FAMILIAR. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al PEF de Cáceres. Contacto Ana Rodríguez, 618 020 732. Me dirige a los compañeros de Infancia y Familia, Lucas (924-008835) y Mª Dolores (924-008833). Hablo con esta última y quedo en que consultará la posibilidad de atender a una persona adulta pero incapacitada legalmemente, dado que el acceso al PEF solo se puede realizar a petición de los juzgados o de la propia D. General.Dejo mi teléfono y correos-e. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mª José pero cuelga sin descolgar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con MªDolores (PEF): los puntos de encuentro familiar están dirigidos exclusivamente a los menores y sus familias y siempre por orden judicial. Además no se admiten casos en los que exista la posibilidad de conductas disruptivas que puedan afectar el buen funcionamiento del recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMINO'and edp.apellido1='GOMEZ'and apellido2='MARTINEZ'),'2016-12-22','-se le visita desde CTAEX en la residencia de Olivenza , perfectamente adaptado . Se concreta el pago de la plaza residencial . Tf de una hermana de madrid 916184781 Tf de su sobrina Vanesa 629956449','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2016-12-22','PENSION DE ORFANDAD Remitida el 22/12/2016. Registrada con f/ 22/12/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2016-12-22','PENSION POR HIJO A CARGO Remitida el 22/12/2016. Registrado en f/ 22/12/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-12-22','-Renuncia a su plaza residencial de RAL en Mensajeros de la Paz de Nuñomoral . - el dia 27 nos llama para que paguemos el hostal los amigos en Olivenza hasta que le vuelvan a dar plaza en Olivenza, se le explica que no tiene ninguna plaza . -Llama un taxista al que él le ha pedido que vaya a Nuñomoral a recoger sus pertenencias y al que se le deben 50€ de otro servicio anterior. Se le pide que no vaya a Nuñomoral y se le van a abonar estos 50€. - Al ser una curatela economina , no vamos a buscan ninguna plaza residencial más , teniendo en cuenta las innumerables ocasiones en que posteriormente él renuncia a las mismas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2016-12-27','-Enviada PFHC con fecha de entrada de hoy . -La p. orfandad se queda como está , en el mismo numero de cuenta ( está el solo y se añadirá a la Gerenta Sepad ) y ya percibe la absoluta .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2016-12-28','- Se envia un Cambio de circunstancia a PFHC de Badajoz para cambiar el numero de cuenta .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2016-12-28','-Se solicita (PFHC) . No tiene derecho al complemento de ATP , sólo tiene 8 puntos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2016-12-28','- Valorar cambio de PIA , tiene C.Dia +SAD , puede ser que necestie RAE . Enviar a Futuex y pedir informe .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2017-01-02','Se envía por fax (924-231645) y por correo ordinario Consentimiento Informado para administración de anestesia. Carmen, Psicóloga del CRR comenta que se encuentra mejor desde que ha podido retomar el contacto con su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2016-12-30','+++Desde el CSS de Plasencia, se informa al Juzgado de lo Penal nº 1 de esta localidad del ingreso voluntario de José María en el C Penitenciario de Cáceres. +++también se informa a esta Comisión de dicho ingreso por un PERIODO DE SEIS MESES, encontrándose en estos momentos "estable a nivel psicopatológico".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2017-01-02','Llamada de Mª José Montesinos (ASINDI, 927-390974). INCIDENCIAS: +++Viernes 30 dicimbre: Victoria provoca un incendio en la 1ª planta de la Residencia, quemando un sofá. SE le trasalada al médico pero consideran que no existe criterio para ingreso. +++Sábado 31 diciembre: por la mañana, provoca un nuevo incendio en la habitación que afecta además al entorno de la misma. Esto provoca el dealojo del Centro y la imposibilidad de su ocupación, lo que da lugar a que, hasta que se pueda volver, algunos residentes se hayan ido con su familia y otros se enecuentran alojados en las dependencias cedidas por la Residencia de Mayores de la Localidad. EN ESTOS MOMENTOS, VICTORIA SE ENCUENTRA INGRESADA EN LA UHB DEL h. Virgen de la Montaña. +++SLe comento a Mª Jose la conversación que mantuve con Victoria en el Juzgado el día 1 de diciembre: me comenta que por sus rasgos psicopatológicos es una persona que desconfía de todo el mundo y que antes de estos incidentes fue a la Guardia Civil a denunciar a Ángel. NO parece que éste sea el problema, deduzco de lo que Mª José comenta, sino los rasgos psicopatológicos a los que se refiere. Miguel Simón es conocedor de estos hechos y de Asindi enviarán informe detallado de lo sucedido. ++++++++++++++++++++++++++++++++++++Mª José refiere que Victoria tiene claros rasgos patológicos de esquizofrenia ..., habiemndo solicitado habilitación funcional al CADEX para su tratatmiento, si bien no se puede curar, al menos tratar. Respecto a la alternativa de Centro, Mª José considera que si hubiese uno en el que sus ragos patológicos fuesen convenientemente atendidos, ese sería el adecuado. Pero dado que no existe , le digo, un centro para atender patología dual, no parece que un centro de discapacidad sea el recurdso más adecuado para Victoria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2017-01-02','Enviamos al Juzgado de Primera Instancia e Instrución nº 1, de Villafranca de los Barros, autorización y aprobación judicial de la herencia de sus tíos, Manuel Pecero Tinoco y Antonia Cháves Cuellar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-01-02','Recibido por correo-e Informe de Incidencias en relación a Beatriz:DESCOMPENSACIÓN PSIQUIÁTRICA el pasado 25 de diciembre que motivó su ingreso en la UHB de Llerena donde continúa ingresada. La salida inicialmente prevista del piso supervisado QUEDA APLAZADA hasta que se den las condiciones para promoverla nuevamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2014-04-22','Nos llama Candelas del CSS para informarno que José Mª volverá de vacaciones de Semana Santa el día 229 y no el 28 como habíamos autorizado.Y que tal y como convenimos las dos antes de marcharse de vacaiones le dio 100 Euros para su estancia en el domicilio familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN ANTONIO'and edp.apellido1='EVERLISTA'and apellido2='LEONISA'),'2017-01-03','Enviamos a Escalona, vía correo electrónico, expediente de jurisdicción voluntaria para ingreso involuntario con los documentos foliados, para que se los envíe al Juzgado de Prmera Instancia nº 4 de Badajoz, vía lexnet.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-01-03','Llama D. Luciano (685-804272), taxista de Barcarrota. José Florencio le ha pedido que lo lleve a recoger la ropa que dejó en Nuñomoral y le ha dado nuestro teléfono para que le paguemos el desplazamiento (no es el mismo taxista que el referido en la incidencia anterior (22-12-2016). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Nuñomoral: Cristina está de vacaciones. Hablo con Daniel, Psicólogo del centro: efectivamente, José Florencio dejó ropa en el centro. Comenta que ha llamado varias veces durante estos días para hablar con Cristina porque no se creía que estuviera de vacaciones y "en ninguna ocasión ha mencionado nada de la ropa, solo que quería hablar con ella." Le propongo a Daniel que envíen a la ropa a la dirección que José Florencio nos indique, a lo cual no pone impedimento alguno. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelvo a llamar al taxista para no autorizar el desplazamiento y pedirle que si habla con José le diga que nos llame a la Comisión y LE ENVIAREMOS LA ROPA A LA DIRECCIÓN QUE NOS INDIQUE: "Yo, como se que él no está bien, les he llamado a ustedes para saber si autorizaban el desplazamiento o no..." -comenta D. Luciano. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Cuando hablemos con José Florencio, que INDIQUE LA DIRECCIÓN A LA QUE Mensajeros de la Paz DEBE ENVIAR LA ROPA. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llama José Florencio (TELÉFONO:643-182681). Ha enviado presupuesto para comprar una cama, porque dice que no tiene y quiere que le mandemos a su madre el dinero que antes le enviábamos para su manutención: "Ella me trae la comida todos los días..." a pesar de la Orden de Alejamiento que pesa sobre él y de la cual se le informa en caso de quebrantamineto: "Sí Ya lo sé. He estado ya dos veces en el calabozo...". La dirección que nos da para enviar la ropa es la casa de su abuela, calle Arriba 55, de Barcarrota. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a la Secretaria Judicial del Juzgado de 1ª Instancia e Instrucción nº 1 de Jerez de los Caballeros. Le explico la situación, la curatela de carácter económico que ejercemos sobre José Florencio y el quebrantamiento de la Orden de alejamiento que se está produciendo. Ya en el Juzgado han abierto un procediemiento en base a dicho quebrantamiento a raíz de llevar la Guardia Civil a José Florencio al Juzgado. ME PROPONE ENVIAR POR FAX (924-730634)UN INFORME AL JUZGADO SOBRE LA SITUACIÓN ACTUAL, que pasarán a la Fiscalía para que actúe al respecto, uniéndose al procedimiento referido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-01-03','Llamada de Dª Mª Estrella Gómez (625-960751), madre de Vanesa: quiere informarse de la situación en que se encuentra su hija. Comenta que vive con sus hermanos y que ella quiere volver al Aprosuba. "A mí me gustaría quedarme con ella, pero yo también estoy mal de salud y económicamente...¿Ella no tiene derecho a alguna pensión por su discapacidad? Le pido que le diga a su hija que nos llame para hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-01-03','Visita de los padres y hermano de Ramón para saber si lo vamos a llevar a un Centro o no. Ya los Psiaquiatras con los que han hablado les han comentado las dificultades existentes para encontrar un centro que se adecue al perfil de su hijo. +++Comentan que no han recibido desde hace unos meses los 275€ para la manutención de su hijo. Una vez comprobado en su cuenta, dicha transferencia se ha seguido realizando durante los meses de octubre, noviembre , diciembre y enero, manteniéndose activa en estos momentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='HOLGUIN'and apellido2='MENESES'),'2017-01-04','Se recibe Informe de Alta de fecha 27 de diciembre de 2016 y relación de gastos de acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-01-04','Se envía por fax al Juzgado de 1ª Instancia e Instrucción nº 1 de Jerez de los Caballeros el Informe solicitado por la Secretaria Judicial. Se solicita en él INSTRUCCIONES para actuar ante esta situación y no "facilitar" así el posible quebrantamiento de la Orden de alejamiento. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Nuñomoral. Hablo con la Piscóloga: enviarán sus pertenencias a la dirección indicada por José Florencio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMINO'and edp.apellido1='GOMEZ'and apellido2='MARTINEZ'),'2017-01-04','La familia comunica a la Residencia "Virgen de Guadalupe" el fallecimiento de D. Maximino en la mañana de hoy y desde la Residencia se ponen en contacto con la CTAEx para saber cómo proceder: ROSA (697-165236). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Confirmamos el fallecimiento con MERCEDES MENAYA,T. Soc. del Hospital "Perpetuo Socorro" (924-215144): el fallecimiento se ha producido a las 08:03h de esta mañana. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Dada la nula información que tenemos sobre D. Maximino en relación a sus cuentas y existencia o no de seguro de deceso (la aceptación del cargo es de 22 de noviembre) me pongo en contacto con la Mancomunidad "Río Bodión". No puedo hablar con ninguna de las T. Sociales por estar ausentes por vacaciones y bajas. Hablo con la GERENTE de la Mancomunidad, Eva Arenal (645-809145) quien, tras hablar con Olga (T. Social) le confirma que al parecer tenía ahorros pero no sabe si seguro de decesos o no. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Rosa: Esteban, sobrino de D. Maximino, ha hablado con ellos y les ha dicho que AL PARECER SU TÍO TENÍA SEGURO DE DECESOS CON LA COMPAÑÍA "LA ALMUDENA", y que era VOLUNTAD de D. Maximino ENTERRARSE EN SU PUEBLO, VALVERDE DE BURGUILLOS, en el NICHO EN EL QUE YA ESTÁ ENTERRADA SU MUJER. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Contacto con Mº Carmen, de la Compañía "LA ALMUDENA" (901-242526): CONFIRMA que D. Maximino es uno de sus asegurados. SE LE DA LA SIGUIENTE INFORMACIÓN: +++Deseos del finado para su enterramiento según la familia. +++Teléfono de contacto con el H. "Perpetuo Socorro". +++Teléfono de contacto con la Residencia "Virgen de Guadalupe". +++Teléfono de contacto de Dª Josefa, hermana de D. Maximino.Se pondrán en contacto con la familia para concretar detalles (velatorio, etc.). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Comunico nuevamente con Rosa y con Mercedes para informarles sobre las gestiones realizadas con la compañía de Seguro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='RODRIGUEZ'and apellido2='FERNANDEZ'),'2016-12-23','SE gestiona acompañamiento hospitalario. D. Antonio (hermano:634-226200): se le comunica la persona que va a acompañar a su hermano de 18h a 08h cada día hasta el próximo juevesb 29 (si hiciese falta prolongarlo se comunicaría).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='RODRIGUEZ'and apellido2='FERNANDEZ'),'2017-01-03','Intento hablar con María Barrasa sobre el acompañamiento, pero está de vacaciones. Trato de hablar con Blanca pero no comunico con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='RODRIGUEZ'and apellido2='FERNANDEZ'),'2017-01-05','Conversación con Blanca:D. Pedro fue dado de alta en el Hospital el pasado día 29 de diciembre, retornando al CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-01-05','Se recibe Providencia (fax) del Juzgado de 1ª Instancia e Instrucción nº 1 de Jerez de los Caballeros, dando cuenta de la recepción del escrito de la Ctaex e informando de su traslado al Ministerio Público para que informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2017-01-05','Aurora nos facilita el nuevo nº de teléfono, 685 46 28 54 es de Orange y de tarjeta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-01-05','Recibimos citación del Juzgado de lo Penal nº 1 de Plasencia, para comparecer el día 20/1/17, a las 10.45 al protocolo de conformidad por un posible delito de lesiones contra Juan Antonio Martín Soria. Tiene abogado Javier Ramos Rojo. Tenemos que asistir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2017-01-05','Solicitamos DNI de Francisco a la TS de Orellana, Dolores 924867801, para enviar al banco, pero nos comenta que no enviemos la documentación hasta que llegue la valoración por dependencia para ingreso en centro, para no bloquear la cuenta en Banco Santander de Orellana(Jose Carlos Venero 924866156), que es donde están domiciliadas las dos pensiones (una pensión de orfandad 620€ y una prestación familiar x hijo a cargo 367,90€)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-01-05','En relación con el monitorio 684/16, seguido en el Juzgado de Primera Instancia e Instrucción nº 3, de Cáceres, solicitamos aplazamiento y fraccionamiento de los 163 euros que la reclaman, para pagarlos a partir de febrero de 2017, que es cuando cobra la pensión. Ahora tiene 9,82 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2017-01-05','Del Comité Ciudadano Antisida de Extremadura se comunica a esta Comisión que D. Javier Rubio González se ha marchado en la mañana de hoy del recurso mencionado de manera voluntaria. Al parecer, este hecho ha sido motivado por la llamada de atención que D. Javier ha recibido de parte de los profesionales que lo atienden debido a su reiterado incumplimiento de las normas exigidas por el Centro. Según se informa a esta Comisión, D. Javier mencionó que se marchaba a casa de su madre en la localidad de Cañamero. SE COMUNICA AL JUZGADO ESTA CIRCUNSTANCIA POR fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2017-01-05','Cáceres, a 4 de Enero de 2017 Yo, María José Alvárez Molano, madre del usuario de residencia Álvaro González, y de acuerdo al procedimiento que establece la comisión tutelar de la Junta de Extremadura, respecto de las salidas en fines de semana y festivos, que Álvaro González Álvarez pudiera realizar fuera del recurso residencial, SOLICITO, que la comisión anteriormente referenciada, de su consentimiento para que Álvaro González Álvarez pueda efectuar salida el día 5 de Enero de 2017 a las 17:00 horas, habiéndose programado encuentro para esa hora en una cafetería próxima al centro residencial. María José Álvarez Molano +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Noemí (T. Soc. Novaforma: 927-629107): no hay problema en llevar adelante el encuentro programado para esta tarde. Nos informarán al respecto de su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2017-01-09','Se solicita certificado de nacimiento al Juzgado de Paz de Aliseda para enviarlo a la notaría de Elgoibar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2017-01-09','Nos citan para acudir al Juzgado de Primera Instancia nº 1 de Villanueva de la Serena, en relación con las DPPA 526/2016, abusos sexuales contra José Donoso Casado, a las 11:15 horas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2017-01-11','Conversación con Sonia. Victoria sigue ingresada en la UHB en estos momentos, si bien el alta estaba pensada para el martes de la semana pasada. Solicitaron al Psiquiatra que hablase con ella sobre la vuelta al centro y ella respondió que si la volvían a llevar allí volvería a hacer lo mismo. +++Estuvo visitando el Consolación con Centro Cristina (Gerente Territorial).ALTERNATIVAS: TRASLADO A UDAC una vez le den el alta en la UHB; otra posibilidad que plantean el el centro es la UME. SE le indica a Sonia que esa derivación depende de que el Psiquiatra valore la existencia o no de criterios clínicos para la misma. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Miguel Simón: parece que la única alternativa que se baraja es la UDAC, para la cual ya se han empezado los trámites desde los SS.Territoriales.SE recuerda que una vez dada de alta en la UDAC ha de volver nuevamente a ASINDI. Según evolución en la UDAC se tomarán las medidas oportunas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2017-01-11','Conversación con Laura Pulido Méndez (Dependencia PIA 78021): +++Negociarán con D. Juan plaza en Badajoz, Mérida y Montijo. +++Informarán sobre vinculada y el uso que de los ahorros debería hacer para el pago de la plaza (curatela "sin sustituir su voluntad"). +++Ya tiene el diagnóstico de Demencia pero ha de pasar todavía por Neropsicología.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2017-01-12','Conversación con D. Cándido (924-670580). Este viernes va a ir el albañil. Le digo que nos tiene que enviar el presupuesto de la obra antes de hacer nada. Al parecer ya se lo dió a la T. Social del SSB pero no nos consta que lo hayamos recibido. Comenta que son alrededor de 250€. Enviará presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2017-01-12','Llamada de Catalina (657-637918): quyiere contratar un "catering" que lleva la comida a domicilio. Está en el bar "La Bodega de la Comida" y su encargado se llama Paco (691-204273). Al parecer se ha enterado por una amiga y supone un coste mensual de 70€. +++MOTIVO: "Es que quiero descansar un mes o dos de tener que comprar y hacer comida...Además me sale más barato porque no tengo que usar el gas, ni fregar los platos, etc...". +++ANTES de aceptar o no debemos hablar con el encargado para ver en qué condiciones presta el servicio, qué incluye, si se puede abonar por transferencia, etc. +++Se le explica a Catalina que los 70€ SALDRÁN DE SU ASIGNACIÓN MENSUAL, a lo cual ella se niega porque lo que realmente quiere es tener 70€ más todos los meses para, como ella dice, "comprar unos cuadros para la casa, y otras cosas que necesita..." Enfadada ante esta situación , cuelga brúscamente el teléfono. +++NO SE HARÁ NINGUNA GESTIÓN AL RESPECTO, EN TANTO ELLA NO ACEPTE LAS CONDICIONES INDICADAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-01-12','Acude Jonathan a la Comisión. Se le indica que debe ingresar en el C. Penitenciario de Badajoz en esta semana porque en caso contrario lo pondrán en rebeldía. +++Se le vuelve a entragar la documentación que debe presentar en su ingreso. +++Pide 30€ por que dice tener lo puesto y necesita unos pantalones (el dinero que se le dió para la tarjeta del móvil la ha empleado -dice- para comprarse la "chupa" que lleva puesta. +++Llamo a Antonio (687-969982), su hermano, para ver la posibilidad de que lo lleve a Badajoz: una vez confirmado por Ángel que el ingreso puede ser por la tarde (antes de las 20:00h), su hermano está dispuesto a llevarlo, pero necesita algo de dinero siquiera para la gasolina porque su situación económica es mala. +++Quedo con Antonio, y se lo digo a Jonathan, que su hermano lo espera a las 15:10h en la puerta del SEPAD, una vez que salga de su trabajo.Se le AUTORIZA SACAR 40€, de los cuales 10€ se los dará a su hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2017-01-12','Nos llama Raquel Franco, abogada de Barcelona (934582053 - rfranco@gabarroadvotats.com). Está tramitando una herencia de una tía de Rosa. Va a hereder 6.000 y pico de euros. Me envía documentación para que firmemos un documento privado, debido a que no van a hacer Escrituras de Herencia, al no haber propiedades inmuebles. El dinero está en Banco Sabadell y según la abogada, para cobrar ese dinero en la cuenta de Rosa tendríamos que abrirnos una cuenta en el Banco Sabadell. Le he pedido el teléfono para hablar con el banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2017-01-12','INFORMACIÓN TUTELADA Fue Enfermera ~ No tiene seguro de deceso ~ 45 años ~ de Usagre ~ Cuenta en Caja Rural de Extremadura en Usagre (Mancomunada con su padre y otra hermana) ~ Reside en el CSS de Mérida ~ Su cuñado se llama Aejandro Espina Limones, reside en Sevilla y su nº. de móvil es el 653770998.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-01-13','Ayer acudió con su hermano para ingresar en prisión pero NO PUDO INGRESAR POR CARECER DE DNI. LO HA PERDIDO. Tras hablar con el C. Penitenciario (Belén, T. Soc.) y con la Oficina del DNI de Mérida, se acompaña a Jonathan a hacer una copia del DNI para que ingrese esta tarde.SALE CON EL NUEVO DNI (dejo fotocopia del mismo en el expediente). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Aviso a Belén del ingreso que va a realizar esta tarde y ME CONFIRMA QUE NO ES POSIBLE EL INGRESO SIN EL DNI ORIGINAL. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++lLAMO A aNTONIO, SU HERMANO: me confirma que trasaladará a Jonathan a Badajoz esta tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2017-01-13','Llama abogada del turno de oficio de Villanueva de la Serena para conocer la situación de incapacidad del tutelado. Informa que los familiares va a solicitar la remoción de la tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-01-16','-visita en las oficinas de la madre de Jonathan y su pareja para hablar del estado de su hijo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ABDONA MATILDE'and edp.apellido1='SANCHEZ'and apellido2='HERNANDEZ'),'2017-01-16','FALLECIDO El 06/01/2017. A las 08:30 Hs.','2');
