insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-01-16','-Concedida la ayuda por alquiler de vivienda ( 525€)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-01-16','Llama José Florencio: dice que no le ha llegado la ropa que dejó en Nuñomoral y que quiere 200€ para pagar unas deudas que tiene en Olivenza (de las cuales no mencionó nada en la última conversació). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Raquel, directora de Mensajeros de la Paz: no han enviado las pertenencias de José Florencio a la dirección indicada porque son varias cajas, maletas, una TV, etc. y no saben como pagar la mensajería. INDICACIÓN: NO ENVIAR NADA HASTA QUE EL JUZGADO TOME LA DECISIÓN OPORTUNA EN RELACIÓN AL QUEBRANTAMIENTO DE LA ORDEN DE ALEJAMIENTO, para no favorecer el mismo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se vuelve a llamar a José Florencio pero rechaza la llamada antes de descolgar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2017-01-16','LLAMAN DE LOS PISOS TUTELADOS DE CALZADILLA PARA INFORMAR EL INGRESO DE eMILIANA SÁNCHEZ EN EL HOSPITAL VIRGEN DEL PUERTO DE PLASENCIA POR OTRA CRISIS. HA NECESITADO DE ACOMPAÑANTE QUE DEBERÁ REGRESAR A LOS PISOS TUTELADOS EN TAXI POR LO QUE SE PASARÁ EL CARGO A LA COMISIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2017-01-17','Hablo con Elisa, trabajadora social del Comité Antisida de Cáceres (927226143) para preguntar si la orden de alejamiento con respecto a su madre sigue vigente. Me llama.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-01-17','-La Dra Puerto no ha concluido el informe médico , lo enviará en cuento lo tenga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-01-17','El Programa de Familia de la Mancomunidad Tajo-Salor,Gloria, nos indica que la sucursal de Liberbank en Navas del Madroño no permite sacar dinero a la tutelada si no va acompañada del tutor legal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2017-01-17','Llaman desde el Ayuntamiento de Pozuelo de Alarcón, Juana, para indicar que la Residencia donde se encuentra el tutelado ha cambiado de dueños, se le indica que el recibo de mes de enero ya ha sido pasado a los anteriores titulares, Alamo, indica enviará correo electrónico con el nº de cuenta de la nueva empresa, Linoex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2017-01-17','Se le indica a trabajadora social que envie correo electrónico con presupuesto semanal de Felisa para mandar orden al banco, ya que no hemos visto que tenga limitación de gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2017-01-17','Recibimos el 4/1/2017, emplazamiento para contestar a demanda presentada por D. José Luis Martínez Pardo, contra Ignorados y Desconocidos Herederos de Dª. Mencia Romero Ramos (madre), entre los que se encuentra Aquilino, del Juzgado de Primera Instancia nº 6 de Badajoz, PO 1122/2016. La demanda es porque la vivienda de la madre de Aquilino se encuentra encima de la de José Luis y hay filtraciones. Según la demanda han hecho requerimientos, no sabemos a quién. Para contestar a la demanda se necesita abogado y procurador. Solcitamos asistencia jurídica gratuita y suspensión del plazo para contestar a la demanda, hasta que le concedan o no abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2017-01-18','GESTION SOLICITUD INFORMACION ORDEN ALEJAMIENTO El 12/01/2017 nos pusimos en comunicación con el Juzgado de Logrosán intentando averiguar la vigencia de la orden de alejamiento que Javier tiene contra su madre. Logrosán nos remite a Cáceres. En dichos juzgados nos pasan con "ejecutorias". En un primer momento, y según el archivo informático, no aparece nada que demuestre que existe la orden de alejamiento. Se queda con "ejecutorias" para que busque en los archivos materiales. Se recibiría llamada el miércoles 18/01/2017 con el resultado de dicha búsqueda. El 17/01/2017. Se atiende llamada de "ejecutorias" de Cáceres. Un día antes de lo pactado. Según parece lo único que allí figura es una sentencia, por amenazas, que le condena a: medida de ingreso, medida de prisión y medida de localización permanente. Según parece no hay orden de alejamiento de Javier contra su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-01-12','Se recibe, a petición de CTAEx, fax con la petición de plaza en CRR por Emergencia Social para Saturnino y respuesta DENEGATORIA por parte de la Comisión de Valoración de Expedientes en base a dos criterios: NO ALCANZAR LA PUNTUACIÓN REQUERIDA y NO VOLUNTARIEDAD de SATURNINO para dicho ingreso. Dicha Comisión, en respuesta, propone CRPS para trabajar la voluntariedad y posteriormente solicitar el recurso (si se considera).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-01-18','Llamo a Pilar, T.Soc. ESM (927-213730). Comprobará si se ha solicitado CRPS como la propia Comisión de Valoración plantea en su respuesta. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++RESPUESTA DE PILAR (fax):no se considera procedente la derivación a CRPS por estimar que se trata de un paciente crónico de larga duración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2017-01-18','Se envía por correo electrónico sentencia de incapacitación y nombramiento de la Comisión como tutor al departamento de pensiones, así como la dirección de la residencia donde se encuentra Rosa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2017-01-18','Conversación con Mª José Marquez Andrade (ASINDI:927-390974).Victoria sigue en UHB del Hospital Virgen de la Montaña y permanecerá en ella hasta que se resuelva la solicitud para ingreso en UDAc. No obstante, el Psiquiatra de la UHB cree que es más un caso para UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-01-18','TRASLADO de Jesús desde el C. Penitenciario de Badajoz al Psiquiátrico Penitenciario de Sevilla. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++PROCEDIMIENTO ABIERTO EN EL jUZGADO DE 1ª INSTANCIA E INSTRUCCIÓN DE SEVILLA con Juicio programado para el 23 de enero de 2017: se han SOBRESEIDO las actuaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2017-01-18','Citan a Antonio el día 30/1/2017, a las 10:00 horas, en la sede del Juzgado de Primera Instancia e Instrucción nº 2, de Mérida (auxilio judicial 4/2017, Juicio Delitos Leves 178/2016, Juzgado de Instrucción nº 4, de Badajoz), para reconocimiento forense. Le acompaña alguien del centro. Nosotros no tenemos que acudir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2017-01-19','Conversación con Javier (673-624350): ya se ha comprado las gafas (180€) y se las enviarán por correo. +++Pregunta por la supuesta orden de alejamineto de la madre: se le indica que estamos pensientes de recibir por escrito la información del Juzgado de Logrosán, pero que al parecer, en el momento de la consulta , no había indicios de que existiese en vigor ninguna orden. Le ruego que nos de tiempo para confirmarlo una vez lo tengamos por escrito. +++Respecto al comprobante de las gafas dice que esperará a tener más para enviarlos: le doy la opcxión de enviarlo del el SSB de Cañamero.','2');
