insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2017-01-17','Correo-e (17-01-2017):os escribo por comentaros acerca de la situación de Juan José Bergantiño y Vicente Rojo, ambos tutelados vuestros y usuarios de piso. Realmente no cumplen horarios, continuamente incumplen tareas que se le indican así como no acuden a actividades programadas en CRR y relacionadas con su PIR, a parte de esto tenemos serias dudas acerca de conductas de consumo. Son continuas las faltas de respecto y el pasotismo hacia monitores y compañeros. Todo esto nos ha hecho valorar la necesidad de establecer contratos conductuales con ambos, en estos se establece que en caso de incumplimiento de los mínimos exigidos tendrán salidas terapéuticas del dispositivo. Os lo comento porque entiendo que debéis estar informados de esto y porque no sé si estimáis la posibilidad de darles un toque a ambos. Respecto a esta situación nos preocupa el resto de compañeros y la repercusión de las conductas de ambos en ellos.','2');
