insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-09-15','SALIDA Entre el 15/09/2016 y el 21/09/2016. Viaje a Tenerife organizado desde el centro. El viaje lo realiza en autobús y avión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-01-05','SALIDA El 05/01/2016. MAP. Acude para pedir un receta, incluir la medicación en la tarjeta, recoger resultados de la citología y pedir cita con la ginecóloga.****************** Le dan receta que debe en la farmacia pero decide no incluirle la medicación en la tarjeta porque ahora es difícil calcular para cuando necesitaría otra caja y cuando le falten tres días para terminar con la caja que pidamos cita para meterla en la tarjeta.******************* Los resultados de la citología son normales. No la derivan al ginecólogo porque la última vez no se dejó explorar y se refleja en el informe que le quitaron los anticonceptivos porque manchaba en mitad del ciclo. Le mandaron a que apuntara las reglas pero no volvió a ir.**** Nos da cita para planificación familiar el martes 12 a las 12, dice que la atenderá unamujer y así estará más cómoda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-01-12','SALIDA El 12/01/2016. PLANIF. FAM. La doctora mira su informe y le insiste en que sólo se puede poner anticonceptivo inyectable porque tiene 32 años y fuma más de 20 cigarrillos al día y está contraindicado. El inyectable es cada tres meses y la primera vez que se pinche debe ser el primer día de regla. Le da el volante para que lo lleve cada vez que tenga que pincharse. La pinchará el enfermero de planificación familiar. Durante el primer mes debe usar preservativo cuando tenga relaciones. También le da por escrito cómo pueden ser sus reglas, ya que puede que no le venga algún mes o puede que manche poco durante mucho tiempo y de forma constante. Le aconseja dejar de fumar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-01-13','SALIDA El 13/01/2016. ANTICONCEP. Se pincha el primer inyectable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-01-26','SALIDA El 26/01/2016. MAP. Actualiza la tarjeta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-02-22','SALIDA El 22/02/2016. URG. Eva va a urgencias, dice que tiene gingivitis. Se ha comprado un enjuague que no entraba por la seguridad social, se lo tiene que enjuagar dos veces o tres al día. Y le ha dicho que se cepille bien los dientes, de arriba a abajo. Que si le doliera mucho se tome un analgésico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-02-29','SALIDA El 29/02/2016. PSIQ. Le han subido la dosis a 100 mg., empeza mañana. Si la notamos rara tenemos que ir a comentárselo al psiquiatra sin cita. Le ha dicho que tiene que centrarse y las medidas que hemos puesto con el móvil y con las salidas le vienen muy bien. Tenemos que seguir controlando y apuntando la tensión. Próxima cita: 21/06/2016, a las 10.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-03-18','SALIDA El 18/03/2016. PADDI. Se le mueve un diente, pero no es preocupante. Debe lavarse bien los dientes y cuando le sangren las encías utilizar un enjuague Clorhexidina laxer (colutorio). Comenta que tiene tanta separación entre los dientes porque está perdiendo hueso debido a su enfermedad periodontal. No le recomienda ponerse aparato.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-04-13','SALIDA El 13/04/2016. INYECTABLE. Le inyecta el anticonceptivo Depo-progevera 150 mg. Próximo dentro de tres meses: a principios de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-05-25','SALIDA El 25/05/2016. PODÓLOGA. Le lima durezas de los dedos y de los talones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-06-21','SALIDA El 21/06/2016. PSIQ. La ve más centrada y nos comenta que las cosas con las que se ilusiona son propias de su personalidad. Le mantiene la medicación. Próxima cita: 11 de octubre, a las 13.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-07-01','SALIDA El 01/07/2016. MAP Y DENTISTA. Se ha hecho un pequeño corte en la mano trabajando. Le ponen la vacuna del tétano, tiene que ponerse otra dosis al mes y otra al año en su enfermero en el centro de salud.********************* Al dentista va porque le duelen las encías, le dice que está perdiendo hueso de la encía y por eso se le mueven los dientes y hasta se le podrían caer. Tiene que verla un especialista y nos da cita para el 29 de septiembre, a las 9.30 Hs. Tiene que usar un enjuague 3 veces al día (le da muestras).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-07-13','SALIDA El 13/07/2016. MAP.Tiene un pequeño bulto en la mano derecha y unos callos muy grandes en los dedos de los pies. El médico dice que tiene una verruga en lamano y debe echarse un producto durante 4 semanas, si no se le quita ir al médico para que la mande al dermatólogo. Para estar en la cocina debe tapárselo con un apósito y ponerse un guante. Para el pie le aconseja que vaya al podólogo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-07-15','SALIDA El 15/07/2016. INYECTABLE. Se picha el anticonceptivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-09-12','SALIDA El 12/09/2016. MAP. Diarrea desde el sábado y le dicen que tiene gastroenteritis. Le manda suero durante 3 días y debe beberlo poco a poco a sorbitos. Hoy debe comer poco e ir aumentando la omida conforme se encuentre mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-08-09','SALIDA El 09/08/2016. ATS. Acude para ponerse la segunda dosis de la inyección del tétano y la ats dic que no hace falta porque ya con la que se puso está inmunizada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-10-11','SALIDA El 11/10/2016. PSIQ. La ve mejor, le ha contado como van ahora sus relaciones sentimentales y le ha dicho que le parece bien, pero que se lo tome con calma y vaya despacio. Tenemos que ayudarla y apoyarla para que siga así y reconducirla para que tome las decisiones correctas, le ha dicho que se haga caso. Ella le ha dicho que no quiere volver a como estaba antes. Sigue con la misma medicación. Vuelve el 23/04/2016, a las 13.10 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-11-08','SALIDA El 08/11/2016. Le han dicho en el dentista que tiene periodontitis, piorrea (creo que esto también se lo dijeron en el PADDI y no sé si le hicieron algo) y con esta enfermedad no se puede poner aparatos ni nada para corregirle los dientes. Le han hecho una radiografía porque le comente que se le movían los dientes y ahí es dónde vio que tenía el nervio afectado y en uno de los dientes centrales, que es el que más se le mueve, le dijo que se le va a caer tarde o temprano. También, me comentó el dentista, que esto de la periodontitis se lo detectaron en 2014, pero como no se trató ahora están los dientes mucho más afectados. De momento le mandan un tratamiento para la infección porque Eva ha comentado que a veces le duelen los dientes. Tomará: amoxicilina 750 mg., que se tomará cada 8 horas, y un colutorio, perio.aid, cada 12 horas. Le verá un periodontólogo este jueves. Tiene cita a las 19.30 Hs. para ver en que estado tiene la periodontitis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-11-10','SALIDA El 10/11/2016. DENTISTA. De momento me dijo el dentista de no quitar ninguna pieza porque primero hay que curar esa zona y luego ya, según vea el proceso tomaría medidas. Serían sesiones cada 6 meses y luego un mantenimiento, está todo incluido en ese presupuesto. Le dijo que fumar para esa enfermedad es una de las cosas peores y más durante el tratamiento. Se habla con ella y a ver si se consigue reducir los cigarros.***************************** Nos entrega presupuesto (guardado en pdf y en piso).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-11-17','SALIDA El 17/11/2016. MAP. Llevamos los resultados de la analítica del reconocimiento del trabajo porque le han salido algunas alteraciones (colesterol, perdida auditiva...).************ La doctora le dice que el tabaco está afectando a su función respiratoria. Debe proponerse dejar de fumar. Tiene colesterol y debe seguir una dieta baja en colesterol, aunque no es muy importante porque sólo está un poco elevado. La doctora cree que es un factor hereditario porque es muy joven para tenerlo. Tiene que comer sano y hace ejercicio. La pérdida auditiva no es importante. Debe usar las gafas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-08-08','SALIDA Entre el 08/08/2016 y el 14/08/2016. Viajó a Chipiona, con motivo de una excursión. El viaje lo realizó en autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-09-15','SALIDA Entre el 15/09/2016 y el 21/09/2016. Viajó a Tenerife, con motivo de una excursión organizada por el centro. El viaje lo realizó en autobús y avión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-07-25','SALIDA El 25/07/2016. XEPLIÓN. Tensión: 106-78. Frecuencia cardíaca: 66. Peso: 101.30 Kg. Ha engordado, dice la enfermera que hay que controlarle la alimentación o habrá que ponerla a dieta. El xeplión se lo pone cada 5 semanas, pero si la últimas semanas la notamos cambiada, se le puede poner cada 4. La próxima cita es el 29 de agosto, que se lo tiene que pinchar su enfermera del médico de cabecera y el 4 de octubre con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-07-26','SALIDA El 26/07/2016. ALERGÓLOGO. Le hacen la prueba y da positivo al olivo y un tipo de gramínea. Debe seguir con la misma medicación que toma hasta ahora. Revision en un año y mandarán la cita por correo. Nos entregan informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-08-23','SALIDA El 23/08/2016. PSIQUIATRA. Ha puesto un kilo. Le pone adofen por las mañanas, dice que le quitará el apetito. Las tres primeras semanas debe tomar media por las mañanas y luego ya entera. Próxima cita el 16 de febrero de 2017 a las 11.50 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-10-04','SALIDA El 04/10/2016. XEPLIÓN. Peso: 102.60 Kg. Tensión: 11.3/7.6. Próxima cita: 02/11/2016, a las 9.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-11-02','SALIDA El 02/11/2016. XEPLIÓN. Peso 102.60 Kg. Tensión: 117/77. Próxima cita el 30/11/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-11-08','SALIDA El 08/11/2016. ENDOCRINO TELEMEDICINA. Peso: 102.50 Kg. Ha puesto 4 Kgs. desde la última consulta. Tensión 100/82. En la analítica los valores son normales. Tiene que hacer ejercicio para bajar de peso, sigue con el mismo tratamiento. Nos mandarán la próxima cita al piso para dentro de un año. La regla se le irá pronto y debemos quitar el sogilem. Antes de la próxima consulta debe hacer analítica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-11-02','SALIDA El 02/11/2016. XEPLIÓN. Peso: 102.50 Kg. Tensión: 102/86. Frecuencia: 61 pm. Próxima cita: 30/12/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-12-26','SALIDA El 26/12/2016. URG. Le duele el tobillo izquierdo y dice que se ha caído hace unos días. Le vendan el tobillo y le dicen que lo tenga así dos o tres días. Dicen que puede ser un esguince. Si le duele puede tomar paracetamol y reposo y que en 3 o 4 días vaya a su médico y si es necesario que le hagan una placa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-12-27','SALIDA El 27/12/2016. MAP. Actualiza el topiramato y le ven el tobillo. Como no está su médico le dicen que vuelva a primeros de año porque no hay rayos hasta entonces. Paracetamol y reposo hasta entonces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-12-30','SALIDA El 30/12/2016. XEPLIÓN. Tensión: 135/82. Peso: 105 Kg. Frecuencia: 91. Ha puesto tres kilos. En la próxima cita le llevaremos en menú para que nos de indicaciones para bajar de peso. Próxima visita el 27/01/2017, a las 9.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-10-28','SALIDA Entre el 28/10/2016 y el 02/11/2016. Visita a su hermana en Badajoz. El medio de transporte que utiliza es el autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-12-23','SALIDA Entre el 23/12/2016 y el 09/01/2017. Visita a su hermana en Badajoz para disfrutar del período de vacaciones de navidad. El medio de transporte que utiliza es el tren.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-10-05','SALIDA El 05/10/2016. DIGESTIVO. Acude para consultar si tiene que seguir tomando la medicación, ya que la última consulta fue en 2013 y desde entonces está con ella. Le dice que se encuentra bien. Tiene que seguir tomando la misma medicación. Su estómago y sus músculos se mueven mal y la medicación ayuda para que las digestiones sean mejores. Comenta que si se le retira la medicación puede empezar a encontrarse peor, e decir, está bien por lo que toma. Tendrá que tomarla de por vida. No es necesario realizar revisiones, a menos que se encuentre peor o tenga molestias. Nos entrega el último informe de 2013 y el de hoy. Medicación que se refleja en el informe: omeoprazol, cidine 1-1-1 y almax a demanda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-10-20','SALIDA El 20/10/2016. ATS. Se realiza analítica de orina y sangre. Recoge resultados el 26/10/2016 a las 9.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-10-26','SALIDA El 26/10/2016. MAP. Los resultados de la analítica son normales pero el PCK (creatinquinasa) la tiene alto y es el responsable de las fibras musculares, han pasado de 800 a 1121. Debe dejar de hacer algo de ejercicio. El fútbol sala es muy intenso. No le receta los batidos de proteínas porque no es necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-11-24','SALIDA El 24/11/2016. ENFERMERO. Se pone la vacuna de la gripe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='ROMERO'and apellido2='VERA'),'2016-12-14','SALIDA Entre el 23/12/2016 y el 03/01/2017. A su casa con motivo de las fiestas navideñas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ROMERO'and apellido2='VERA'),'2016-12-14','SALIDA Entre el 23/12/2016 y el 03/01/2017. A su casa con motivo de las fiestas navideñas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2016-05-18','SALIDA Entre el 30/06/2016 y el 05/07/2016. Viaje a Lourdes, organizado por la Hospitalidad Ntra. Sra. de Lourdes. Se trata de una peregrinación Diocesana. Asistirán varios residentes.************************************************ La vacaciones implican una salida socio cultural que favorece sus relaciones con el entorno social y previene los efectos rutinarios que pudiera tener una vida institucionalizada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2016-05-26','SALIDA Entre el 05/09/2016 y el 12/09/2016. Viaje a Ceuta, organizado por PREDIF, subvencionado por el IMSERSO. Asistirán varios residentes. ****************************** La residente noha viajado, ni viajará, en otros viajes subvencionados por el IMSERSO durante el periodo comprendido entre el 01/06/2016 y el 31/05/2017, tal y como establece el programa de vacaciones.****************** Las vacaciones implican una salid socio cultural que favorece sus relaciones con el entorno social y previene los efectos rutinarios que pudiera tener una vida institucionalizada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2017-02-01','llamada desd Paqui, T. Soc. de SS Penitenciarios de Badajoz. José Florencio está citado el próximo día 15 de febrero a las 11:30h. Dado que es una curatela económica no es precisa la asistencia de CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-02-01','Conversación con Cati (Apba. 3) y respuesta por correo-e: Hola de nuevo, Cati. En relación a la petición que el abogado de la abuela (que no aparece en el escrito que adjuntas, por cierto) de Daniel hace a esta Comisión para solcitar de su ex-marido una pensión, según refieres, cabe decir lo siguiente: Sobre el certificado de Minusvalía de Daniel: se trata de un documento que solamente el tutor, en este caso la Comisión Tutelar, tiene competencia para disponer de él y solamente para aquellos acciones que vayan en beneficio del tutelado. Sobre el documento que acredite que (Daniel) lo tiene ella (la abuela) asignado los fines de semana:lo que parece solicitar es un certificado de convivencia, documento que solo puede ser expedido por el Ayuntamiento correspondiente. Por otra parte, no es cierto que exista ninguna asignación de nuestro tutelado a la abuela para pasar los fines de semana, sino que se trata de visitas que la propia abuela, salvo durante un cierto periodo de tiempo en el que refirió haber estado enferma, siempre ha solicitado y estado dispuesta a llevar a cabo y que a Daniel le son beneficiosas. Por las razones, esta Comisión no va a proporcionar los documentos solicitados. Por otra parte, si las visitas de Daniel ocasionan algún gasto a la abuela y ella así lo solicita (pero sin planteárselo previamente desde el centro), se podría estudiar la cantidad a facilitar para llevar a cabo dichas visitas.','2');
