insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2017-02-03','Conversación con Aida (671-507221) +++El inquilino que tenía se ha marchado ya de su piso y tiene planes de ocuparlo ella. Se le pide que nos diga cuándo se va a marchar para ajustar su presupuesto. +++Quiere seguir pagando a Leandro, con quien ha convivido hasta ahora, su parte del alquiler para que este no pierda su capacidad económica justificándolo con la necesidad que ella demanda de supervisión (Plantea un calendario de actividad en el correo-e de 10 de enero de 2017): se le informa de que si se marcha a su piso no existe justificación para dicho pago, por lo que si quiere ayudar a su amigo debería salir de la signación que tiene mensulamente. +++Regularemos la domiciliación de los gastos del piso que hasta ahora, según comenta, estaban a nombre del inquilino. +++Quiere hablar de todo ello con su hermana Sonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-02-03','Conversación con José Tello. Enviará oferta para la compra del olivar de Dª Sofía. Una vez nos llegue, pedir autorización judicial para la venta. RAZONES: Terreno que no se atiende, donde se produjo un incendio que pudo afectar va las fincas colindantes y que en estos momentos se encuentra en una situación de abandono que puede llevar de nuevo a los riesgos antes indicados.','2');
