insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2017-02-03','Se llama a Orange para la restricción de las llamadas a números 900, tanto en el fijo como en el móvil, 657 83 30 08. Lo gestionan en el momento. Nos piden una clave para cualquier trámite que se realice. La clave es "comisión". Para cualquier trámite nos tiene que pedir esta clave.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GORDILLO'and apellido2='PINTO'),'2017-02-06','Conversación con Blanca (CSS Mérida: 924-388081). Se están planteando la derivación de D. Antonio a una residencia de Mayores. Enviarán la solcitud para su firmna por la CTAEx. +++En cuanto al contacto con la familia para informarles, solamente contamos con un número de teléfono (Teléfono hermano 936583294) al que ya han llamado y que al parecer no es el actual. No tenemos más información acerca de la familia.','2');
