insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-02-06','Conversación con Elena: la evolución de MargariTA sigue siendo buena y sin nada que destacar. +++CONVERSACIÓN CON MARGARITA: como he estado alguna semana sin llamarla, preguntaba si le habían cambiado de tutores. Sigue muy contenta, destacando entre sus actividades la realización de puzzles. Hoy va a ir a jugar a golf y también monta a caballo. Seguiré llamando con cierta frecuencia.','2');
