insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2017-02-06','Hablamos con Engracia, la inspectora de Seguros SAnta Lucía, t/c 680.463.311, para que vuelva a pasar los recibos devueltos desde el mes de noviembre 2016, nos indica que así lo gestionan. TAmbién hablamos con Caja Badajoz, para que no se pueda realizar ninguna operación sin la autorización de la Comisión. Pilar,t/c 647.407.464, la ayuda a domicilio, ha sido quién ha devuelto los recibos, hablamos con ella, y se le indica que no debe proceder de esa manera sin autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-02-06','Conversación con Clemen (Directora CAMP). Hermenegildo está mejor, ya no necesita silla de ruedas pero sigue bastante débil: le bajaron la dosis de medicación que le pusieron en el HospitalComenta que se escapó durante un día una vez que se encontró mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2017-02-06','Visita de María Dolores a la CTAEx. Quiere más dinero y que le vuelvan a dejar salir a su casa como se quedó en la reunión anterior. Hablo con Raquel (CRR):No ha cumplido con el comportamiento que se estableció en la reunión mantenida con ella, Gisela y Niria (su tutora en el CRR)y, dado que se marchó del Centro sin permiso, ahora tiene que pagar los dos viajes en taxi, por lo que durante febrero y marzo solo podrá percibir 4€/día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2017-02-06','Conversación con Cristina, E. Social de la Residencia "El Pendere" (927-592135 y FAX 927-592370): Don Arturo está bastante bien integrado en el centro, si bien de vez en cuando menciona que, aunque se encuentra bien, se quiere ir a su casa (cree que puede tener cierto principio de deterioro cognitivo). Se relaciona bien tanto con los demás residentes como con los profesionales del centro. +++Recibió la visita de Dª Granada y D. Miguel Ángel la semana pasada y lo llaman por teléfono más o menos una vez a la semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2017-02-06','Nos llama Manuel Garrancho Casas (617050792), abogado, diciéndonos que ha sido designado para representar a Aquilino en el procedimiento 1122/2016. El Colegio aún no nos ha designado. Por otra parte, el Juzgado de 1ª Inst. nº 6, de Badajoz, va a dictar resolución concediéndonos la suspensión del plazo concedido para contestar a la demanda, hasta que se designe, oficialmente, abogado de oficio. Una vez que recibamos designación oficial, ponernos en contacto con abogado para enviarle documentación y que conteste a la demanda.','2');
