insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GRANADO'and apellido2='CARDITO'),'2017-02-07','-NOS HA LLEGADO UN DOCUMENTO DE LA PENSION DE FRANCIA , ES UN CUESTIONARIO EN EL QUE PREGUNTAN POR LOS HEREDEROS . ANTONIO YA HA FALLECIDO Y NO DISPONEMOS DE ESA INFORMACIÓN . SE ARCHIVA LA PETICIÓN EN SU EXPEDIENTE SIN RESPONDER.','2');
