insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-02-03','Se recibe en la Comisión Resolución en la que NO SE APRUEBA el PIA de D. Juan al haber tenido entrada en el SEPAD, escrito del interesado manifestando expresamente su rechazo al mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2017-02-07','Jesús, de 46 años, nos envía un escrito, solicitándonos que reclamemos judicialmente al padre para que vuelva a pagarle 400 euros, que, tras el procedimiento de modificación de medidas, tras la separación de sus padres, el padre reclamó judicialmente y estimaron parcialmente. Anteriormente a ese procedimiento, el padre le pasaba 700 euros. Hablo con la psicóloga del CRR de Cáceres, me dice que Teo, que es el trabajador social de Jesús está de permiso, vuelve en marzo 927232106 Jesús cobra dos pensiones, una de orfandad y otra por hijo a cargo, cobrando en total 657,16 euros de pensión. Si además recibe los 300 euros de diferencia del padre, cobraría en total 957,16 euros. Llama la atención, que entre sus gastos, se encuentren 40 euros mensuales, que le paga a una señora para apoyo en la limpieza/planchado y orden de la casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-02-07','CORREO-e de José Mª Tovar:+++El pasado sábado día 4 llevamos a Urgencias del H.S.P.A a Tomás Esteban Iglesias con parálisis de cintura hacia abajo. El miércoles comenzó a encontrarse débil de la pierna izquierda, el jueves amaneció con dicha pierna totalmente dormida, llevándole esa misma mañana a su médico de cabecera quién suspendió los medicamentos que hasta entonces venía tomando, bajando en algunos las dosis y quedado pendiente de una nueva revisión pasada una semana, pero el viernes a penas pasadas 18h esa debilidad le fue pasando a la pierna derecha, amaneciendo el sábado sin sensibilidad en ninguna de sus extremidades inferiores, habiéndose orinado sin él darse cuenta, motivos por los cuales le llevamos directamente a urgencias. El sábado le han hecho Análisis de sangre, TAC y resonancia. Descartando problemas en los dos primeros, observaron anomalías en la resonancia por lo cuál decidieron hacerle un pinzamiento y analizar problemas bacterianos, víricos o tumores. Los bacterianos, ya han quedado descartados y estamos pendiente a lo largo de la semana de los otros resultados . Tomás continua hospitalizado y se encuentra actualmente en la habitación 517 del Hospital San Pedro de Alcántara, esperando que le puedan ubicar en la planta correspondiente. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON José María: Tomás está pendiente de recibir, seguramente este viernes, los resultados de las pruebas que se han enviado a Barcelona, para descartar posibles causas de la situación sobrevenida, entre otras, una posible enfermedad autoinmune, algo que al parecer no es frecuente que se produzca en personas tan jóvenes como Tomás. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Tras la conversación, nos llega por correo ordinario Informe Clínico del Dr. Blanco González, Especialista en Psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-02-07','El Juzgado de Primera Instancia e Instrucción nº 2, de Trujillo, dicta Auto nº 130/2016, de fecha 23 de noviembre de 2016, autorizando a María Isabel para que pueda darle a su hermana 900 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-02-07','Conversación con Eva, Educadora en Piso Supervisado de Cáritas en Mérida, tel. 924-260175 (Cristina,la Coordinadora, está enferma).José Mª se ha marchado del piso y no ha aceptado ninguna de las propuestas que desde el mismo se le han hecho ("Padre Cristobal", CEDEX, ESM). +++Le pido que nos remitan un informe para comunicar al Juzgado dicha circunstancia. +++Proponemos hablar con José Mª personalmente, para lo cual quedamos mañana, 8 de febrero, para mantener una reunión con él y con Eva en la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2017-02-07','A raíz de la carta manuscrita dirigida a esta Comisión por Dª Mª José Álvarez, madre de Álvaro, intento contactar con ella para proponerle tener una reunión en la sede de la Comisión. salta información de telefónica indicando que en estos momentos (14:00h) el número marcado no está disponible.VOLVER A INTENTARLO.','2');
