insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-02-13','SE recibe fax del CAMP: +++10 de febrero: la mejoría experimentada por Hermenegildo ha dado lugar a una nueva escapada, apareciendo en Cabeza del Buey a las 12 de la noche. Avisó al Centro Marta, su hermana, el sábado 11 por la mañana, regresando ese mismo día a las 18:00en taxi. +++Marta solicita a la CTAEx permiso para que Hermenegildo pase el periodo de carnavales en el domicilio familiar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON Cristina, T. Soc. CAMP (924-021574): respecto a la salida durante carnavales, la opinión de la Comisión es que, dadas las características de este periodo de tiempo, el deterioro físico que ha sufrido Hermenegildo últimamente y del que se está recuperando, NO ES el momento más adecuado para autorizar una salida a casa duramnte los carnavales. SE VA A REUNIR EL EQUIPO DEL CAMP y plantearán esta situación. Una vez de acuerdo, comunicar al Juzgado la misma.','2');
