insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2017-02-14','-ANTONIO PERCIBIA PNC.A FINALES DE DICIEMBRE DEL 2016 SE SOLICITA PFHC+P.ORFANDAD. LA P.ORFAND VIENE APROBADA CON EFECTOS EC. DE 194.80 DESDE EL 29/09/16 . LE DAN UNOS ATRASOS DE LOS TRES MESES EN LOS QUE SE RETROTRAE ESTA SOLICITUD POR LA FECHA DE FALLECIMIENTO DEL PADRE QUE ASCIENDEN A 887.80. COMO HASTA DICIEMBRE 2016 ERA PERCEPTOR DE PNC , HABRÁ UN COBRO INDEBIDO POR INCOMPATIBILIDAD DE AMBAS PENSIONES QUE RECLARMARÁ PNC , SE REDUCIRÁ LA CUANTIA DURANTE ESOS 3 MESES. LA PFHC ESTÁ APROBADA CON EFECTOS 1//1/2017 ASCIENDE A 368.90. YA SE MANDÓ LA OPCION DE ELECCCION POR PF Y SE LO VAN A COMUNICAR A PNC .','2');
