insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2017-02-15','+++Ventura solicita 300€ para marcharse a Coria el próximo fin de semana porque tiene allí -dice- un familiar enfermo. Se le explica que en estos momentos y hasta que el juez autorice el incremento de su disponibilidad mensual a 600€ no va a haber extras. Acepta esta situación. +++SE LE INFORMA DE LO SIGUIENTE: se va a DAR DE BAJA a todas las líneas de teléfono que tiene contratadas menos a una. Él reconoce tener dos, pero no dice quién las ha contratado. SE DARÁ DE BAJA A TODAS MENOS A LA DEL nº 622-356104, LIMITANDO EL SALDO ENTRE 50 Y 60€ al mes. ventura está de acuerdo en todo ello.','2');
