insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2017-02-17','Conversación con Paula, T. Ocup. CRR de Plasencia. +++Comprobar estado de cuentas, movimientos y si existe o no limitación, dado que en los últimos meses ha sacado todo lo que tenía (ludopatía) al parecer sin autorización alguna. CASO DE NO ESTAR LIMITADA LA CUENTA LIMITARLA A 300€/MES, límite impuesto por la sentencia de curatela: superando dicha cantidad hemos de ejercer la misma. +++HERENCIA: según Paula, todos los años Eugenia paga a una de sus hermanas la parte correspondiente de los impuestos que unas propiedades que tienen en Salamanca le suponen. Es poco dinero pero pero los años 2016 y 2017 ya están pagados (aunque la hermana, ENEDRINA, le reclamó el 2016 que ha pagado ahora con el del presente año.). HABLAR CON Dª ENEDRINA (el contacto está en el último informe enviado a la CTex desde el CRR para la rendición anual) y VER LA POSIBILIDAD DE PAGARLO POR TRANSFERENCIA TODOS LOS AÑOS (para garantizar que no vuelve a suceder lo mismo).','2');
