insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2017-02-17','Conversación con Paula, T. Ocupacional del CRR de Plasencia (927-423978 y 682-704401). +++Comprobar estado de cuentas y valorar mantenerlas con la de la hija: en el CRR consideran que no hay problema en que las cuentas estén juntas, ya que ello le da una mayor sensación de seguridad y de estar haciendo algo por su madre a Flora, su hija , curatelada en este caso también por la CTAEx). +++Piso en propiedad en Badajoz: pedir nota simple al registro de la propiedad y valorar posibilidad de venta según titular. NO ES PREVISIBLE que ninguna de las dos mejore tanto en su situación como para llevar a cabo su desinstitucionalización, por lo que una vez comprobada la situación de dicha vivienda valoraremos solicitar autorización judicial de venta.','2');
