insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILIA'and edp.apellido1='IÑIGO'and apellido2='SANCHEZ'),'2017-02-20','FALLECIDO El 18/08/2016. La primera noticia de la muerte de D. Basilia nos llega junto con el informe social que nos remite la R. G. Virgen de la Montaña II, en fecha 20/02/2017. Hubo, además, un traslado desde el centro anterior a la Asistida de Cáceres. Ésta última, es la que nos ha proporcionado la fecha de fallecimiento tras conversación telefónica mantenida con ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2017-02-20','Prisión de Badajoz. COMUNICACIONES:924-289116 (horario de 09-13:00h). VISITAS: hasta cuatro personas, dando nombre y DNI de cada una de ellas. INGRESO EN CENTRO PENITENCIARIO: 13 DE ENERO. DURACIÓN MEDIDA:5 MESES. MÓDULO:UTE (Unidad Terapéutica). T.SOCIAL de ref: BEATRIZ. +++Una vez establecida esta primera visita, se puede solicitar a través del operador automático en el 913-356099. +++TELÉFONO DE ANTONIO (hermano): 687-969982. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Beatriz, T. Soc. Centro Penitenciario de Badajoz (924-289117///Centralita:924-289100). +++Revisión Cadex-cáceres con cita el 28 de febrero: ¿cómo gestionar dicha revisión: desplazamiento, traslado de expediente, etc.? Consultará los trámites a seguir y se pondrá en contacto con Carmen, T. Soc. Cadex Cáceres (927-005510). Se propone hacer todo lo posible por que dicha revisión se realice durante los meses que Jonathan esté en prisión, dado que después es muy posible que no se le pueda localizar. +++Contacto con Carmen (Cadex) y le doy los teléfonos de Beatriz para que se pongan en contacto. Le hago la misma sugerencia sobre el momento de llevar a cabo dicha revisión.','2');
