insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-02-21','Conversación con Rosa Mª Alonso (68831), Jefa de Sección de Admón. General. Servicio de Infancia y Familia. Propuesta desde la CTAEx: +++mantenimiento de Joaquín en el piso que Hofa tiene en Montijo (Calle Macías de Porras, 23, 06480 Montijo Teléfono: 924 45 48 45) hasta cumplir los 21 años. +++solicitar PNC +++solictar plaza en C. Ocupacional de Montijo. Rosa comenta que el mantenimiento en la vivienda hasta los 21 años no sabe si es posible, ya que la mimsa no se trata de un piso semiautónomo, sino que está bajo la tutela directa de Menores, tutela que finaliza con el cumplimineto de la mayoría de edad. LO CONSULTARÁ Y NOS LLAMARÁ.','2');
