insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2017-02-25','- Se mantiene contacto tf. con Angel equipo valoracion (924015558-689575715-689575712)para negociar PIA . Se decide optar por SAD Dependencia pero por convenio con el Ayto. que es gratuito pq por prestacion vinculada tendria que hacer un copago de unos 70€ . Su mujer , Isabel Molina Cano ( 01805689M) tiene G2 y recibi SAB conveniado con Ayto . Montijo a 0€ de coste . Quedo pte. que me envie la aceptacion PIA desde la Gerencia Bjoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2017-02-22','Reunión mantenida con Dª Mª Jose y Dª María, madre y abuela materna(645-032615) respectivamente de Álvaro. +++Se trata de explicar a ambas cuál es la situación legal de Álvaro respecto a la tutela, ya que su madre sigue considerando que es su principal responsable. En esta aspecto la abuela entiende mejor las explicaciones que su hija... +++Se plantea la situación producida tras el incidente de diciembre pasado cuando Mª José no volvió a llevar a su hijo a Novaforma, pero sigue manteniendo que su actuación fue correcta, a pesar incluso de que su madre, refiere, ya le advirtió en su momento de que debería haberlo llevado cuando le correspondía. +++Protesta porque, según comenta, ella carece de ningún tipo de recurso económico al haber abierto una cuenta a Álvaro en la que ella no figura, y que es su madre la que la está ayudando en esta situación. También se le explica que la responsabilidad de la Comisión es con su hijo y que ella deberá buscar ayuda para cubrir esa carencia. +++Ante su constante rechazo a la pérdida de la tutela de su hijo, comprensible como madre, se le informa de que de todas las quejas discutidas durante la reunión está en su derecho de dirigirse al Juzgado para plantearlas (también las de carácter económico que ella manifiesta), incluso la posibilidad de promover la remoción de la tutela que ella, en varias ocasiones, manifiesta debe ser la Comisión la que lo promueva en beneficio de ella. Respecto a ello, se le informa que en las actuales circustancias la Comisión no va a plantear dicha remoción, pero que sí puede hacerlo ella o cualquier miembro de la familia que quiera proponerse como tutor (la abuela mostró interés en este aspecto), sabiendo que es al Juez, finalmente, quien decidirá si se remueve o no el cargo y en su caso a quién se le confía. +++RÉGIMEN DE VISITAS: de momento, y hasta que el Centro informe positivamente, las mismas consistirán en la reunión que todos los viernes, bajo supervisión, mantiene Álvaro con su madre y abuela en una cafetería próxima. Una vez propuesta por el Centro, se podrá volver a pasar los fines de semana con ellas y si esto evoluciona adecuadamente se planteará la posibilidad de estancias más prolongadas. +++Finalmente, y al igual que al comienzo de la reunión, se le plantea a Mª José la posibilidad de mantener una reunión conjunta con la dirección de Novaforma, negándose en ambas ocasiones a ello (aunque la abuela sí manifestó que podía ser una buena ocasión para ello).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-02-22','Reunión con Mª JOsé Y José María en su casa. +++Tomás sigue ingresado en el Hospital San Pedro de Alcántara Ronda de San Francisco, 19, 10002 Cáceres//Telf: 927 62 14 62 +++Paraplejia de cintura para abajo por una infección bacteriana que ha afectado a la medula (se está pendiente de recibir los informes médicos al respecto). +++Pronóstico: se va a derivar a Tomás al Hospital de Parapléjigos de Toledo para su tratamiento.','2');
