insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-03-02','Conversación con Rosa. Me pone en contacto con Susana Guerrero, Jefa de Sección de APOYO Y RECURSOS a la Infancia y la Familia (68855). Hablo también con Begoña, T. Soc. del Servicio (68856). Información: +++PISO TUTELADO: solamente hasta los 18 años.En estos momentos, además, hay menores esperando acceder a este tipo de plaza. +++PISO SEMIAUTÓNOMO: no tiene perfil para el nivel de autonomía que se exige en este tipo de recurso.Todas las profesionales consultadas coinciden en que en el caso de Joaquín este recurso sería completamente inapropiado para él. +++ALTERNATIVA: para facilitar la transición, promover inicialmente el contacto con el piso en el que ha estado mediante visitas puntuales al mismo.En cualquier caso, NO ES POSIBLE SU MANTENIMINETO EN EL RECURSO ACTUAL. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Sección de Dependencia: +++PERFIL: de RAL y de VIVIENDA TUTELADA. +++EN MONTIJO: 54 puntos para Vivienda Tutelada. Posición 3º. Tiempo de espera: imposible de determinar.En esta localidad no hay plazas de RAL. +++EN PLASENCIA: 1ª POSICIÓNE en V. Tutelada. +++EN MIAJADAS:1ª POSICIÓN en V. Tutelada.','2');
