insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-03-03','Teléfono de D. Atilano:696985926. No tiene inconveniente en que se prorrogue el alquiler durante un mes más mientras vemos alternativas para mantenerlo o no. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Sara, hija de Isabel, confirma que entre su abuela y su padre van a ingresar todos los meses 100€ en la cuenta de Isabel, con la finalidad de que lo destine a alimentación. +++Por parte de la Comisión, se pedirá a Isabel que todos los gastos en alimanetación sean justificados con los correspondientes recibos de compra. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se comunica a Asunción Cabrera todo ello, para que lo tenga en cuenta de cara a la entrevista programada con Isabel el próximo 23 de marzo.','2');
