insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2017-03-03','Reunión en CRR de Mérida con Javier y Gisela. +++NO creen oportuno pedir una permuta de Centro, ni siquiera temporal, porque consideran que puede ser incluso perjudicial para ella. +++Van a intentar que haga salidas progresivas desde la UME al CRR previas al alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2017-03-03','Reunión en CRR de Mérida con Javier y Gisela. +++Tramitarán la pensión de orfandad de Concepción. +++No se le debe dar dinero para su familia, ya que ella lo da como una forma de ser aceptada por su familia. +++Sigue en la Asociación contra la ludopatía: desde marzo pasará a pagar 20€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2017-03-06','Solicito al SSB de Fuente del Maestre (Luisa, T. Soc., 924-531736) Informe Social para solicitar plaza residencial por Decreto en base a la emergencia social del caso cuando Andrea se va a su pueblo. Lo enviará por correo ordinario y electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-03-06','Conversación con Eugenia, T. Soc. SSB de Jerez. +++Reitera los datos ofrecidos por el Informe de Futuex y por el propio Informe remitido por corre-e sobre las amenazas de Ramón a su hermano Manuel y a su amigo Willy. Finalmente NO HAN PRESENTADO DENUNCIA como manifestaron a la Delegada, al parecer, según Eugenia ha sabido del propio Manuel, porque la madre de ambos le dijo que cómo iba a denunciar a su propio hermano, que ni se le ocurriera..." La madre está yendo actualmente a comer al comedor social derivada por el SSB. +++Llamo a Manuel, hermano de Ramón, pero cuelga la llamada. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al ESM de Jerez. Hablo con Manuel, Enfermero del Equipo (924-751834). +++Ramón está cumpliendo correctamente con su tratamiento (inyectable trimestral) y cuando acude a la consulta se muestra tranquilo y conciliador. +++Realizará visita domiciliaria este próximo jueves, 9 de marzo, junto con Silvia (delegada Futuex). Le pido que nos envíe un informe valorando la situación actual de Ramón. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se envían al Juzgado, por fax, los informes relativos al inicdente protagonizado por Ramón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2017-03-06','-Mantenemos conversacion tf con la TS del SSB ( Eloisa ) para hablar de este caso . Vamos a solicitar dependencia , les va a entregar el I.Medico a los seminaristas con los que vive Cesareo para que se lo entreguen al médico .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2017-03-03','Reunión en CRR de Mérida con Javier y Gisela. +++Luisa está yendo a un nuevo dentista. De momento, del presupuesto que tenía inicialmente con el otro dentista le quedan 400€, de los que irá pagando al actual. Cuando se agoten, desde el CRR solicitarán el dinero que se precise.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2017-03-03','Reunión en CRR de Mérida con Javier y Gisela. +++José María comenta que la vivienda que tiene en copropiedad con sus hermanos ya está puesta a la venta por 120-140.000€. +++Se reafirma en su deseo de vender su parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2017-03-03','Reunión en CRR de Mérida con Javier y Gisela. +++Fermina solamente hace una demanda: QUIERE LOCALIZAR A SUS HIJOS y poder tener contacto con ellos. +++El mayor, nos dice, se llama David y nació en la Clínica Perpetuo Socorro de Badajoz. Tiene 29 años. +++Pido a Gisela que trate de obtener todos los datos posibles de dichos nacimientos para tratar de coordinarnos con Menores para ver si sus hijos han hecho algún intento de contactar con su madre biológica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-03-07','Conversación con Ángela, Directora de Placeat (927-421950 y correo-e: angela@placeat.org). +++Se le envía la información sobre Joaquín de la que dispone la Comisión. +++Han solicitado el cambio de perfil de sus usuarios de V.T. a RAL pero no hay resolución todavía. +++A FAVOR del traslado: cuentan con Centro Ocupacional y C.E.E. con actividades de jardinería. +++EN CONTRA (relativamente)del traslado: la edad de los residentes en el centro, mucho mayores que él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2017-03-03','Reunión en CRR de Mérida con Javier y Gisela. +++En tratamineto en CEDEx por alcholismo +++Quiere acercamiento familiar: su madre está en la Residencia de Olivenza, a la que visita una vez al mes durante cuatro días. Durante este tiempo se queda en un piso propiedad de todos los hermanos y va a comer a casa de una hermana.++++++OPCIONES pàra acercamineto familiar: ***Solicitar traslado a la residencia de su madre o ***solicitar, desde CRR, traslado al CRR de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2017-03-06','El inmueble tiene varios herederos, Anita Priscila es propietaria del 50%, el otro 50% tiene varios propietarios. No se hace ninguna gestión. Primero deberán consultar con los otros herederos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-03-07','Llamada de Manuel (924-953756 y 697-781239),hermano de Ramón. Ayer no pudo coger la llamada porque estaba ocupado en ese momento. +++"Mi hermano tiene que estar en un centro ingresado..." +++"No hemos denunciado por no darle un disgusto a mi madre..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LETICIA'and edp.apellido1='NIETO'and apellido2='SAN CARLOS'),'2017-03-07','Conversación con Soledad, T. Soc. de Nuestra Señora de la Luz (924-237551). +++Valorarán en el Equipo la posibilidad de que leticia pueda volver a casa de sus padres para la Feria de Mérida, 3-4 días como ha venido siendo habitual anteriormente. Nos comunicarán su opinión. +++Las salidas fuera de esas fechas son muy, muy esporádicas y los contactos más frecuentes son por teléfono. +++Leticia en ningún caso manifiesta preferencia ni en un sentido ni otro de cara a estas visitas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2017-03-07','Conversación con Pablo Sánchez Marchesi (director del CRR: 687-487908): +++Feliciano NO QUIERE VENDER la casa. +++Dado el apego emocional que para él supone su propiedad, la venta de la misma supondría un MÁS QUE PROBABLE RIESGO de desestabilización emocional y psíquica para él. +++La posibilidad de que Feliciano compre la parte de su hermana NO se contempla desde la Comisión, por cuanto un desembolso así supondrá un gasto innecesario en el presente, con una pérdida de capacidad económica que de cara al futuro fuera preciso afrontar (p.e. el pago de una plaza residencial). +++Pablo enviará informe sobre la repercusión que la venta de la casa podría tener para Felciano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2017-03-06','-se eniva aceptacion PIA , se solicita SAD conveniado con el Ayto sin pago .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2017-03-07','-llega la autorizacion judicial para su internamiento en Centro resdiencial . - He solicitado cambio de PIA , del SAD a plaza residencial . Insintir llamando a Cecilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-03-08','Llaman del Ayto de Alburquerque en relación con una deuda de agua de la casa de Isidoro. Nos ponemos en contacto con la compañía, Luis Miguel 924 400 574, para conocer lo que se adeuda, enviará facturas al correo electónico, un total de 17 facturas desde junio de 2014 por un total de 145,91 €. Los recibos habían sido devueltos por LA Caixa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2017-03-08','Llamada de Sonia, del Centro de Rehabilitación y Reinserción Social “Camino a la Vida" . +++Curatela patrimonial y económica. +++José Antonio se fugó el viernes y a fecha de hoy no ha regresado todavía al centro. +++Según la sentencia de remoción de la curatela tuvo una orden de alejamiento de su madre y de su médico en juicios de faltas 467/10 y 278/12 dellos Juzgados de Instrucción nº 4 y 3 respectivamente. +++Según comenta Sonia, se ha marchado a casa de sus padres. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Recibimos Informe solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2017-03-08','Conversación con Carlos Mejías González, Letrado de la Junta. Teléfono 44420 y correo-e: carlos.mejias@juntaex.es +++Se le envía la documentación solcitada y los antecedentes para el prcedimiento judicial en curso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2017-03-08','Conversación con el Padre Miguel: +++Concertamos visita domiciliaria para el próximo día 14 de marzo a las 10:00h. +++Dirección: Avda. de Plasencia 3, BARRADO. +++Teléfono: 619-040701 y 679-077448.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-03-08','Conversación con Mª del Mar, directora de Fuente Atenor (924-018738): +++El principal problema que plantea D. Isidoro es que se quiere marchar a su casa y a veces se "escapa" de la Residencia. +++El segundo problema es que tan solo tiene 50 años y se encuentra en un Centro con personas mucho mayores...aunque su deseo es no estar en centro alguno. +++Se le ha dado de baja en CEDEx porque las últimas veces ha faltado a la consulta y en este recurso la voluntariedad es imprescindible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RODRIGUEZ'and apellido2='PARRILLA'),'2017-03-09','- Se concreta con el centro solictar PNC , nos enviarán la solicitud. - Se hace un cambio en PIA por cambino de circunstancias ( domicilio , pasa de Llerena a Azuaga )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2017-02-08','Correo electrónico: Buenos días He de comunicarle que la Abogacía General de la Junta de Extremadura no asume ordinariamente la defensa y representación de personas cuya tutela ostenta la Comisión Tutelar. Hacemos notar que la actuación como tutor de la Administración se realiza desde el ámbito establecido en el Código Civil y por tanto, sustituyendo o representando al incapacitado en todos aquellos actos o negocios jurídicos personales o patrimoniales que le afecten en los términos establecidos en la sentencia. Por tanto, la representación o actuaciones judiciales que se pretendan lo es en nombre y representación de una persona física y respecto de intereses particulares, por lo que los letrados de la Abogacía General no pueden ejercer esa condición, pues tienen encomendada la defensa y representación de la Junta de Extremadura y su Administración Institucional. Por tanto, deberá la Comisión Tutelar arbitrar las medidas necesarias para designar un abogado que defienda los intereses del menor (anulación del testamento), distinto del designado de oficio para defender a éste. Un saludo, F_Antonio_Alonso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-03-09','Conversación con José Mª Tovar. +++Hoy ingresa Tomás en el Hospital de Parapléjicos de Toledo. +++Envía Informes de Alta del Hospital San Pedro de Alcántara y derivación a Toledo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2017-03-10','SE envía al Servicio de Infancia, Familias y Adolescencia propuesta para mantener a Joaquín en el recursos actual (Vivienda Tutelada de Hofa en Montijo), junto con Certificado de Escolaridad e Informe Académico. CONTACTOS:Pilar (Psicóloga de Plena Inclusión) y Marina. 924-454842 y 695-539909.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-03-08','Conversación con Francisco, hermano de Saturnino. +++En su opinión, este es el peor momento para ingresar a su hermano: "Está teniendo un comportamiento como nunca, ayuda a nuestra madre, va a la compra...está tranquilo, toma su medicación...". +++Francisco se muestra muy enfadado por lo que, en su opinión, es un despropósito: "Cuando Saturnino está mal hay dificultades para ingresarlo y ahora que está como nunca lo queréis ingresar". "Pues le vais a dar un disgusto enorme a mi madre y veremos cómo le sienta a Saturnino está situación..." Dadas las circunstancias, le pido a Francisco que me envíe un correo-e describiendo la situación actual de su hermano y la convivencia con su madre, para poder comunicar al Juzgado la situación mencionada. Además de por teléfono, se le pide dicha respuesta también por correo electrónico. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Para verificar la situación, se pide a Futuex que realice una visita domiciliaria y nos informe al respecto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SE trata de contactar con el ESM de Cáceres pero no es posible en el día de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-03-07','Conversación con Rosa (CSS de Plasencia): saturnino puede ingresar en UME de Plasencia, según Unidad de Programas antes del 10 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-03-09','Conversación con Pilar, T. Soc. del ESM de Cáceres: tras explicarle la situación, comenta que la Psiquiatra se encuentra en un Congreso en Madrid. Llamaré nuevamente el lunes. +++Me informa de que Saturnino FALTÓ a la consulta progarmada para el día 6 de marzo, pero que se le dió otra cita para el día 16 del presente mes. Ruef¡go nos informen del resultado de esa consulta en relación con la conveniencia o no de ingreso en estos momentos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Dª Isabel, madre de Saturnino. Es media mañana y Saturnino sigue acostado, según me dice su madre. +++DESCRIPCIÓN de la situación según Dª Isabel (en ningún momento se hace referencia por mi parte a la posibilidad de ingreso ni presebte ni futura): "Mi hijo se está comportando ahora como hacía mucho tiempo no ocurría.Soy ya muy mayor (85 años) y me hace mucha compañía, mire usted...Como además estoy delicada, el me hace la compra, va a recados y la verdad es que si no fuera por él en estos momentos me sentiría muy sola...me hace mucha compañía". +++++"Es cierto que faltó a la consulta que tenía esta semana, pero fue porque se le pasó. Yo le dije que eso no podía volver a ocurrir y que fuera a pedir otra cita, pero el prefirió llamar por teléfono para pedirla". +++++"El está muy bien, está tomando todos los días su tratamiento, pero fuma mucho, muchísimo...y no hay manera de que lo deje. +++++Deberían buscarle una ocupación, para que no esté todo el día sin hacer nada...pero también reconozco que tiene usted razón, que él no pone de su parte..." Dado que parece tener afición a la guitarra, le propongo a Dª Isabel que hable con él para que se busque una academia y pueda aprender a tocarla (mejor una academia que clases particulares). Dª Isabel se muestra ilusionada con esta posibilidad, dado que reconoce que quizá esto sí pueda ser aceptado por su hijo. De cualquier forma, no podemos olvidar que Dª Isabel, en conversaciones tenidas con ella en el pasado, siempre ha tendido a disculpar en mayor o menor medida el comportamiento de su hijo, viéndose superada por la scircunstancias. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de Dª Mar Salgado, hermana de Saturnino (690-671204), interasada por la llamada que hemos realizado a su madre esta mañana. Es el primer contacto que la Comisión tiene con Dª Mar, quien se muestra comprensiva con la situación y colaboradora, manifestando en varias ocasiones la tranquilidad que supone para ella y su familia el saber que la Comisión está pendiente de su hermano. +++Llama porque su madre le ha comentado, bastante alterada, que tenía miedo de que fuéramos a ingresar a su hijo.: "Saturnino dice que no quiere volver a ingresar en Plasencia, y nos ha amenazado en varias ocasiones con que si lo hacéis, se suicida. Mi madre tiene un miedo terrible a ello, porque teme que a saturnino le ocurra como a su otro hijo que se suicidó..." +++"Mi hermano debería estar en un Centro siempre, pero comprendo que quizá no sea este el mejor momento para ingresarlo. ES cierto lo que te dijo mi hermano de que se está portando como hace mucho tiempo no ocurría,es cuando menos guerra está dando, pero también es cierto que la situación es de un "equilibrio inestable" que no sabemos cuándo se puede romper". PIDO A MAR que hable con su hermano y, por separado o conjuntamente, nos manden por correo-e una descripción de la situación actual, con su valoración de lo que en su opinión supondría el ingreso de su hermano en estos momentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='DIAZ'and apellido2='VAZQUEZ'),'2017-03-10','Se archiva el procedimiento relativo al Juicio sobre delitos leves 138/2016, seguido en el Juzgado de Instrucción nº 16, de Sevilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-03-10','A día de hoy no hay correo de los hermanos de Saturnino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2017-03-10','Sonia confirma el regreso hoy al centro de José Antonio: muy arrepentido, se ha acutocastigado lavando los platos durante una semana (algo a lo que le tiene muchísima vergüenza) y pidiendo disculpas por su comportamiento. +++Se sugiere que resalten este comportamiento de José Antonio como refuerzo del mismo. +++Se les propone también que, si en alguna ocasión él quiere hablar con la Comsión, o consideran pertinente que lo haga que no duden en contactar con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-03-10','Conversación con Manuel, Enfermero del ESM de Jerez (924-751834). Remite FAX con la información de la visita domiciliaria realizada ayer a Ramón ("la entrevista transcurrió en los aledaños de la vivienda sin acceder a la misma"). +++Aparente normalidad en la situación. +++Ramón niega las amenazas con un cuchillo a su hermano y al amigo. +++Desde octubre, ha acudido a la administración del inyectable trimestral en las dos ocasiones programadas. La siguiente es en abril. Manuel refiere que, en opinión de Silvia (Delegada), quizá se podría intentar el alquiler de una vivienda para Ramón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2017-03-10','Solicitamos abogado de oficio al Colegio de Abogados de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2017-03-10','Enviamos a la notaría de Elgoibar el cdo. de nacimiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-03-10','Enviamos:- a Vodafone escrito para requerir autorización de la CTAEX para nuevas contrataciones y cancelar datos personales de la base de daos. -Orden al banco dejar de pagar 63€ Ed Planeta a partir de abril -Contratación nula a EDitorial planeta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2017-03-10','Llama Manuel Terrones,t/c 650010866, comprador de la finca, interesándose por el estado de las gestiones. Se le informa de que hay que pedir autorización al juez para aceptar la herencia de la madre y posteriormente autorización al juez para vender.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-03-10','Mandamos correo electrónico a Aquarex Almendralejo para solicitar información para dar de baja el suministro. Hablado con sección social nos informan que el Isidoro dificilmente volverá a su domicilio, por ello se procederá a la baja para que no sigan pasándole recibos.','2');
