insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2017-03-15','Informo al ESM de Cáceres de los trámites realizados con la Fiscalía y remito el correo enviado por Francisco a la Comisión, junto con el de Futuex y el Informe de la visita realizada el pasado día 10 a Saturnino. +++Pendiente la consulta que para mañana, 16 de marzo, tiene programada con el ESM. Hablo con Futuex: lo acompañarán mañana. +++Conversación con Rosa (CSS Plasencia): informo de las gestiones realizadas. Plantea que, en caso de ingreso, quizá lo mejor sería en URA, si bien quizá debería pasar primero por UME.','2');
