insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-03-15','Visita de José Mª a la Comisión: +++Solicita un extra de 80€ porque el sábado quiere invitar a sus amigos y para llegar a final de mes. +++Se le plantea la posibilidad de que, una vez cocnocida la opinión de los profesionales que conocen su caso, pueda si se ve oportuna plantear la posibilidad de un piso de alquiler. +++Se le intenta hacer ver que con el actual gasto del Hostal (+/-300€7semana) y lo que saca a pricipios de mes (250€) debe tener bastante..."Sí, tienes razón...además fumo mucho..." +++Se refuerza que siga acudiendo al CEDEX, al ESM y evite cualquier contacto con abuso de sustancias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2017-03-14','VISITA DOMICILIARIA realizada el 14 de marzo, acompañado por Elosisa, T. Soc. SSB de Barrado. +++Reunión mantenida con Cesáreo y el Padre Miguel Muñoz Moreno, fundador de la Asociación "NUNQUAM SANTIS". +++CONTACTO: 619-040701///679-077448. +++CORREO-e: hildegardamil@hotmail.com +++Actualmente viven 5 personas en dicha vivienda. +++D. Cesáreo lleva un año viviendo con ellos. Llegó a la Asociación derivado por un conocido suyo que le propuso que se fuera con el Padre Miguel, quien lo recogió "...como ha hecho en otras ocasiones con otras personas...que en un momentoto determinado se han marchado a seguir con sus vidas..." +++TUTELA: se explica la situación en la que se encuentra Cesáreo, quién es el responsable del mismo, las responsabilidades que supone cuidar de él, etc. +++ECONOMÍA: mantener la situación actual (sacan 480€ al mes). Si finalmente el juzgado da por finalizada la pensión por alimentos que D. Cesáreo pasa a sus hijos (adultos y al parecer con trabajo) ese dinero quedará en la cuenta de nuestro tutelado, al igual que las pagas extras, con la finalidad de poder hacer frente a posibles contingencias futuras (el Padre Miguel comenta que en esos casos, la Comunidad afrontaría la situación, como han hecho hasta ahora...Pagaron-comenta- la limpieza y tapiado de la casa de Tejeda, propiedad de la hermana que vive en Barcelona(no tenían teléfono de ella y les pedí que cuando hablaran con ella le dijeran que se pusiera en contacto con la Comisión). +++SALUD: El Padre Miguel comentó que había acudido a varias especialidades en el H. Virgen del Puerto de Plasencia, pero que no tenía en nese momento preparados los Informes correspondientes. LOS PEDIREMOS DESDE CTAEx. +++SITUACIÓN DE D. CESÁREO:nos abrió el la puerta y con mucha educación nos hizo pasar al salón mientras llamaba al padre Miguel. +++++Aspecto inmejorable: bien vestido, con chaqueta (ene esta ocasión dijo el Padre que no se había puesto la corbata) y una sonrisa que solamente se le marchaba de la cara cuando por alguna razón, se emocionaba (quizá al recodar cómo era su vida antes de concer al Padre Miguel). +++++Apenas habló durante la visita, pero se mostró muy contento cuando le pedí que me enseñara su habitación que, como el resto de la vivienda, estaba en perfectas condiciones (de la vivienda solamente ví las zonas comunes): amplia, con la cama, un armario una mesa y la mesilla, con vistas a la sierra, con baño completo dentroi de la habitación. +++++Al parecer, a Cesáreo, aunque es una persona válida, carece al parecer de habilidades necesarias para llevar a cabo las actividades básicas de la vida diaria: el Padre Miguel confirmó que necesita ayuda para casi todo y siempre supervisión (Ramón, otro de los residentes, se encarga de ello.) +++++DÍA A DÍA: Cesáreo se encarga de pequeñas tareas como dar de comer a las gallinas "...me pongo el mono para trabajar, pero cuando termino me arreglo bien, como ahora..." +++++A Cesáreo SE LE NOTA CONTENTO CON SU SITUACIÓN ACTUAL. Según el Padre Miguel, "...lleva tres días nervioso con su visita...". No quiere marcharse a otro sitio bajo ningún concepto, cosa que, se le dijo, no ocurrirá mientras la Comisión sepa que él se encuentra bien en todos los sentidos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Pasé también por el Ambulatorio, donde pude hablar con Margarita, la Enfermera: "No sabes mucho de él, apenas viene por aquí...Suelen venir más algunas de la personas que conviven con él a por la medicación, etc.','2');
