insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIANO'and edp.apellido1='RODRIGUEZ'and apellido2='DE LA CONCEPCION'),'2017-03-21','Conversación con Rosario, T. Social del C. Salud San Fernando de Badajoz, sobre la dirección de este señor solcitada por Escalona: +++Se envía dicha informción por correo-e: En relación a la Defensa Judicial de D. Mariano R. de la C., con nº de procedimiento 172017, que le comentaste a Ángel para localizar su actual paradero, el mismo se encuentra en la siguiente dirección: Residencia Sarquavitae Avda. Castillo Puebla de Alcocer, 16. 06006. BADAJOZ. Teléfono: 924 28 65 30 En la conversación mantenida con la T. Social del C. de Salud de San Fernando, Rosario Hornero (902-112014), me comentó que hay un señor, D. Manuel José Menacho Gómez (662-066006) que se estaba haciendo pasar por su tutor, sin serlo, y que pretendía sacarlo de la Residencia. Te lo digo a efectos de si se puede plantear alguna medida cautelar en realción a la situación de D. Mariano.','2');
