insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2017-03-21','Llama Eva, T.Soc. de las hermanitas de los Pobres (626-734673). +++Refiere brotes de agresividad de Dª Andrea en los últimos días y no saben qué hacer.SE niega a tomar su tratamiento. +++Se les indica que deben llamar al 112 cuando esto ocurra, para valorar posible tratamineto y en su caso posible internamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-03-22','Llama Caty,trabajadora social de Aprosuba-3, indicando que los fines de semana que Daniel visita a su abuela va al comedor social a recoger la comida para ella, pero que en ningún caso recoge comida para él. Además comenta que enviará por correeo electrónico cuota de baloncesto de 20€/mensual de Danie.l','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2017-03-22','Visita domiciliaria, acompañado por Eva, T. Soc. SSB de Arroyo de la Luz y Julio y Manuel, Policías Locales (no fue necesaria su intervención, ya que la visita transcurrió dentro de una absoluta normalidad. +++CONTACTOS: ****EVA, T. Soc. SSB(evajimenez@tajosalor.es)///****MARU, T. Soc. Centro de Salud (maru.rodríguez00@gmail.com) +++D. Ángel ha acogido en su casa a Dª Mª Eugenia, una vez que está abandonó su convivencia con D. Marcelino (por desavenencias). La vivienda está en unas condicones aceptables de habitabilidad, pero la convivencia queda a expensas de que uno u otro se cansen de mantenerla. +++ACCIONES: ****Mª Eugenia acudirá a consulta con su Médica de Familia. Pedirá la cita Eva, quien a la vez pedirá sea derivada al ESM de Cáceres para valoración. ****Pedirá a la Médico que nos envíe el Informe para solicitud de revisión del grado de Dependencia (Ni EVa ni yo creemos que alcance un grado II). ****Visitar por Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2017-03-03','se envia a la gerencia sepad solicitu cambio PIA , solicitando plaza residencial por emergencia social . -quedamos pte . de que nos asignen plaza para contactar con el 112 para el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2017-03-23','Conversación con Manoli, T. Soc. Psiquiátrico Penitenciario de Sevilla (955-616666-Ext.135).Ayer llamó Jesús (955-987332) diciendo que salía de prisión el 1 de abril y que le teníamos que buscar un centro, que tenía caducado el DNI y que pusieramos a su hermana en las cartillas. +++EXCARCELACIÓN: sigue prevista para el mes de octubre. Informo a Manoli de la idea que tiene Jesús respecto a su fecha de salida para prevenir en lo posible reacciones negativas por parte de Jesús y le ruego que NOS MANTENGA INFORMADOS DE LAS CAUSAS QUE TENGA PENDIENTES (ha vuelto a protagonizar algunos incidentes y comprobará la apertura de nuevas causas)y SOBRE TODO DE LA FECHA DE EXCARCELACIÓN, con tiempo suficiente para tener preparado el recurso al que pueda acceder. +++CADUCIDAD del DNI: Manoli lo comprobará, aunque no cre que sea así porque ellos tienen un listado de aquellos internos a los que les va a cumplir y lo renuevan directamente. En estos momento, de los cuatro Psiquiatras de los que dispone el Centro solo está disponible uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2017-03-23','Conversación con Caty, T. Soc. Aprosuba 3 (610-292594). +++Nos enviará, para firma y remisión, solicitud del Carnet Joven en lugar de la Tarjeta de Transporte (aquel incluye este servicio.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-03-23','Conversación con Caty, T. Soc. Aprosuba 3 (610-292594). +++Enviará solicitud para firma de la Federación de Baloncesto, para abonar los 20€/mes. +++La abuela está yendo a diario al comedor social y los fines de semana, que Daniel los pasa en su casa con ella, es él que que acude al comedor para recoger la comida y llevársela a su abuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2017-03-23','Conversación con Caty, T. Soc. Aprosuba 3 (610-292594). +++Solicitará complemento a la PNC de Emilia al tener una incapacidad superior al 75%. +++RELACIÓN CON SU HIJO: estupenda. Acudió el día de Reyes con un regalo para ella, lo cual le hizo mucha ilusión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-03-23','Llamada a José Mª Tovar: +++EVOLUCIÓN: están empezando a retirar sonda vesical progresivamente hasta recuperar el control. Al menos hay que esperar 3 meses, hasta que desaparezca la inflamación medular, para hacer un diagnóstico y pronóstico adecuado. +++RUTINA: de 11 a 14h Tomás está en el gimnasio y con terapia. También una hora por la tarde. +++VISITAS: ellos van todos los fines de semana. +++C. OCUPACIONAL: se informa de la baja solcitada desde aquí en la plza de C. Ocupacional. +++LE PIDO QUE NOS ENVÍE LOS TELÉFONOS O CORREOS DE CONTACTO del personal que lo está atendiendo y enviará también el teléfono de Tomás para llamarlo de vez en cuando.','2');
