insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2017-03-24','Visita de D. Juan Rollán, padre de Cristofer. +++Interesándose (¿?) por la situación de su hijo. +++Le ha planteadola posibilidad de irse a vivir con él al piso de Cristofer, pero este le ha dicho que está mejor solo. +++Pregunta por los ingresos que tiene su hijo "...si se pued e saber ...". Obviamente no. +++Intento hablar con el ESM para pedir información sobre la situación actual, pero no contestan a la llamada. Pedirlo por escrito.','2');
