insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2017-03-24','El Juzgado de lo Penal nº 1 de Plasencia dicta Sentencia nº 182/2017, de 14 de febrero, (procedimiento abreviado 381/2016, tras tramitarse por el Juzgado nº 3 de Plasencia diligencias previas 599/2014, procedimiento abreviado 48/2014)), frente al propio Agustín y José Mª. Vicho Alfonso. La medida termina el 13/2/2018. Nos dicen desde el Juzgado que el día del juicio le dieron a Pedro un número de cuenta donde hacer el pago. Se les absuelve del delito de lesiones y se le imponen las medidas de internamiento en régimen cerrado, en establecimiento médico por tiempo de un año. Se les condena como responables civiles a indemnizar a Francisco Macías Martínez a la cantidad de 1.860 euros. Se declara la responsabilidad civil directa de la Comisión Tutelar de Adultos.','2');
