insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2017-04-03','Reunión en CSS de Mérida. Presentes:Blanca (T. Social), Ángel (Enfermero), Álvaro (Psiquiatra)y Pedro (CTAEx). +++Se informa de la necesidad imperiosa de limitar cualquier vía de comunicación de D. Antonio con el exterior:se tratará de limitar las salidas (fundamentalmente con su hermana), las llamadas telefónicas y el acceso a ordenadores con internet.NO EXISTE LA GARANTÍA 100% DE EFICACIA, dado que hay cabina de teléfono en el centro, pide los móviles a los trabajadores (se avisará a todos de que no le presten sus telefonos) y también a los pacientes, a los cuales les abona lo que le piden por la llamada. +++En terapia sí usan ordenadores. Se procurará que si usa alguno sea sin conexión a internet. TODO ELLO, AL MENOS, HASTA QUE HAYA SENTENCIA EN EL JUICIO y con arreglo a la capacidad y medios de los que dispone el centro para aplicar dichas precauciones.','2');
