insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-04-04','Desde la última conversación con Pablo se ha intentado en varias ocasiones recabar información de su parte respecto de la situación en la que se encuentra el expediente de Margarita en cuanto a la asunción de la Tutela por parte de Castilla-León. NO HA SIDO POSIBLE CONTACTAR con él en ninguna de las ocasiones mencionadas. Se guiremos intentándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2017-03-29','- Hablo con PNC Caceres ( Javier Monago Jefe de SEccion ) para ver el expediente de PNC . Le remito Cdo negativo de empadronamiento en Trujillo. Le explico la modificacion sufrida en PNC para asimilar el grado de discapacidad. -Quedo pte. de su respuesta . Tb lo comunico a Adela ( PNC Mérida )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2017-04-05','Solicita 100€ porque se quiere marchar a Sevilla en Semana Santa. Se autoriza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-04-04','SALIDA Durante el primer trismestre de 2017 ha acudido a su médico de familia a consecuencia de una faringitis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-01-13','SALIDA 13/01/2017 (PADDI). Tiene piorrea. Se le comenta a la doctora que en marzo comienza un tratamiento para tratar la enfermedad. Nos comenta que este tratamiento debería hacérselo cada 3 meses. Le manda enjuague bucal después de las comidas dirante 15 d/. Le dice qie fumar le perjudica mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-01-18','SALIDA El 18/01/2017 (INYECTABLE). Se pincha el inyectable. Próxima cita el 18/04/2017, a las 11.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-02-01','SALIDA El 01/02/2017 (PODOLOGA). Le arregla los pies y le recomienda una crema para los hongos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2017-03-02','SALIDA El 02/03/2017. (DENTISTA). Tratamiento piorrea. Le realizan periodontograma, radiografía periapical, raspado parte superior y pulen manchas. En la siguiente consulta cuando le hagan el raspado de la parte inferior, le unirán los dientes de arriba (paletos) porque uno se mueve mucho porque ha perdido mucho hueso. Se debe cepillar primero sin nada y de encía a diente, por delante y por detrás, luego otra vez com la pasta y para finalizar usar un cepillo interdental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2017-04-04','SALIDAS Durante el primer trimestre 2017.**************************En el aspecto sanitario, este primer trimestre de 2017 acude a su médico de cabecera para control rutinario de salud, además de comentarle que le sigue doliendo el pie, por lo que le mandan una radiografía para ver si lo que tiene es un esguince. Le hacen la radiografía pero no se ve nada fuera de lo normal.**********************************************Tiene revisión con la podóloga.**********************************También se continúa con su tratamiento de Xeplión, así como el control de tensión y peso.*********************************Va al PADDI para revisión anual rutinaria.**********************************Asiste a la consulta del psiquiatra para control del tratamiento. El doctor comenta que no se ríe tanto como otras veces y que la nota más tranquila. Cambia medicación a TREVISTA. Le harán un seguimiento cada 3-6 meses. La cita para el inyectable y analítica fue el 27/02/2017, a las 8.45 Hs. Nos da un cuestionario para rellenarlo. La próxima revisión del psiquiatra es el 02/10/2017, a las 11.30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-12-23','SALIDA Entre el 23/12/2016 y el 09/01/2017. Visita a su hermana en Badajoz para disfrutar del periodo de vacaciones de navidad. El medio de transporte que utiliza es el tren.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-02-17','SALIDA Entre el 17/02/2017 y el 20/02/2017. Visita a su hermana en Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-02-06','SALIDA El 06/02/2017 (NEUMÓLOGO TELEMEDICINA). Al preguntarle por la máquina le cie que se la pone pero que a las 2 horas como máximo se la quita. La próxima consulta será en Badajoz para hacerle una espirometría. Nos mandarán la cita por correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-02-07','SALIDA El 07/02/2017 (NEUROLOGÍA). No tiene pérdida de fuerza. Le hace exploración neurológica. Pregunta si tiene dificultad para tragar y se le dice que no, pero a veces tose mucho con la naranja o la mandarina. Dicen qie puede ser principio de disfagia y que en un futuro comerá con sonda. Le dice que es de poco comer. Nos aconseja vigilar el peso y la disfagia y si empeora tiene que verlo el endocrino. Nos entrega informe médico. Próxima revisión: 20/02/2018, a las 11.20 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-03-17','SALIDA El 17/03/2017 (PADDI). Tiene las encías inflamadas y debe limpiarse y hacerse masaje con una gasa mojada en clorhexidina. Tiene buena higiene pero debe cepillarse mejor la zona donde tiene los dientes apiñados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2017-03-27','SALIDA El 27/03/2017 (NEUMÓLOGO). Le realizan espirometría de pie y tumbado. Le resulta extraño que tiene mejores resultados estando tumbado que de pie. Le dan de baja en el uso de la máquina para dormir porque se le comenta que no la usa. Se entrega la máquina y nos dan ficha que asegura que ya la hemos entregado. Entrega informe de espirometría. Próxima cita: 26/04/2018, a las 12.40 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2017-04-05','Envío a Rosa Certificado de Dependencia: GRADO III-1, GRAN DEPENDENCIA. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo de Rosa:ME ACABA DE FIRMAR LA SOLICITUD DE CAMBIO DE PIA POR DEPENDENCIA Y AHÍ HA SOLICITADO CENTRO RESIDENCIAL PARA DISCAPACITADOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-04-05','Llamada de Mariví, T. Soc. del CSS de Plasencia. +++3º en lista de espera para pisos supervisados. +++Quiere hablar con sus tutores ("...tiene la paranoia de que no queréis hablar con él.")Llamare dentro de 25´ +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Juan: +++Quiere marcharse del Centro porque se están vulnerando sus derechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-04-05','Convesración con Dolores Álvarez (924-730061), Secretaria Juzgado de Jerez de los Caballeros: +++informamos sobre la disponibilidad de dinero que reclama Ramón en el Juzgado (transferencia a la madre de 275€). +++informamos sobre últimos ingresos y previsión de UME +++informamos sobre trámites CADEx','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-04-05','Conversación con Juan','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='PEREZ'and apellido2='GARCIA'),'2017-04-05','Llama Pilar, hermana de José Antonio (927-181693 y 617-758711): +++saber qué tienen que hacer ellos en relación a la herencia "...porque mis hermanos -calificativo despectivo- me tienen loca con el tema y por eso he llamado a la Comisión..." Estamos a la espera de la parobación por parte del Juzgado de la Rendición Final de Cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2017-03-29','- EL DIA 27 INGRESO EN CENTRO RESIDENCIAL DE FELIPE TRIGO .EL TRASLADO SE HIZO CON SU CUIDADORA DEL PUEBLO Y SE LE PAGARÁ ELS SERVICIO PRESTADO . LAS LLAVES DE SU CASA ESTÁN EN LA R.M. Y LA CUIDADORA SE HA ENCARGADO DE DEJAR TODO CERRADO . DOY DE BAJA AL SAD CON LA EMPRESA QUE LO GESTIONABA ( MG SERVICIO 924731701 POR EMAIL ) Y TB LO COMUNICO EN DEPENDENCIA. -SE ENVIA AL SEPAD ACEPTACION PIA CON LA PLAZA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-04-05','+++','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-04-05','Conversación con Liliana, T. Soc. SSB Cáceres (927-231295): +++Desde que Martina ingresó en la residencia considera que está más desestabilizada. +++Considera que, si consintiera en llevar los controles en el ESM, C. Salud, etc. se podría seguir manteniendo en domicilio durante más tiempo (con lo cual esta Comisión está de acuerdo), pero dada su negativa a cumplir con ello solo queda la vía del ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-04-05','Conversación con Liliana, T. Soc. SSB Cáceres (927-231295): +++Han dado el alta a Martina en el Hospital Virgen del Puerto, regeresando a la Residencia de Villa del Campo). +++Al parecer, Paula habló con la Residencia al saberlo y el trató que recibió por teléfono no fue el correcto (al parecer el personal que atendió la llamada contribuyó de alguna forma al delirio de personalidad que muestra). Liliana lo puso en conmocimiento de la directora de la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-04-06','Conversación con Curro: +++Se ha archivado el prcedeimiento solicitando valoración y en su caso ingreso en centro. +++Curro proponer volver a solcitar ingreso directamente y luego ejecutarlo o no segúin se valore en Comisión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Liliana. +++Enviará Informe apoyando la necesidad de ingreso de Paula.','2');
