insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-04-06','Conversación con Natividad, T. Soc. del Hospital de Parapléjicos de Toledo (925-247753). +++A la espera de la evolución de Tomás para valorar recurso más adecuado. +++Dejo correos electrónicos y teléfono de contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-04-06','Acudimos al Juzgado de 1ª. Instancia e Instrucción nº 1, de Mérida, a la comparecencia en relación con la venta de la casa de Valdecaballeros. María del Carmen no se presenta. Aún así, se celebra la comparecencia. El Fiscal no se opone. Estamos a la espera que se dicte Resolución judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2017-04-05','-Futuex nos informa que desde el SSB de CC le han tramitado renta basica y ha recibido el primer pago este mes . Actualmente está viviendo con los abuelos maternos . No quiere estar tutelado para evitar la administración del dinero . volver a llamar a PNc para ver cómo está su expte. y comunicar este cambio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2017-04-05','-Valentina ( TS del CEntro de salud ) es la que tiene q solicitar por PIA ingreso en centro residencial cuando tengamos la autorización . Contactar con ella cuando llegue.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-04-04','-VISITA EN LAS OFICINAS DE CTAEX DE RAMON . LO RECIBE LA TS ( AMALIA ) ME AMENZA CON TRAER UN ARMA SI NO LE DAMOS EL DINERO QUE PIDE . DESPUES DE TRANQUILIZARLO NOS SENTAMOS CON ÉL Y VOLVEMOS A REVISAR SU PTO ( PEDRO Y AMALIA ) SE LE CONCEDE UNA SUBIDA EN DINERO PARA PIENSO Y ALGO MÁS PARA SUS GASTOS . TIENE QUE IR A RECOGER UN EXTRA EN UNA SUCURSAL DE MERIDA DE 10€ PARA VOLVER A JEREZ . VUELVE DE SEGUNDAS , NO HA LLEGADO EL FAX AUN AL BANCO Y NO HA PODIDO RETIRAR EL DINERO . VUELVE AMENARNOS ( AMALIA Y BELÉN ) CON SACAR EL ARMA ( CUCHILLO ) . EL JEFE DE SECCION COMUNICA A LA GERENCIA Y AL SERVICIO DE RIESGOS LABORALES LO OCURRIDO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-04-07','SE avisa a José María de que desde Futuex se pondrán en contacto con él para hacerle una visita y ayudarle en la búsqueda de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2017-04-07','Hablo con Antonio Nisa (924-531736): enviará Informe Social para ingreso (cree que lo han enviado pero no nos consta en la Comisión). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Eva, T. Soc.de la Residencia. +++Andrea se quiere marchar el lunes a su pueblo y la Madre Superiora dice que ya no puede controlarla más (los voluntarios dicen que no vuelven mientras esté ella y el otro día a una de las monjas le hizo llorar).QUIERO QUE SE LO DIGÁIS VOSOTROS A LA MADRE SUPERIORA, sor Mª Luisa, porque yo ya no sé cómo hacérselo entender. +++NO deben darle dinero. +++Si se altera, deben llamar al 112','2');
