insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2017-04-05','- Hablo con PNC , se le ha suspendido la misma a raiz del contrato indefinido de trabajo por superar los limites ec. establecidos en la ley . Los ingresos superan IPREM .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2017-04-07','- Comunico a ADela ( PNC ) el cambio de circusntancia de Samuel , ha percibido un mes de Renta Basico y ambas pensiones son incompatibles. Seguimos esperando respuesta de PNC , las territoriales de Bjoz lo enviaron al CADEX ( no tuvieron en cuenta la asimilación del grado discapacidad al 65% que no tiene ) . Se puso la direccion del SEPAd en la solicitud PNC puesto que vivia en la calle .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-04-07','Llamo a Tomás. Apenas puedo hablar con él porque me dice que lo van a bañar en unos minutos. Comenta que está bien y que ya ha hecho algún amigo en el hospital. El tono de su voz es tranquilo, incluso animada, alegre. Volveré a llamar.','2');
