insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2017-04-07','Conversación con Juan Carlos Serrano,Director de la Residencia "Los Pinos" de Plasencia (927 40 16 69). Ingresó por Órden Jucidicial el 13 de abril de 2016. +++Enviará Informe sobre Dª Eduvigis. +++Existe una medida cautelar sobre las cuentas de esta señora, solicitada a la Fiscalía por parte de la Residencia ante el temor de que los hijos y nietos de esta señora pudieran sacar dinero de ellas. Todo ello lo reflejará en el Informe mencionado. +++Enviarán para su firma solicitud de revisión de grado. Están revisando a todos aquellos residentes que no tienen este aspecto actualizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2017-04-07','Acude a la Comisión: +++Ella e Isabel V. se han puesto de acuerdo para compartir piso. El próximo lunes irá a ayudarla a hacer la mudanza de las cosas que tiene que llevar. +++Aviso a Yolanda, hija de los propietarios: no pone objección a que compartan piso. Mantendrá el contrato como tal a nombre de Catalina.','2');
