insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2017-04-10','-acude Cati a la Comisió , no se han puesto de acuerdo y al final no comparten piso . - se le elabora pto . a Isabel con 250€+100€ q le manda la familia , se le van a autorizar unos 80€/ semana aprox. para sus gastos . Todo lo demás domiciliado en su cuenta . Pte. seguro decesos q dice q le paga su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='PIRIS'and apellido2='RAMILLETE'),'2017-04-10','Pilar, T. Soc. CSS de Plasencia. Comunica el FALLECIMIENTO de D. Francisco el pasado sábado, 8 de abril, en el Hospital Virgen del Puerto de Plasencia. +++Ha comunicado a su sobrino el óbito y no ha puesto objección alguna a la incineración. +++D.E.P.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-04-10','Corre-e de Liliana, T. Soc. de Aldea Moret:Buenas tardes Pedro, te envío el informe social de PAULA SOLANA GUERRA, tal y como hemos hablado esta mañana. Tenme al corriente por favor de lo que suceda con fiscalía. Te informo por otra parte que hoy ha vuelto a venir Paula, estando incluso más alterada que los días anteriores, manifestando que un vecino la había increpado para que pagara la comunidad a lo que ella se niega y reiterándose en su negativa de acudir a Salud Mental o al médico de atención primaria para tomar medicación. Te ha llamado por teléfono para comentártelo y para preguntarte si no sois vosotros los que os ocupáis de abonar todos sus gastos, al igual que hacéis con el alquiler de la vivienda social que ocupa. Un saludo. LILIA ANA FDEZ.-BORRELLA GARCÍA TRABAJADORA SOCIAL DEL SSB DE ALDEA MORET','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2017-04-10','Conversación con Alfredo, Secretario del Juzgado de Instrucción nº 4 de Badajoz: +++Si el tutor considera que no se le debe permitir la salida de la Residencia esta debe hacer todo lo que esté en su mano para cumplir con ello. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con la Madre Superiora, Sor Luisa (924-255503): se informa de que en caso de que se produzca alguna alteración , se ponga en conocimiento del 112. En caso de "fuga" avisar a la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2017-04-06','Reconocimiento forense en Juzgado de Coria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-04-11','Conversación con Elena, T. Soc. de Las Cumbres. +++Margarita está más tranquila a raíz de la última conversación mantenida con ella en relación a un posible traslado a Extremadura. +++Hace unos días dijo que si se marchaba a Cáceres querría tener un hijo, una ideación de las suyas fuera de la realidad. +++FACTURACIÓN: el mes de abril facturarán la parte correspondiente a Margarita y hasta el 1 de mayo no lo harán con la correspondiente al SEPAD. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++NUEVA CONVERSACIÓN CON ELENA: +++Se le solicita certificado de coste de plaza para este año. Lo enviará por correo-e y ordinario. Mañana nos comunicará si se mantienen las condicones económicas del pasado año o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2017-04-11','Converscaión con José Mª Tovar: +++Indignación con la situación de Tomás. Según los informes médicos, la mielitis se origina a raiz de la sangre hallada en el recto, por lo que se sospecha que ello pueda estar relacionado con los abusos sufridos. +++José Mª nos hará llegar dichos Informes a la Comisión y los presentará igualmente en el juzgado para unirlos al procedimiento abierto por los abusos sexuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-04-11','Conversación con Pilar Martín: José Manuel parece ser que está dispuesto, ahora, a aceptar plaza en cualquiera de los CRR existentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2017-04-11','Conversación con Dª Mª Ángeles, hermana de Dª Isabel: +++Solicita, nuevamente, estar en la cartilla de su hermana. Se le vuelve a explicar el por qué no es posible. +++Reclama que a su hermana siguen sin darle dinero de bolsillo para sus gastos: volveremos a hablar con el Director de la Residencia. +++Insiste en que "...si mi hermana fallece -Dios no lo quiera-..." pongamos a sus hijos en la cartilla si no se puede poner ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2017-04-12','Conversación con Elena, T. Soc. de las Cumbres. +++El precio de la plaza que se puso para el contrato actual, 1000€, era para una permanencia en la plaza de 12 meses. +++Si no se garantiza esa permanencia mínima el coste de la plaza asciende a 1926€.Enviará certificado de coste. +++IMPORTANTE: Margarita','2');
