insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2017-04-12','Convresación con Clemen: +++Hermenegildo está completamente recuperado de su enfermedad. +++VER INFORME DEL CAMP DE 12 DE ABRIL DE 2017. +++El comportamineto de Hermenegildo ha vuelto a ser el mismo que antes de su enfermedad: altercados en el centro y fuera, fugas constantes. +++PROPUESTA: se volverá a tratar este tema en la primera convocatoria de la Subcomisión Sociosanitaria Regional de Gestión de casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-04-11','Se pone en conocimient, de la Sección de Salud Mental,mediante Nota Interior, el cambio de opinión de D. José Manuel respecto a la posibilidad de aceptar plaza en cualquiera de los CRR de Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-04-17','Conversación con Antonio, Enfermero de la Residencia. +++D. Isidoro, tras los cinco días que se menciona en el Informe remitido tanto al Juzgado como a la Comision, ha vuelto a comer pero intercalando periodos de negativa a hecerlo. +++Han pedido cita en el ESM de Llerena para valoración: CITADO el 15 de JUNIO. Intentaremos que adelanten la cita. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Beli, T. Soc. ESM de Llerena (924-872260): SOLICITO ADELANTO DE LA CITA prevista para el 15 de junio, dada la problemática que presenta en cuanto a la alimentación. Intentarán adelantarla y nos lo comunicarán (dejo también fax). +++++++++++SE ADELANTA LA CITA AL 4 de MAYO (enviarán la carta a la residencia).Se lo comunico a Maite (Auxiliar de Enfermería), para que lo traslade a Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTIBALIZ'and edp.apellido1='MENDEZ'and apellido2='CARRASCO'),'2017-04-17','Estíbaliz (695-959333) llama hoy planteando las siguientes quejas por lo sucedido durante su viaje a Punta Umbría durante los cuatro días de Semana Santa (acompañadas por felipe, Coordinador, e Inma (Educadora): +++Se queja del trato en general de ambos profesionales. +++Felipe se negó a darles el dinero de bolsillo que Segunda (Directora)les había dado para sus gastos, alegando que lo invertirían en la cena que iban a realizar uno de esos días. Todos manifestaron su desacuerdo y querían que les diese ese dinero para emplearlo como ellos quisieran ("...además, Segunda siempre le da el dinero para los gastos que en el grupo se produzcan). +++Gori también se quejó por ello. +++Estíbaliz dice que, además, mientras estaban fumando en la terraza del centro comercial, Felipe también le recogió el dinero que llevaba en su monedero y no se lo devolvió. +++Estíbaliz confiese que no lleva bien los CAMBIOS que se han producido en el piso: "...Con Quina tenía confianza para hablar, pero ahora con Inmaculada y con Felipe no es lo mismo..." +++El lunes previo a la marcha a Punta Umbría, la Educadora dijo que no le cuadraban las cuentas de la caja del piso y "...me acusó a mí de haber cogido dinero. Pero aunque yo no fuí me tuve que autoinculpar de ello porque me amenazaron con que si no lo decía no me dejarían celebrar la próxima semana (28 de abril) mi cumpleaños.Por eso ahora estoy haciendo TRABAJOS SOCIALES y sin gratificación...sin haber sido yo la culpable..." +++Le planteo que con quién prefiere que lo hable en La Luz, porque tiene miedo de que la castiguen si digo su nombre: "Me gustaría que lo hablases con Sole y con Felipe..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2017-04-18','Pedimos al Registro de la Propiedad de Logrosán, nota simple de las propiedades a nombre de Florentina y en especial de la casa sita en Plaza de los Tres Chorros, 6, de Guadalupe, de la que hemos recibido reclamación de la compañía de seguros de la vivienda colindante, por daños. Creemos que esa propiedad la heredó de su madre, junto con su hermana Dolores, comprándole la parte restante a los sobrinos. Al morir su hermana, puede que la única propietaria de la vivienda sea Florentina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2017-04-18','Llamo a Kutxabank para el tema de las claves de banca online. Raúl el director está de vacaciones, hablo con la subdirectora de la sucursal. Le indico que ya el 2/2/17 les enviamos por correo la solicitud de dichas claves. Posteriormente que hablé con Raúl el día 23 de marzo el cual me dijo que esa carta la reenviaba a su gabinete jurídico para que le dijeran cómo actuar, él se pondría en contacto con nosotros la semana siguiente, cosa que no ha ocurrido. La subdirectora me pide que le vuelva a enviar la carta de solicitud a su correo aalvareza@kutxabank.es, así lo hago. A la espera de noticias. Iciar','2');
