insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2017-04-19','Recibimos demanda del Juzgado de primera instancia nº 6 de Badajoz, relacionada con el PO 1122/2016, junto con Ignorados y Desconocidos herederos de Dª. Mencía Romero Ramos (madre), por daños causados al vecino de su casa, en C/. Bravo Murillo, 32A, de Badajoz. Tiene designación de abogado. Estamos esperando que el Juzgado nos comunique plazo para contestar a la demanda. ------------------------------------------------------------ Relacionado con esa vivienda, el Juzgado de Primera Instancia nº 7, de Badajoz, dicta Auto nº 34/2015, relativo al dominio y cargas afectas sobre la finca. Hemos solicitado por escrito al Juzgado que nos remitan todo lo relacionado con ese expediente, que al parecer está en proceso de Ejecución Hipotecaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-04-20','RECIBO LLAMADA DE JOSE MANUEL PREGUNTANDO COMO ESTÁ SU PETICIÓN DE CENTRO. QUIERE INGRESAR EN CRR. LE COMENTO QUE LA PETICIÓN SE HIZO EL 11 DE ABRIL Y TODAVÍA ES PRONTO. ME DA SU TELÉFNO PARA CUANDO TENGAMOS ALGUNA NOVEDAD. 927773218','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2017-04-19','Lourdes, Enfermera de la Residencia de Mayores de Barcarrota (924-737993): comunica el traslado e ingreso de D. Francisco al H. Infanta Cristina de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2017-04-20','Llama D. Luis Cardoso (673-295276), sobrino de D. Francisco. +++"He estado con él estos dos días, pero no puede estar más tiempo y necesitaría alguien que le hiciese compañía". Le propongo hablar con el hospital y ver qué necesidades de acompañamiento tiene su tío para contratar a alguien. RESPUESTA: "Hombre, si me lo pagáis a mí me puedo quedar yo". Pregunto por su disponibilidad de tiempo. RESPUESTA: "El que haga falta, porque estoy parado..." ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Lourdes a la Residencia: +++Motivo de ingreso: dolor de cabeza y estómago que no remitía con el tratamiento del Médico de Familia, quien lo derivó al Hospital. +++El sobrino va de vez en cuando a ver a su tío. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada al H. Infanta Cristina. Hablo con Loli, T. Social (924-218100). Informará de: +++Estado de salud de D. Francisco. +++Previsión temporal de ingreso. +++Necesidad de acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2017-04-20','Llama madre de José Antonio para decir enviará facturas del periodo que José Antonio estuvo ingresado. Pregunta por el momento en que su hijo pueda salir del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-04-20','Nos comunican que el ingreso de D. Ramón en la UHB DEL INFANTA CRISTINA se produjo AYER, 19 de abril, por Orden Judicial y tras haber provocado diversos incidentes que obligaron a la intervención de la Guardia Civil y al cierre del Juzgado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Manuel, hermano de Ramón: +++Se encargará del cuidado de los animales mientras dure el ingreso de su hermano. +++Solicita 100€/mes para el pienso, pero se le va a hacer una transferencia de los 60 que quedamos con Ramón, más 20€ en concepto de su trabajo: "Bueno, pero yo voy a utilizar esos 20€ para los animales, porque no lo hago por mí, sino por mi hermano..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2017-04-21','Solicito a Mariví (T. Soc.CSS de Plasencia) Informe Social y Psiquiátrico de D. Juan, para remitir Informe de la Comisión a Gabinete Jurídico para apoyar procedimiento de aumento de la incapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-04-21','Conversación con Joaquín Fernández, Psiquiatra de la UHB del H. Infanta Cristina (924-218100): +++"Ramón, desde que está en la Unidad se encuentra muy tranquilo y diciendo que se quiere marchar porque tiene que cuidar a sus animales." SE le informa que de ello se está ocupando su hermano Manuel (para que lo tranquilice al respecto). +++"Vamos a empezar a ponerle la inyección trimestral hoy, porque en el Informe de Fabiola (ESM de Jerez) se indica que estaba con la mensual y que era preferible cambiarla a la trimestral..." Le indico a Joaquín que en la Comisión tenemos la inpfrmación de que está con la trimestral desde octubre (ver incidencias de fechas 15 de noviembre de 2016 y 6 y 10 de marzo de 2017). +++"PREVISIÓN" DE INGRESO": un par de semanas. +++Se informa al Psiquiátra del comportamiento manipulador de Ramón, de su planteamiento respecto a su tratamiento como una "letra de cambio" para conseguir lo que quiere, en especial dinero ("...si no me lo das, no me pongo la inyeccón..." +++Joaquín comenta que Ramón justifica su comportamiento porque "...mi hermano me está pinchando continuamente..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2017-04-21','SALIDA Entre el 29/05/2017 y el 02/06/2017. Viaje a Madrid para visitar el Zoo y acudir al musical "El Rey León". *********Supone un gasto total de 440€. Se aprueba el gasto por tener suficiente dinero en su cuenta. Se autoriza, por tanto, el viaje.','2');
