insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-04-25','Conversación con Eugenia, T. Soc. de Jerez (924-730101 y 924-730011). +++Su hermano Manuel dice que parece ser, según le ha dicho Ramón, que lo van a traer a Mérida y que va a estar ingresado 4 meses (no tenemos confirmación de ello) y que el se puede hacer cargo de los animales 15 días, pero no más (hasta mediados de mayo). +++Otro de sus hermanos dice que se podría hacer cargo de ello por 10€/día (300€/mes). +++Pendientes de confirmar traslado y tiempo previsto de estancia (comunicar cunado lo sepamos a Eugenia) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++LLAMADA DE MANUEL: ++++De los perros de su hermano se encarga él. ++++Del resto de animales (3 cerdas, 1 berraco, gallinas, lechones, etc.) se encarga HASTA MEDIADOS DE MAYO.Llevará a la T. Soc. listado con todos los animales que tiene. ++++SI NADIE SE PUEDE ENCARGAR DESPUÉS: se consultará con Ramón para que entienda la necesidad de la venta.SE VENDERÁN:Manuel se ofrece para ello, pero ya se le INDICA QUE DEBERÁ TENER LA AUTORIZACIÓN DE ESTA COMSIÓN PARA ELLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-04-25','-NOS LLAMA PILAR PARA COMUNICAR QUE EL DIA 17 DE MAYO TIENE UNA CITA JUDICIAL ,QUEDAMOS PTE. DEL RESULTADO DE LA MISMA PARA EL ALQUILER DE PISO , QUIERE Q SEA EL 1 DE JUNIO . SEGUIRIA EN SEGUIMIENTO DEL CRPS Y DEL E.S.M. . EL ALTA EN LOS PISOS SUPERVISADOS DE SALUD MENTAL DE ZAFRA SE LO HA DADO ELLA COMO COORDINADORA.','2');
