insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-04-26','Conversación con Loli Olivera, T. Soc. H.Infanta Cristina (924-218075//fax: 924219615). +++El Psiquiatra ha pensado derivarlo a la UME de Mérida, pero la madre de Ramón se ha presentado en el Hospital negándose a que lo traslade. +++INFORMACIÓN PROPORCIONADA:La derivación, en primer lugar, debe responder a criterios clínicos del especialista correspondiente y en segundo, la responsabilidad legal sobre Ramón le corresponde a la Comisión Tutelar, por lo que ningún familiar puede oponerse a la medida desde un punto de vista legal. +++Informarán a la Comisión cuando se produzca dicho traslado.','2');
