insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2017-04-28','Conversación con Toni (Futuex): +++En la próxima visita de Virginia valorar la necesidad de que Dª Manuela pueda requerir un centro residencial: SIEMPRE QUE ELLA SE ENCUENTRE BIEN EN SU ENTORNO SE MANTENDRÁ EN ÉL. +++Según Toni, aunque tiene ciertos problemas de movilidad, ella se encuentra bien en su casa y, al menos aperentemente, bien atendida por su nieto. Cree que autorizar a José Manuel (nieto) a que vaya al banco sin su abuela solo daría lugar a que esta saliera menos todavía de su casa. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con la Dra.Sandra Borrero, Médico de Familia (927-580295): +++La última vez que acudió a su casa fue a finales de 2015. Desde entonces ha ido en varias ocasiones al médico y parece encontrarse bien.Enviará Informe de salud. +++Pedir Informe a la T. Soc., Lidia Cabanillas (no veulve hasta el 2 de mayo).','2');
