insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2017-05-04','Conversación con Mara: +++D. Isidoro ha acudido al ESM: no da perfil para esta red de recursos. Enviará por fax el Informe del ESM. +++Correo-e enviado a Jorge Muñoz Tinoco, Jefe de Sección de Centros de los SS. Territoriales: Buenas tardes Jorge, Te adjunto el informe de las últimas incidencias de Isidoro Morgado Sánchez. El último resumen te lo envié el 6 de abril 2107. Tras el incidente de fuga que te envío el informe, ha mantenido una actitud desafiante hacia todo el personal, insultando en varias ocasiones y en la dinámica habitual en él de no comer en varios días o saltarse algunas comidas. Lo he comunicado igualmente a la Comisión Tutelar, al Juzgado de Llerena y al Gerente. El gerente me indica que te envíe a tí el informe, así como la Solicitud de Cambio de Residencia. Un saludo, Mara Atienza +++Pendiente de respuesta a la solicitud de cambio de Centro.','2');
