insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2017-05-08','Conversación con Manuel, hermano de Ramón. +++Dice que su hermano quiere vender 2 "cochinas" grandes y 25 lechones. +++Se le envían 60€ para pienso. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo también con Eugenia, T. Soc. de Jerez: +++Posibilidad de mediar de alguna forma en la venta de dichos animales. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Converscaión con Loli, T. Soc. del Infanta Cristina: +++Ramón sigue en la UHB. +++Confirmará que quiere vender esos animales y por cuánto dinero. +++Enviará información por correo-e o fax. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Loli confirma el deseo de Ramón de hacer dicha venta. Desconoce el valor de los mismos. +++El jueves 11 lo trasaladan a UME para valoración.','2');
