insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-05-09','Llama de nuevo Pilar (t/c 924.55.46.51)para indicar que ya han visto un piso para Beatriz. Nos va a enviar por correo electrónico los detalles del alquiler que le faciliten en la inmobiliaria ( serían 300€/mes + gastos). También se le informa de que el juicio por videoconferencia de Beatriz ha sido pospuesto por ser el día 15 de mayo festivo en Zafra, estamos a la espera de que nos faciliten nueva fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='REY'and apellido2='COLOMBO'),'2017-05-09','Conversación con Pilar Salguero (924-010060). Se comunica resolución de plaza en Nuestra Señora de la Luz con fecha 3 de Mayo. +++Enviarán expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2017-05-05','Buenos días, el motivo de email es informaros de que Corre-e CRR.Consuelo N. ha sido ingresada en la UHB de Mérida por descompensación de su sintomatología y por propia voluntad.Os iremos informando de su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOSA'and apellido2='MARTINEZ'),'2017-05-10','Hablo con Mª Carmen Rodríguez: el médico de Cuidados Paliativos que trata a José es el doctor Marcos López t/c 696 935 460. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con el Dr. Marco López. +++Comenta que de continuar con el soporte vital (diálisis) se podría incurrir en una situación de ensañamiento terapéutico, por lo que se considera que lo más bneneficioso para el paciente es la retirada del mismo. Comenta que la Nefróloga estuvo hablando ayer con él, explicándole la situación y que él era consciente de la misma y apoyaba la decisión. +++SE le explica a Marcos que, al ser una persona tutelada, no tiene capacidad legal de decisión, por lo que esta situación, desde la CTAEx, hemos de ponerla en conocimiento del Juzgado. Entendemos que desde el punto de vista clínico -se le comenta- seguro que es la decisión más beneficiosa para D. José, pero le pido que, siempre que no haya perjuicio para él, retrasen la decisión hasta que lo comuniquemos al Juzgado por si éste tuviera algo que decir. +++Enviará por fax Informe Clínico de Paliativos y de Nefrología explicando la situación, que la CTAEx pondrá en conocimiento del Juzgado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al Juzgado de 1ª Instancia nº 2 de Zafra, solicitando hablar con la Secretaria del Juzgado. Planteo la situación a la funcionaria con la que hablo y me dice que le pasará el caso a la Secretaria y me llamará cuando haya estudiado el expediente. +++Vuelvo a llamar a última hora y comentan que el Juzgado de Zafra se ha Inhibido en favor del de Villafranca de los Barros (no teníamos conocimiento de dicha inhibición). +++LLamo al Juzgado de Villafranca y dicen que envíemos la información mediante un Informe sobre la misma.Nº ESPEDIENTE:V90 231/16. CONTACTO: ANTONIO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN con Mª CARMEN, DIRECTORA de la RESIDENCIA "La Coronada" (Villafranca) para saber si había algún familiar que mantuviese algún contacto con D. José para ponernos en contacto con él. +++D. ANTONIO MARTÍNEZ SOSA, primo de D. José, quien de forma habitual visita a su primo y se interesa por él. TELÉFONOS:948-330947 Y 645-956307.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2017-05-10','Llama el hernmano José Luis para comunicar que ha cambiado la cerradura del piso e interesarse por la situación del hermano si ingresado por orden judicial o voluntariamente en el CRR','2');
