insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='SANCHEZ'and apellido2='CRUZ'),'2017-05-11','BAJA Se recibe llamada del Hospital Virgen del Puerto, de Cáceres, en referencia a Dña. Ana Mª. Al parecer le tienen que dar el alta y no saben, a ciencia cierta, quién es su tutor.*****************************************************Dña. Ana Mª. resulta ser defensa judicial nuestra. Sin embargo, la Trabajadora Social del Hospital nos informa que su hijo fue nombrado curador de la misma en su momento.***************************************************Para aclarar el caso, se realiza llamada telefónica al Juzgado nº. 6, de Cáceres. Al parecer, su hijo, fue nombrado curador, efectivamente. Posteriormente, éste, decide excusarse de dicho cargo. Según el juzgado, existe un Auto de 2014 que supedita la aceptación de la excusa al ingreso de Dña. Ana Mª. en un centro. No obstante, no hay un Auto posterior que, efectivamente, acepte la excusa del hijo. Por ello, y tras ser cuestionado mediante pregunta directa, el juzgado reconoce que, técnicamente, a día de hoy, el hijo sigue siendo curador de Dña. Ana Mª. El mismo juzgado nos dice que comuniquemos a la Trabajadora Social del Hospital que eleve escrito indicando la problemática del caso.**************************************************En vista de que, en su momento, el hijo fue nombrado curador de su madre, es por lo que se lleva a cabo la baja del sistema de Dña. Ana Mª.','2');
