insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-05-15','Conversación con Dª Soledad Delgado, madre de María (658-889091): +++Está dispuesta a colaborar en todo lo que esté en su mano. +++RESIDENCIA ACTUAL: URBANIZACIÓN CAMPO PINO, parcela nº 2, de Badajoz. +++Informa que, por una conocida de su hermano que es vecina en esta Urbanización, una ambulancia fue a recogerla hace unos días, al parecer presa de una fuerte crisi de ansiedad. +++Inoforma que su hija solía ir al Dr. Pozuelo, en el C. de Salud de "la Paz" y al ESM de Valdepasillas, con el Dr. Samino. +++Comenta que le han dado cita en dicho ESM para agosto. Propuesta de intervención inicial: llamaré al ESM para confirmar dicha cita y, en su caso, procurar que sea adelantada lo más posible. Su madre está de acuerdo con ello. Plantear al ESM un ingreso para estabilización y tratamiento ( a ser posible en U. de deshabituación alcohólica del CSS Plasencia) y, según evolución, progresar dentro de la red de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ARNEDO'and apellido2='LOPEZ'),'2017-05-16','Recibimos oferta de compra de José Bellón (jm.bellon@gmail.com), para comprar tres fincas rústicas de Francisco en Los Guájeres (Granada), por 12.000 euros (acompaña tasación. Este precio se ajusta a la valoración del portal tributario de la Junta de Andalucía (11.032 euros). Realizamos tasación para conocer el valor del precio de mercaro de las fincas, la hace Ignacio Vallejo Viciana, Ingeniero Agrícola (ignaciovv@gmail.com)y las valora en 34.610 euros. Según él, por menos de la mitad no vendería las fincas (es decir, unos 17.000 euros). Vuelvo a ponerme en contacto con José Bellón, para indicarle este punto y, si continúa interesado en la compra de las fincas, realice una oferta superior a la inicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2017-05-16','-hablo con RM Fuente del Maestre, hay una plaza libre de mujer , cuesta 1000€. Ella podria abonar 743€ prorrateando su pension . Vamos a solicitar nueva revision de grado dependencia ya que inicialmente no ha dado grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2017-05-08','SALIDA El 16/05/2017. Nos informan, desde el Centro, que el 16/05/2017, Eulalia, tiene programada una salida para visitar su hermano al CAMP Las Cruces. Irá en trasporte del centro y estará acompañada por dos monitorasy algunos de sus compaleros de taller. La hora prevista de llegada a Don Benito será a las 11 de la mañana y, tras pasar un rato con su hermano dando un paseo fuera de la residencia, comerán por allí y, después, regresarán al centro para estar aquí a la hora de la salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2017-05-16','Conversación con Olga, T. Soc. Valencia del Ventoso (924-562127): +++La madre está acudiendo al ESM pero no sigue el tratamiento. Él sí lo está haciendo. +++Situación lamentable de la vivienda, donde no dejan entrar a nadie desde hace años. La última visita, de la que surge el I. Soc. se puede considerar una excepción. Le perimitieron hacer fotografías incluso, que nos enviará. +++No dejan entrar a nadie desde que falleció su padre y este le dijo que él no se tenía que mover de su casa. +++ESTUVO en C.O. de Zafra alrededor del 2011...Desconocemos el por qué lo dejó. ALTERNATIVAS: +++Solicitar REVISIÓN DE PIA. En caso de ACEPTAR SAD, mantener en domcilio. En caso contrario plantear C.O. o C. Día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-05-16','Conversación con Carmen Díaz, (T. Soc. ESM de Valdepasillas)(42853). +++Tiene cita para el 14 de agosto con el Dr.Samino. INTENTARÁN ADELANTARLA. +++Planteo posibilidad de ingreso para estabilizar y garantizar adherencia al tratamiento. Carmen plantea una posible convocatoria de la Subcomisión de casos. +++Ayer acudió a la Consulta del C. de Salud de La Paz, con el Dr. Jerónimo Pozuelo (924-232891) y tiene cita también el próximo 5 de junio. +++CONTACTAR con Gloria, T. Soc. del C.Salud de La Paz (41718). +++VER POSIBILIDAD DE QUEDAR CON MARÍA EN EL ESM o C. de SALUD (planteárselo a ella para ver qué nivel de conciencia tiene de su situación). +++Se envía la carta de la madre a Carmen Díaz por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-05-17','Llama Gema Carrasco T.S. de Puebla de Sancho Pérez, T/C 673.595.805 o 924.57.52.09, indica que ha ido a visitar a Ildefonso a petición del hermano. La situación de este ha empeorado desde el fallecimiento del padre el pasado 10 de abril,reclama su parte de la herencia, amenaza con marcharse, con obsesiones. La madre está también en situación de dependencia, y tanto ella como el hermano están angustiados y no saben qué hacer con Ildefonso, la situación actual de convivencia en la casa se les hace muy difícil. Es el hermano el que le ha pedido que interceda porque la madre no estaba muy por la labor','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-05-18','Conversación con Mariola. Se le pide Informe de las últimas incidencias ocurridas con Ramón. +++Domingo: la madre de Ramón sufre una caída y se fractura la cadera. +++Padre y hermanos no quieren hacerse cargo de él...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2017-05-16','Contestamos por correo electrónico a Pilar, que previamente nos había enviado borrador, indicando las modificaciones que debería aplicarse al contrato de alquiler para que se pueda proceder a la firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-05-18','Conversación con Gloria, T. Soc. C. Salud La Paz: +++No creer haber llevado este caso. +++hablará con el Dr. Pozuelo para informarse. +++Volver a llamar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Carmen Díaz (ESM de Badajoz): +++Le llegó la carta de la madre que le envíe por fax y la leyó el Psiquiatra. +++A la espera de ver si es posible un adelanto de la cita. +++Se podría aprovechar dicha consulta para mantener una reunión con ella en las dependencias del ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-05-16','URGENCIAS El 16/05/2017, 18:40 Horas. Traslado al Servicio de Urgencias del Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2017-05-17','TRASLADO El 16/05/2017. Traslado al Hospital de Mérida con fecha 16/05/2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='HOLGUIN'and apellido2='MENESES'),'2017-05-18','Nuevo ingreso en H. Don Benito-Villanueva por infección respiratoria el 06 de mayo. Alta el 10 de mayo. Seguimiento por MAP. +++Llamo a Aprosuba 12. Hablo con su Directora, Mª José (924-620400). D. Manuel se encuentra bien, estable, aunque su patología es crónica y requiere ingresos en fase aguda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='GALINDO'and apellido2='CALLE'),'2017-05-18','Llama la hija, Puerto T/C 661.27.32.04, indicando que su abuela ha fallecido hace dos meses, y necesita el DNI de su madre para la declaración de herederos.En la residencia no se lo facilitan. Nos informa de la notaría de Plasencia donde se van a realizar los trámites para que nosotros nos pongamos en contacto: Notaría Francisco de Asís Jiménez Velasco T/C 927.41.14.47. Dice haber llamado ya informar del fallecimiento de su abuela.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-05-18','SE envía la documnetación requerida (fotocopia de DNI, cobro de pensión, sentencia de incapacitación) a la inmobiliaria DOmmus.Antes hablo con Teresa y Toni: +++El piso está para entrar a vivir. +++Necesitará comprar menaje de cocina y ropa de cama.Lo acompañará Teresa, una vez formalizado el contrato de alquiler: +++GASTOS: 285€ (FIANZA), 285€ (MENSUALIDAD. Entra agua y comunidad) y 169.40€ (gastos Inmobiliaria, IVA incluido).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2017-05-19','Se envía fax (924-245551) al C. Salud de "La Paz" solicitando Informe Médico y, si existen datos, también social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-05-19','Conversación con Gema, T. Soc.de Puebla de Sancho Pérez (924-575709 y 673-595805). +++Según su hermano Luis, últimamente la convivencia se ha vuelto más difícil a raíz del fallecimiento de su padre. +++Teléfono familiar: 924-575077.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEVERIANO'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2017-05-19','Conversación con Ana Delfa (CRR de Badajoz): +++Enviará informe sobre incidencia de Severiano: ha dirigido un escrito "amenazante" al Juzgado haciéndose pasar por una monitora del CRR y la Polciía Judicial ha solcitado la identificación. +++Según Ana, ha confesado ser el autor del escrito, en un momento de ofuscación que tuvo.','2');
